  const AMO_DELIVERABLE_NO_TEMPLATE_OPTIONS = [
    'Business Discussion',
  ];

  let _amoDeliverableRemoteOptions = [];
  let _amoDeliverableFetchStarted = false;

  function normalizeAmoDeliverableName(value) {
    const text = String(value || '').replace(/\s+/g, ' ').trim();
    if (!text) return '';
    if (/^upsell\s*-/i.test(text)) return 'Upsell';
    return text;
  }

  function isValidAmoDeliverableName(value) {
    const text = normalizeAmoDeliverableName(value);
    if (!text || /^\d+$/.test(text)) return false;
    if (/^more options\b/i.test(text)) return false;
    if (/\bfunction\s*\(/i.test(text)) return false;
    if (/[{};]/.test(text)) return false;
    return text.length <= 80;
  }

  function getBaseAmoDeliverableOptions() {
    const seen = new Set();
    return [
      ...Object.keys(AMO_DELIVERABLE_TEMPLATES),
      ...AMO_DELIVERABLE_NO_TEMPLATE_OPTIONS,
      ..._amoDeliverableRemoteOptions,
      ...getExtraAmoDeliverableOptions(),
    ].map(normalizeAmoDeliverableName)
      .filter(name => {
        const key = name.toLowerCase();
        if (!isValidAmoDeliverableName(name) || seen.has(key)) return false;
        seen.add(key);
        return true;
      });
  }

  function buildAmoDeliverableOptionMarkup(options) {
    return (options || getBaseAmoDeliverableOptions()).map(name => {
      const hasTemplate = Boolean(AMO_DELIVERABLE_TEMPLATES[name]);
      const attrs = hasTemplate ? '' : ' data-no-template="true"';
      return `<option value="${escAttr(name)}"${attrs}>${escHtml(name)}</option>`;
    }).join('');
  }

  /* ────────────────────────────────────────────────────────────────
     TIMEZONE INFERENCE
     Maps US state / CA province location codes to IANA timezones.
  ──────────────────────────────────────────────────────────────── */
  function inferTimeZone(location) {
    if (!location) return '';
    const ET = 'America/New_York', CT = 'America/Chicago',
          MT = 'America/Denver',  PT = 'America/Los_Angeles',
          AZ = 'America/Phoenix';
    const map = {
      // Eastern
      ME:ET, NH:ET, VT:ET, MA:ET, RI:ET, CT:ET, NY:ET, NJ:ET, PA:ET,
      DE:ET, MD:ET, DC:ET, VA:ET, WV:ET, NC:ET, SC:ET, GA:ET, FL:ET,
      OH:ET, MI:ET, IN:ET, KY:ET, TN:ET, AL:ET, MS:ET,
      // Central
      WI:CT, IL:CT, MN:CT, IA:CT, MO:CT, AR:CT, LA:CT,
      ND:CT, SD:CT, NE:CT, KS:CT, OK:CT, TX:CT,
      // Mountain
      MT:MT, ID:MT, WY:MT, CO:MT, NM:MT, UT:MT,
      // Arizona (no DST)
      AZ:AZ,
      // Pacific
      WA:PT, OR:PT, CA:PT, NV:PT,
      // Outlying
      AK:'America/Anchorage', HI:'Pacific/Honolulu',
      // Canada
      'CA-NS':'America/Halifax',  'CA-NB':'America/Halifax',
      'CA-PE':'America/Halifax',  'CA-NL':'America/St_Johns',
      'CA-QC':'America/Toronto',  'CA-ON':'America/Toronto',
      'CA-MB':'America/Winnipeg', 'CA-SK':'America/Regina',
      'CA-AB':'America/Edmonton', 'CA-BC':'America/Vancouver',
    };
    const full = location.toUpperCase();
    if (map[full]) return map[full];           // e.g. "CA-ON"
    const m = full.match(/^(?:US-)?([A-Z]{2})/);
    return m ? (map[m[1]] || '') : '';
  }

