  /* ────────────────────────────────────────────────────────────────
     PANEL HTML
  ──────────────────────────────────────────────────────────────── */

  function buildProductOptions() {
    return [...PRODUCTS]
      .sort((a, b) => a.name.localeCompare(b.name))
      .map(p => `<option value="${p.id}">${p.name}</option>`)
      .join('');
  }

  function fallbackProductSkillOptions() {
    return Object.entries(PRODUCT_SKILL_MAP)
      .map(([productId, skillId]) => {
        const product = PRODUCTS.find(p => String(p.id) === String(productId));
        return {
          value: String(skillId),
          text: product ? product.name : `Product Skill ${skillId}`,
          scrValue: String(productId),
          scrText: product ? product.name : '',
        };
      })
      .sort((a, b) => a.text.localeCompare(b.text));
  }

  function buildProductSkillOptionMarkup(options) {
    return (options || []).map(o => {
      const value = o.value || o.skillId || '';
      const text = o.text || o.name || value;
      return `<option value="${escAttr(value)}" data-skill-id="${escAttr(value)}" data-scr-value="${escAttr(o.scrValue || '')}" data-scr-text="${escAttr(o.scrText || '')}">${escHtml(text)}</option>`;
    }).join('');
  }

  function buildProductSkillOptions() {
    return buildProductSkillOptionMarkup(PRODUCT_SKILL_OPTIONS_CACHE || fallbackProductSkillOptions());
  }

  function buildIndustryOptions() {
    if (INDUSTRY_OPTIONS_CACHE && INDUSTRY_OPTIONS_CACHE.length) {
      return buildIndustryOptionMarkup(INDUSTRY_OPTIONS_CACHE);
    }
    return buildIndustryOptionMarkup(fallbackIndustryOptionsFlat());
  }

  function buildIndustryOptionMarkup(options) {
    return normalizeKnownIndustryOptions(options || [])
      .map(i => `<option value="${escAttr(i.id)}">${escHtml(i.name)}</option>`)
      .join('');
  }

  function normalizeIndustryText(text) {
    return String(text || '')
      .toLowerCase()
      .replace(/&/g, 'and')
      .replace(/[^a-z0-9]+/g, ' ')
      .trim();
  }

  function normalizeIndustryLabelKey(text) {
    return normalizeIndustryText(text).replace(/\s+/g, ' ');
  }

  function isLikelyInternalIdText(text) {
    return /^\d+(?:\s*,\s*\d+)*$/.test(String(text || '').trim());
  }

  function simplifyIndustryPart(text) {
    const raw = String(text || '').trim();
    if (!raw) return '';
    const parts = raw
      .split(/\s+-\s+/)
      .map(p => p.trim())
      .filter(Boolean);
    return parts.length ? parts[parts.length - 1] : raw;
  }

  function mergeDuplicateIndustryOptions(options) {
    const byLabel = {};
    normalizeKnownIndustryOptions(options || []).forEach(option => {
      if (!option || !option.id || !option.name) return;
      const key = normalizeIndustryLabelKey(option.name);
      if (!key) return;
      if (!byLabel[key]) {
        byLabel[key] = { ...option, ids: [] };
      }
      String(option.id).split(',').filter(Boolean).forEach(id => {
        if (!byLabel[key].ids.includes(id)) byLabel[key].ids.push(id);
      });
    });
    return Object.values(byLabel)
      .map(option => ({
        ...option,
        id: option.ids.join(','),
      }))
      .sort((a, b) => a.name.localeCompare(b.name));
  }

  function getStaticIndustryGroupForId(id) {
    const idText = String(id || '');
    for (const group of INDUSTRY_GROUPS) {
      if ((group.items || []).some(item => String(item.id) === idText)) return group.group;
    }
    return '';
  }

  function isSpecificIndustryOption(name, family) {
    const n = normalizeIndustryText(name);
    if (!n) return false;
    if (/\bgeneral\b/.test(n)) return false;
    return true;
  }

  function gtmIndustryKey(industry, subgroup) {
    return normalizeIndustryLabelKey(`${industry || ''} ${subgroup || ''}`);
  }

  function getCanonicalGtmOption(industry, subgroup) {
    const key = gtmIndustryKey(industry, subgroup);
    return FY27_GTM_INDUSTRY_OPTIONS.find(option => gtmIndustryKey(option.industry, option.subgroup) === key) || null;
  }

  function addUniqueGtmRollup(out, industry, subgroup) {
    const canonical = getCanonicalGtmOption(industry, subgroup);
    if (!canonical) return;
    const key = gtmIndustryKey(canonical.industry, canonical.subgroup);
    if (out.some(item => gtmIndustryKey(item.industry, item.subgroup) === key)) return;
    out.push(canonical);
  }

  function getGtmRollupsForSubIndustry(subIndustryName) {
    const raw = String(subIndustryName || '').trim();
    if (!raw) return [];
    const candidates = [raw];
    const parts = raw.split(/\s+-\s+/).map(p => p.trim()).filter(Boolean);
    if (parts.length > 1) {
      candidates.push(parts.slice(1).join(' - '));
      candidates.push(parts[parts.length - 1]);
    }

    const rollups = [];
    candidates.forEach(candidate => {
      const key = normalizeIndustryLabelKey(candidate);
      (FY27_GTM_SUBINDUSTRY_ROLLUPS[key] || []).forEach(pair => addUniqueGtmRollup(rollups, pair[0], pair[1]));
      FY27_GTM_INDUSTRY_OPTIONS.forEach(option => {
        if (normalizeIndustryLabelKey(option.name) === key ||
            normalizeIndustryLabelKey(option.subgroup) === key) {
          addUniqueGtmRollup(rollups, option.industry, option.subgroup);
        }
      });
    });
    return rollups;
  }

  function makeGtmIndustryOption(id, industry, subgroup, sourceSubIndustry) {
    const canonical = getCanonicalGtmOption(industry, subgroup);
    if (!canonical) return null;
    return {
      id: String(id),
      name: canonical.name,
      family: canonical.industry,
      subIndustry: canonical.subgroup,
      scGroup: canonical.scGroup,
      gtmKey: gtmIndustryKey(canonical.industry, canonical.subgroup),
      sourceSubIndustry: sourceSubIndustry || '',
      isGtmIndustryOption: true,
      hasKnownIndustryFamily: true,
    };
  }

  function expandGtmIndustryOptions(id, subIndustryName) {
    return getGtmRollupsForSubIndustry(subIndustryName)
      .map(option => makeGtmIndustryOption(id, option.industry, option.subgroup, subIndustryName))
      .filter(Boolean);
  }

  function normalizeKnownIndustryOption(option) {
    if (!option) return option;
    if (option.isGtmIndustryOption) return option;
    const rollups = getGtmRollupsForSubIndustry(option.subIndustry || option.name || '');
    if (!rollups.length) return option;
    return makeGtmIndustryOption(option.id, rollups[0].industry, rollups[0].subgroup, option.subIndustry || option.name) || option;
  }

  function normalizeKnownIndustryOptions(options) {
    return (options || []).map(normalizeKnownIndustryOption).filter(Boolean);
  }

  function makeIndustryOption(id, subIndustryName, familyName) {
    const gtmOptions = expandGtmIndustryOptions(id, subIndustryName);
    if (gtmOptions.length) return gtmOptions[0];
    const sub = simplifyIndustryPart(subIndustryName);
    const family = simplifyIndustryPart(familyName || getStaticIndustryGroupForId(id) || resolveIndustryFamily(id, '') || '');
    if (!id || !isSpecificIndustryOption(sub, family)) return null;
    const label = family ? `${family} - ${sub}` : sub;
    return { id: String(id), name: label, family, subIndustry: sub };
  }

  function scoreIndustryFamilyCandidate(option) {
    if (!option || !option.family || !option.subIndustry) return 0;
    const family = normalizeIndustryLabelKey(option.family);
    const sub = normalizeIndustryLabelKey(option.subIndustry);
    const source = String(option.sourceField || '').toLowerCase();
    let score = 10;
    if (option.isGtmIndustryOption) score += 120;
    if (option.hasKnownIndustryFamily) score += 90;
    if (source.includes('industry_family')) score += 60;
    else if (source.includes('family')) score += 55;
    else if (source.includes('industry')) score += 30;
    if (family === sub) score += 20;
    if (family && sub && family !== sub && (family.includes(sub) || sub.includes(family))) score -= 8;
    if (/\bgeneral\b/.test(family)) score -= 15;
    return score;
  }

  function isTrustedIndustryFamilySource(sourceField) {
    const source = String(sourceField || '').toLowerCase();
    if (!source || source === 'static') return true;
    if (source.includes('industry_family')) return true;
    return source.includes('family') && !source.endsWith('_industry');
  }

  function isBroadIndustryHierarchySource(sourceField) {
    const source = String(sourceField || '').toLowerCase();
    return source === 'custrecord_sr_ind_rating_industry' ||
           source === 'custrecord_sr_ind_rating_industry_group' ||
           source === 'custrecord_sr_industry_rating_industry';
  }

  function selfFamilyIndustryOption(option) {
    if (option && option.isGtmIndustryOption) return option;
    const sub = option && option.subIndustry ? option.subIndustry : '';
    if (!sub) return option;
    return {
      ...option,
      family: sub,
      name: `${sub} - ${sub}`,
    };
  }

  function hasMatrixIndustryFamily(option, subIndustryNames) {
    if (!option || !option.family || !option.subIndustry) return false;
    if (option.isGtmIndustryOption) return true;
    if (option.hasKnownIndustryFamily) return true;
    const family = normalizeIndustryLabelKey(option.family);
    const sub = normalizeIndustryLabelKey(option.subIndustry);
    if (!family || !sub) return false;
    return family === sub || subIndustryNames.has(family);
  }

  function chooseBestIndustryOptions(candidates) {
    const normalizedCandidates = normalizeKnownIndustryOptions(candidates || []);
    const subIndustryNames = new Set(normalizedCandidates
      .map(option => normalizeIndustryLabelKey(option && option.subIndustry))
      .filter(Boolean));
    const byId = {};
    normalizedCandidates.forEach(option => {
      if (!option || !option.id) return;
      const ids = String(option.id).split(',').filter(Boolean);
      ids.forEach(id => {
        const item = { ...option, id };
        const key = option.gtmKey ? `${option.gtmKey}:${id}` : id;
        if (!byId[key]) byId[key] = [];
        byId[key].push(item);
      });
    });
    const chosen = Object.values(byId).map(items => {
      const trusted = items.filter(item =>
        isTrustedIndustryFamilySource(item.sourceField) &&
        hasMatrixIndustryFamily(item, subIndustryNames));
      const pool = trusted.length ? trusted : items;
      const best = pool
        .slice()
        .sort((a, b) => scoreIndustryFamilyCandidate(b) - scoreIndustryFamilyCandidate(a))[0];
      return (!trusted.length && (isBroadIndustryHierarchySource(best.sourceField) ||
             !hasMatrixIndustryFamily(best, subIndustryNames)))
        ? selfFamilyIndustryOption(best)
        : best;
    });
    return mergeDuplicateIndustryOptions(chosen);
  }

  function optionMatchesIndustryPart(option, partText) {
    const text = normalizeIndustryText(partText);
    if (!option || !text) return false;
    return normalizeIndustryText(option.subIndustry || '') === text ||
           normalizeIndustryText(option.name || '') === text;
  }

  function optionMatchesIndustryPair(option, familyText, subText) {
    if (!option) return false;
    const family = normalizeIndustryText(familyText);
    const sub = normalizeIndustryText(subText);
    const optionFamily = normalizeIndustryText(option.family || '');
    const optionSub = normalizeIndustryText(option.subIndustry || option.name || '');
    if (!sub || optionSub !== sub) return false;
    if (!family) return true;
    return optionFamily === family;
  }

  function optionMatchesIndustryFamily(option, familyText) {
    if (!option) return false;
    const family = normalizeIndustryText(familyText);
    if (!family) return true;
    return normalizeIndustryText(option.family || '') === family ||
           normalizeIndustryText(option.industry || '') === family;
  }

  function findSelfFamilyIndustryOption(options, familyText) {
    const family = normalizeIndustryText(familyText);
    if (!family) return null;
    return (options || []).find(option => {
      const optionFamily = normalizeIndustryText(option.family || '');
      const optionSub = normalizeIndustryText(option.subIndustry || option.name || '');
      return optionFamily === family && optionSub === family;
    }) || (options || []).find(option => optionMatchesIndustryPart(option, family));
  }

  function fallbackIndustryOptionsFlat() {
    return FY27_GTM_INDUSTRY_OPTIONS
      .map(option => {
        const out = makeGtmIndustryOption(
          `gtm:${gtmIndustryKey(option.industry, option.subgroup)}`,
          option.industry,
          option.subgroup,
          'FY27 GTM static fallback');
        if (out) out.sourceField = 'static';
        return out;
      })
      .filter(Boolean)
      .sort((a, b) => a.name.localeCompare(b.name));
  }

  function canonicalGtmIndustryOptions(options) {
    const dynamic = mergeDuplicateIndustryOptions(
      normalizeKnownIndustryOptions(options || []).filter(option => option && option.isGtmIndustryOption)
    );
    const byKey = {};
    dynamic.forEach(option => {
      if (option.gtmKey) byKey[option.gtmKey] = option;
    });
    return FY27_GTM_INDUSTRY_OPTIONS
      .map(option => {
        const key = gtmIndustryKey(option.industry, option.subgroup);
        return byKey[key] || makeGtmIndustryOption(
          `gtm:${key}`,
          option.industry,
          option.subgroup,
          'FY27 GTM static fallback');
      })
      .filter(Boolean)
      .sort((a, b) => a.name.localeCompare(b.name));
  }

  function loadIndustryOptionsFromBOW() {
    const fieldId = 'custrecord_sr_ind_rating_subindustry';
    const join = 'custrecord_sr_ind_rating_employee';
    const familyFieldCandidates = [
      'custrecord_sr_ind_rating_industry',
      'custrecord_sr_ind_rating_industry_family',
      'custrecord_sr_ind_rating_family',
      'custrecord_sr_ind_rating_industry_group',
      'custrecord_sr_industry_rating_industry',
    ];
    const filterSets = [
      () => amoBaseFilters(join),
      () => [
        new nlobjSearchFilter('custrecord_emproster_rosterstatus', join, 'is', 1),
        new nlobjSearchFilter('custrecord_emproster_eminactive', join, 'is', 'F'),
      ],
      () => [],
    ];

    function fetchOptions(makeFilters, familyField) {
      const cols = [new nlobjSearchColumn(fieldId)];
      if (familyField) cols.push(new nlobjSearchColumn(familyField));
      const rows = nlapiSearchRecord('customrecord_sr_industry_rating_entry', null, makeFilters(), cols) || [];
      const options = [];
      rows.forEach(r => {
        const id = r.getValue(fieldId);
        const subName = r.getText(fieldId) || r.getValue(fieldId) || '';
        const familyName = familyField ? (r.getText(familyField) || r.getValue(familyField) || '') : '';
        const gtmOptions = expandGtmIndustryOptions(id, subName);
        if (gtmOptions.length) {
          gtmOptions.forEach(option => {
            option.sourceField = 'fy27-gtm';
            options.push(option);
          });
          return;
        }
        const option = makeIndustryOption(id, subName, familyName);
        if (option) {
          option.sourceField = familyField || 'fallback';
          options.push(option);
        }
      });
      return chooseBestIndustryOptions(options);
    }

    for (const makeFilters of filterSets) {
      const allOptions = [];
      for (const familyField of familyFieldCandidates) {
        try {
          const options = fetchOptions(makeFilters, familyField);
          allOptions.push(...options);
        } catch (e) {
          console.warn('[Staffing Helper] Industry BOW family lookup failed:', familyField, e.message || e);
        }
      }
      if (allOptions.length) return chooseBestIndustryOptions(allOptions);
      try {
        const options = fetchOptions(makeFilters, null);
        if (options.length) return options;
      } catch (e) {
        console.warn('[Staffing Helper] Industry BOW option lookup failed:', e.message || e);
      }
    }
    return [];
  }

  function getFirstReadableField(fieldIds) {
    for (const fieldId of fieldIds) {
      let value = readFormFieldValue(fieldId);
      const text = readFormField(fieldId);
      if (!value && isLikelyInternalIdText(text)) value = text;
      if (value || text) return { value, text, fieldId };
    }
    return { value: '', text: '', fieldId: '' };
  }

  function isScoutPanelElement(el) {
    return Boolean(el && el.closest && el.closest('#sc-skills-panel'));
  }

  function isLikelyVisibleElement(el) {
    try {
      if (!el || isScoutPanelElement(el)) return false;
      const style = el.ownerDocument.defaultView.getComputedStyle(el);
      if (style.display === 'none' || style.visibility === 'hidden') return false;
      return true;
    } catch (e) {
      return Boolean(el && !isScoutPanelElement(el));
    }
  }

  function cleanVisibleFieldText(text) {
    return String(text || '')
      .replace(/\*/g, '')
      .replace(/\s+/g, ' ')
      .replace(/^[:\-|]+|[:\-|]+$/g, '')
      .trim();
  }

  function isLikelyNetSuiteFieldContainer(el) {
    if (!el || isScoutPanelElement(el)) return false;
    const selector = [
      '.uir-field-wrapper',
      '.uir-field',
      '.uir-field-wrapper-content',
      '.uir-field-wrapper-content-visible',
      '.field_widget',
      'td',
      'th',
    ].join(',');
    return Boolean(el.closest && el.closest(selector));
  }

  function stripVisibleLabel(text, labelPatterns) {
    let out = cleanVisibleFieldText(text);
    (labelPatterns || []).forEach(pattern => {
      out = out.replace(pattern, '').replace(/^[:\-|]+/, '').trim();
    });
    return cleanVisibleFieldText(out);
  }

  function isUsableVisibleIndustryValue(value, labelPatterns) {
    const text = cleanVisibleFieldText(value);
    if (!text || text.length > 120) return false;
    if (labelPatterns.some(pattern => pattern.test(text))) return false;
    if (/\bindustry\s+sub[- ]?group\b/i.test(text)) return false;
    if (/\b(?:industry family|industry group|sub[- ]?industry)\b/i.test(text)) return false;
    if (/^(sku|integrations?|partners?|competitors?|why we win|red flags?)\b/i.test(text)) return false;
    if (/staffed deal|sc manager notes|scm staffing notes|forecast notes/i.test(text)) return false;
    return true;
  }

  function readInlineTextAfterLabel(text, labelPatterns) {
    let out = cleanVisibleFieldText(text);
    for (const pattern of labelPatterns || []) {
      if (!pattern.test(out)) continue;
      out = out.replace(pattern, '').replace(/^[:\-|]+/, '').trim();
      return cleanVisibleFieldText(out);
    }
    return '';
  }

  function readUsableVisibleValue(el, labelPatterns) {
    if (!isLikelyVisibleElement(el)) return '';
    const value = stripVisibleLabel(el.textContent || el.value || '', labelPatterns);
    return isUsableVisibleIndustryValue(value, labelPatterns) ? value : '';
  }

  function readSiblingTextAfterLabel(labelEl, labelPatterns) {
    let sibling = labelEl && labelEl.nextElementSibling;
    while (sibling) {
      const value = readUsableVisibleValue(sibling, labelPatterns);
      if (value) return value;
      sibling = sibling.nextElementSibling;
    }
    return '';
  }

  function readTableCellTextAfterLabel(labelEl, labelPatterns) {
    const cell = labelEl && labelEl.closest && labelEl.closest('td, th');
    const row = cell && cell.parentElement;
    if (!row) return '';
    const cells = Array.from(row.children || []);
    const index = cells.indexOf(cell);
    for (let i = index + 1; i < cells.length; i++) {
      const value = readUsableVisibleValue(cells[i], labelPatterns);
      if (value) return value;
    }
    return '';
  }

  function readNextRowCellTextAfterLabel(labelEl, labelPatterns) {
    const cell = labelEl && labelEl.closest && labelEl.closest('td, th');
    const row = cell && cell.parentElement;
    const nextRow = row && row.nextElementSibling;
    if (!row || !nextRow) return '';
    const cells = Array.from(row.children || []);
    const nextCells = Array.from(nextRow.children || []);
    const index = cells.indexOf(cell);
    if (index < 0 || !nextCells[index] || !isLikelyVisibleElement(nextCells[index])) return '';
    return readUsableVisibleValue(nextCells[index], labelPatterns);
  }

  function readAncestorSiblingTextAfterLabel(labelEl, labelPatterns) {
    let node = labelEl;
    let depth = 0;
    while (node && depth < 5) {
      let sibling = node.nextElementSibling;
      let siblingCount = 0;
      while (sibling && siblingCount < 6) {
        const value = readUsableVisibleValue(sibling, labelPatterns);
        if (value) return value;
        sibling = sibling.nextElementSibling;
        siblingCount += 1;
      }
      node = node.parentElement;
      depth += 1;
    }
    return '';
  }

  function readContainerTextAfterLabel(labelEl, labelPatterns) {
    const containers = [
      labelEl && labelEl.closest && labelEl.closest('.uir-field-wrapper, .uir-field, .uir-field-wrapper-content, .uir-field-wrapper-content-visible, .field_widget'),
      labelEl && labelEl.parentElement,
    ].filter(Boolean);
    for (const container of containers) {
      if (!isLikelyVisibleElement(container)) continue;
      const text = stripVisibleLabel(container.textContent || container.value || '', labelPatterns);
      if (text && text.length <= 160 && isUsableVisibleIndustryValue(text, labelPatterns)) return text;
    }
    return '';
  }

  function readVisiblePageValueByLabels(labelPatterns) {
    const labelEls = [];
    getAccessibleDocuments().forEach(doc => {
      try {
        doc.querySelectorAll('label, span, div, td, th').forEach(el => {
          if (!isLikelyVisibleElement(el)) return;
          const text = cleanVisibleFieldText(el.textContent || '');
          if (!text || text.length > 180) return;
          const inlineValue = readInlineTextAfterLabel(text, labelPatterns);
          if (inlineValue && isUsableVisibleIndustryValue(inlineValue, labelPatterns)) {
            labelEls.push({ el, inlineValue });
            return;
          }
          if (labelPatterns.some(pattern => pattern.test(text)) && isLikelyNetSuiteFieldContainer(el)) {
            labelEls.push({ el, inlineValue: '' });
            return;
          }
          if (labelPatterns.some(pattern => pattern.test(text)) && text.length <= 40) {
            labelEls.push({ el, inlineValue: '' });
          }
        });
      } catch (e) { /* keep scanning other documents */ }
    });

    for (const item of labelEls) {
      const el = item.el || item;
      const values = [
        item.inlineValue,
        readSiblingTextAfterLabel(el, labelPatterns) ||
          '',
        readTableCellTextAfterLabel(el, labelPatterns),
        readNextRowCellTextAfterLabel(el, labelPatterns),
        readAncestorSiblingTextAfterLabel(el, labelPatterns),
        readContainerTextAfterLabel(el, labelPatterns),
      ];
      const value = values.find(candidate => isUsableVisibleIndustryValue(candidate, labelPatterns));
      if (isUsableVisibleIndustryValue(value, labelPatterns)) return value;
    }
    return '';
  }

  function getVisibleDocumentTextWithoutScout(doc) {
    try {
      if (!doc || !doc.body) return '';
      const clone = doc.body.cloneNode(true);
      clone.querySelectorAll('#sc-skills-panel, #sc-skills-toggle, script, style, noscript').forEach(el => el.remove());
      return clone.innerText || clone.textContent || '';
    } catch (e) {
      return '';
    }
  }

  function readVisibleValueFromLines(lines, startIndex, labelPatterns, stopPatterns) {
    const maxIndex = Math.min(lines.length, startIndex + 7);
    const inlineValue = readInlineTextAfterLabel(lines[startIndex], labelPatterns);
    if (isUsableVisibleIndustryValue(inlineValue, labelPatterns)) return inlineValue;

    const valueLines = [];
    for (let i = startIndex + 1; i < maxIndex; i++) {
      const line = cleanVisibleFieldText(lines[i]);
      if (!line) continue;
      if ((stopPatterns || []).some(pattern => pattern.test(line))) break;
      const lineInlineValue = readInlineTextAfterLabel(line, labelPatterns);
      if (isUsableVisibleIndustryValue(lineInlineValue, labelPatterns)) return lineInlineValue;
      if (isUsableVisibleIndustryValue(line, labelPatterns)) valueLines.push(line);
    }
    const joinedValue = cleanVisibleFieldText(valueLines.join(' '));
    if (isUsableVisibleIndustryValue(joinedValue, labelPatterns)) return joinedValue;
    return '';
  }

  function readVisibleScrIndustryPairFromPageText() {
    const familyPatterns = [
      /^(?:industry family|industry group|industry)(?!\s+sub[- ]?group)\s*(?:[:\-|]\s*|\s+|$)/i,
    ];
    const subPatterns = [
      /^(?:industry sub[- ]?group|industry subgroup|sub[- ]?industry)\s*(?:[:\-|]\s*|\s+|$)/i,
    ];

    for (const doc of getAccessibleDocuments()) {
      const lines = getVisibleDocumentTextWithoutScout(doc)
        .split(/\r?\n/)
        .map(cleanVisibleFieldText)
        .filter(Boolean);
      if (!lines.length) continue;

      for (let i = 0; i < lines.length; i++) {
        if (!familyPatterns.some(pattern => pattern.test(lines[i]))) continue;
        const family = readVisibleValueFromLines(lines, i, familyPatterns, subPatterns);
        if (!family) continue;

        const maxSubIndex = Math.min(lines.length, i + 12);
        for (let j = i + 1; j < maxSubIndex; j++) {
          if (!subPatterns.some(pattern => pattern.test(lines[j]))) continue;
          const sub = readVisibleValueFromLines(lines, j, subPatterns, familyPatterns);
          if (sub) return { family, sub };
        }
      }
    }
    return { family: '', sub: '' };
  }

  function getVisibleScrIndustryPair() {
    const labelPair = {
      family: readVisiblePageValueByLabels([
        /^(?:industry family|industry group|industry)(?!\s+sub[- ]?group)\s*(?:[:\-|]\s*|\s+|$)/i,
      ]),
      sub: readVisiblePageValueByLabels([
        /^(?:industry sub[- ]?group|industry subgroup|sub[- ]?industry)\s*(?:[:\-|]\s*|\s+|$)/i,
      ]),
    };
    if (labelPair.family && labelPair.sub) return labelPair;

    const pageTextPair = readVisibleScrIndustryPairFromPageText();
    return {
      family: labelPair.family || pageTextPair.family,
      sub: labelPair.sub || pageTextPair.sub,
    };
  }

  function getScrIndustryDefault(options) {
    let sub = getFirstReadableField(SCR_FIELD_INDUSTRY_SUBGROUP_CANDIDATES);
    let family = getFirstReadableField(SCR_FIELD_INDUSTRY_FAMILY_CANDIDATES);
    const hasGtmSub = sub.fieldId === SCR_FIELD_GTM_INDUSTRY_SUBGROUP;
    const hasGtmFamily = family.fieldId === SCR_FIELD_GTM_INDUSTRY;
    const visibleIndustry = getVisibleScrIndustryPair();

    if (!hasGtmSub && visibleIndustry.sub && !isLikelyInternalIdText(visibleIndustry.sub)) {
      sub = { ...sub, text: visibleIndustry.sub };
    }
    if (!hasGtmFamily && visibleIndustry.family && !isLikelyInternalIdText(visibleIndustry.family)) {
      family = { ...family, text: visibleIndustry.family };
    }

    if ((!sub.value && !sub.text) || (!family.value && !family.text)) {
      try {
        const companyId = (nlapiGetFieldValue(SCR_FIELD_COMPANY) || '').trim();
        if (companyId) {
          const rows = nlapiSearchRecord('entity', null, [
            new nlobjSearchFilter('internalid', null, 'is', companyId),
          ], [
            new nlobjSearchColumn('custentity_zoominfo_subindustry'),
            new nlobjSearchColumn('custentity_zoominfo_industry'),
          ]) || [];
          if (rows.length) {
            const r = rows[0];
            if (!sub.value && !sub.text) {
              sub = {
                value: r.getValue('custentity_zoominfo_subindustry') || '',
                text: r.getText('custentity_zoominfo_subindustry') || '',
              };
            }
            if (!family.value && !family.text) {
              family = {
                value: r.getValue('custentity_zoominfo_industry') || '',
                text: r.getText('custentity_zoominfo_industry') || '',
              };
            }
          }
        }
      } catch (e) { /* company fallback is best-effort */ }
    }

    const subLabel = sub.text || sub.value;
    const familyLabel = family.text || family.value;
    const subText = normalizeIndustryText(subLabel);
    const familyText = normalizeIndustryText(familyLabel);
    const hasReadableSubLabel = subText && !isLikelyInternalIdText(subLabel);
    const hasReadableFamilyLabel = familyText && !isLikelyInternalIdText(familyLabel);

    if (hasReadableSubLabel) {
      const exactPair = options.find(o => optionMatchesIndustryPair(o, familyLabel, subLabel));
      if (exactPair) return exactPair.id;

      const rollups = getGtmRollupsForSubIndustry(subLabel)
        .filter(option => optionMatchesIndustryFamily(option, familyLabel));
      const rollup = rollups
        .map(option => gtmIndustryKey(option.industry, option.subgroup));
      const gtmMatch = options.find(o => o.gtmKey && rollup.includes(o.gtmKey));
      if (gtmMatch) return gtmMatch.id;

      const exactSub = !familyText
        ? options.find(o => optionMatchesIndustryPart(o, subLabel))
        : null;
      if (exactSub) return exactSub.id;
    }

    if (sub.value) {
      const byValue = options.find(o => String(o.id).split(',').includes(String(sub.value)));
      if (byValue) {
        if (sub.fieldId === SCR_FIELD_GTM_INDUSTRY_SUBGROUP) return byValue.id;
        if (!hasReadableSubLabel) return byValue.id;
        if (familyText && !hasReadableFamilyLabel) return byValue.id;
        if (optionMatchesIndustryPair(byValue, familyLabel, subLabel) ||
            (!familyText && optionMatchesIndustryPart(byValue, subLabel))) {
          return byValue.id;
        }
        console.warn('[SCOUT] Ignoring SCR industry internal ID because visible text points elsewhere:', {
          subValue: sub.value,
          subLabel,
          familyLabel,
          matchedOption: byValue.name,
        });
      }
    }

    const selfFamily = findSelfFamilyIndustryOption(options, familyLabel);
    return selfFamily ? selfFamily.id : '';
  }

  function applyIndustryOptions(options) {
    const markup = `<option value="">— Any industry —</option>${buildIndustryOptionMarkup(options)}`;
    const defaultIndustryId = getScrIndustryDefault(options || []);
    ['sc-industry', 'sc-amo-industry'].forEach(selectId => {
      const select = document.getElementById(selectId);
      if (!select) return;
      const current = select.value;
      select.innerHTML = markup;
      const optionValues = Array.from(select.options).map(o => o.value);
      if (current && optionValues.includes(current)) {
        select.value = current;
      } else if (defaultIndustryId && optionValues.includes(defaultIndustryId)) {
        select.value = defaultIndustryId;
      }
    });
  }

  function refreshIndustryOptionsFromBOW() {
    if (INDUSTRY_OPTIONS_CACHE && INDUSTRY_OPTIONS_CACHE.length) {
      applyIndustryOptions(INDUSTRY_OPTIONS_CACHE);
      return;
    }
    const options = loadIndustryOptionsFromBOW();
    INDUSTRY_OPTIONS_CACHE = canonicalGtmIndustryOptions(options);
    applyIndustryOptions(INDUSTRY_OPTIONS_CACHE);
  }

  function normalizeProductName(name) {
    return String(name || '').toLowerCase().replace(/&/g, 'and').replace(/[^a-z0-9]+/g, ' ').trim();
  }

  const RETIRED_PRODUCT_SKILL_KEYS = new Set([
    'WMS-Lite',
    'WMS-Advanced',
  ].map(normalizeProductName));

  function isRetiredProductSkillName(name) {
    return RETIRED_PRODUCT_SKILL_KEYS.has(normalizeProductName(name));
  }

  function productNamesCompatible(a, b) {
    const aKey = normalizeProductName(a);
    const bKey = normalizeProductName(b);
    if (!aKey || !bKey) return false;
    return aKey === bKey || aKey.includes(bKey) || bKey.includes(aKey);
  }

  function getScrProductOptionControls() {
    const controls = [];
    const seen = new Set();
    function addSelect(el) {
      if (!el || el.tagName !== 'SELECT' || !el.options || !el.options.length || seen.has(el)) return;
      if (el.closest && el.closest('#sc-skills-panel')) return;
      if (/^sc-/i.test(el.id || '')) return;
      seen.add(el);
      controls.push(el);
    }
    SCR_FIELD_PRODUCT_CANDIDATES.forEach(fieldId => {
      findFieldControls(fieldId).forEach(el => {
        addSelect(el);
        try {
          if (el.querySelectorAll) el.querySelectorAll('select').forEach(addSelect);
        } catch (e) { /* keep scanning */ }
        try {
          const row = el.closest && el.closest('tr, .uir-field-wrapper, .uir-field, .field_widget, .uir-field-wrapper-content');
          if (row) row.querySelectorAll('select').forEach(addSelect);
        } catch (e) { /* keep scanning */ }
      });
    });
    getAccessibleDocuments().forEach(doc => {
      try {
        const labels = Array.from(doc.querySelectorAll('label, span, div, td, th'))
          .filter(el => {
            if (el.closest && el.closest('#sc-skills-panel')) return false;
            const text = (el.textContent || '').replace(/\s+/g, ' ').replace(/\*/g, '').trim();
            return text.length > 0 && text.length < 80 && (
              /^products?\s*(\(\s*s\s*\))?\s*:?\s*$/i.test(text) ||
              /^product\s*\(\s*s\s*\)\b/i.test(text)
            );
          });
        labels.forEach(label => {
          const row = label.closest && label.closest('tr, .uir-field-wrapper, .uir-field, .field_widget, .uir-field-wrapper-content');
          if (row) row.querySelectorAll('select').forEach(addSelect);
          if (label.htmlFor) addSelect(doc.getElementById(label.htmlFor));
        });
      } catch (e) { /* best effort */ }
    });
    return controls;
  }

  function safeJsonParse(value, fallback) {
    try {
      return JSON.parse(value || '');
    } catch (e) {
      return fallback;
    }
  }

  function getNsMultiDropdownProductWidgets() {
    const widgets = [];
    const seen = new Set();
    const names = new Set(SCR_PRODUCT_UI_FIELD_NAMES);
    getAccessibleDocuments().forEach(doc => {
      try {
        doc.querySelectorAll('.ns-multi-dropdown[data-name], [data-name="custpage_product_type_ui"]').forEach(el => {
          if (!el || seen.has(el)) return;
          const name = el.getAttribute('data-name') || '';
          const options = el.getAttribute('data-options') || '';
          if (!names.has(name) && !/Product|SuitePeople|Advanced Manufacturing|Work Orders/i.test(options)) return;
          seen.add(el);
          widgets.push(el);
        });
      } catch (e) { /* keep scanning */ }
    });
    return widgets;
  }

  function parseNsMultiDropdownOptions(widget) {
    return safeJsonParse(widget && widget.getAttribute('data-options'), [])
      .map(o => ({
        value: String(o && o.value != null ? o.value : '').trim(),
        text: String(o && o.text != null ? o.text : '').trim(),
      }))
      .filter(o => o.value && o.text);
  }

  function getScrProductOptions() {
    const byValue = {};
    const byText = {};
    const options = [];
    function addOption(value, text) {
      value = String(value || '').trim();
      text = String(text || '').trim();
      if (!value || !text) return;
      const item = { value, text };
      if (!byValue[value]) {
        byValue[value] = item;
        options.push(item);
      }
      const key = normalizeProductName(text);
      if (key && !byText[key]) byText[key] = item;
    }

    getScrProductOptionControls().forEach(select => {
      Array.from(select.options || []).forEach(option => {
        addOption(option.value, option.text || option.label || '');
      });
    });
    getNsMultiDropdownProductWidgets().forEach(widget => {
      parseNsMultiDropdownOptions(widget).forEach(option => addOption(option.value, option.text));
    });
    return { options, byValue, byText };
  }

  function findScrProductOptionForEntry(entry, scrOptions) {
    if (!entry) return null;
    const byValue = scrOptions.byValue || {};
    const byText = scrOptions.byText || {};
    const value = String(entry.scrValue || entry.value || '').trim();
    const text = String(entry.text || entry.label || '').trim();
    if (value && byValue[value]) return byValue[value];
    const directTextKey = normalizeProductName(text);
    if (directTextKey && byText[directTextKey]) return byText[directTextKey];
    const product = PRODUCTS.find(p => String(p.id) === value);
    const productKey = product ? normalizeProductName(product.name) : '';
    if (productKey && byText[productKey]) return byText[productKey];

    const candidateKeys = [directTextKey, productKey].filter(Boolean);
    if (!candidateKeys.length) return null;
    return (scrOptions.options || []).find(option => {
      const optionKey = normalizeProductName(option.text);
      return candidateKeys.some(key => optionKey === key || optionKey.includes(key) || key.includes(optionKey));
    }) || null;
  }

  function findHelperProductOption(selectEl, productId, label) {
    const options = Array.from((selectEl && selectEl.options) || []);
    const idText = String(productId || '');
    let match = options.find(o => String(o.value) === idText || String(o.dataset.scrValue || '') === idText);
    if (match) return match;

    const product = PRODUCTS.find(p => String(p.id) === idText);
    const keys = [
      normalizeProductName(label),
      product ? normalizeProductName(product.name) : '',
    ].filter(Boolean);
    return options.find(option => {
      const optionKey = normalizeProductName(option.text || option.label || '');
      return keys.some(key => optionKey === key || optionKey.includes(key) || key.includes(optionKey));
    }) || null;
  }

  function getProductSkillIdFromOption(option) {
    if (!option) return '';
    if (option.dataset && option.dataset.skillId) return option.dataset.skillId;
    if (option.dataset && option.dataset.optionType === 'skill') return option.value;
    if (PRODUCT_SKILL_OPTIONS_CACHE && PRODUCT_SKILL_OPTIONS_CACHE.some(o => String(o.value) === String(option.value))) return option.value;
    if (PRODUCT_SKILL_MAP[option.value]) return PRODUCT_SKILL_MAP[option.value];
    const optionName = normalizeProductName(option.text || option.label || option.value);
    const product = PRODUCTS.find(p => normalizeProductName(p.name) === optionName);
    return product ? PRODUCT_SKILL_MAP[product.id] : '';
  }

  function getSelectedProductSkillIds(selectId) {
    const el = document.getElementById(selectId);
    if (!el) return [];
    return Array.from(el.selectedOptions).map(getProductSkillIdFromOption).filter(Boolean);
  }

  function refreshProductOptionsFromScrForm() {
    const opts = getScrProductOptions().options
      .filter(o => o.value && o.text)
      .sort((a, b) => a.text.localeCompare(b.text));
    if (!opts.length) return;
    ['sc-products', 'sc-amo-products'].forEach(selectId => {
      const target = document.getElementById(selectId);
      if (!target || target.dataset.scrOptionsLoaded === 'true') return;
      target.innerHTML = opts.map(o => `<option value="${escAttr(o.value)}" data-scr-value="${escAttr(o.value)}">${escHtml(o.text)}</option>`).join('');
      target.dataset.scrOptionsLoaded = 'true';
    });
  }

  function getProductIdForSkillId(skillId) {
    const found = Object.entries(PRODUCT_SKILL_MAP).find(([, mappedSkillId]) => String(mappedSkillId) === String(skillId));
    return found ? found[0] : '';
  }

  function resolveScrProductForSkill(skillId, skillText, scrOptions) {
    const skillKey = normalizeProductName(skillText);
    if (skillKey && scrOptions.byText && scrOptions.byText[skillKey]) return scrOptions.byText[skillKey];

    const productId = getProductIdForSkillId(skillId);
    const product = productId ? PRODUCTS.find(p => String(p.id) === String(productId)) : null;
    const mappedProductCompatible = product && productNamesCompatible(skillText, product.name);
    const productKey = mappedProductCompatible ? normalizeProductName(product.name) : '';
    if (productKey && scrOptions.byText && scrOptions.byText[productKey]) return scrOptions.byText[productKey];

    const keys = [skillKey, productKey].filter(Boolean);
    const textMatch = (scrOptions.options || []).find(option => {
      const optionKey = normalizeProductName(option.text);
      return keys.some(key => optionKey === key || optionKey.includes(key) || key.includes(optionKey));
    });
    if (textMatch) return textMatch;

    if (productId && scrOptions.byValue && scrOptions.byValue[productId] && productNamesCompatible(skillText, scrOptions.byValue[productId].text)) {
      return scrOptions.byValue[productId];
    }

    return mappedProductCompatible ? { value: productId, text: product.name } : null;
  }

  function applyProductSkillOptions(options) {
    const markup = buildProductSkillOptionMarkup(options);
    ['sc-product-skills', 'sc-amo-product-skills'].forEach(selectId => {
      const target = document.getElementById(selectId);
      if (!target) return;
      const selected = new Set(Array.from(target.selectedOptions || []).map(o => String(o.value)));
      target.innerHTML = markup;
      Array.from(target.options || []).forEach(option => {
        option.selected = selected.has(String(option.value));
      });
    });
    syncProductsToMappedProductSkills('sc-products', 'sc-product-skills');
    syncProductsToMappedProductSkills('sc-amo-products', 'sc-amo-product-skills');
  }

  function optionMatchesLooseQuery(option, query) {
    const q = normalizeProductName(query);
    if (!q) return true;
    const text = normalizeProductName(option?.text || option?.label || option?.value || '');
    if (!text) return false;
    if (text.includes(q)) return true;
    const tokens = q.split(/\s+/).filter(Boolean);
    return tokens.length > 1 && tokens.every(token => text.includes(token));
  }

  function filterSelectOptionsByQuery(selectId, rawQuery) {
    const selectEl = document.getElementById(selectId);
    if (!selectEl) return;
    Array.from(selectEl.options || []).forEach(option => {
      const matched = optionMatchesLooseQuery(option, rawQuery);
      option.hidden = !matched;
      option.style.display = matched ? '' : 'none';
    });
  }

  function bestLooseMatchOption(selectEl, rawQuery) {
    const q = normalizeProductName(rawQuery);
    if (!selectEl || !q) return null;
    const candidates = Array.from(selectEl.options || [])
      .map(option => {
        const text = normalizeProductName(option.text || option.label || option.value || '');
        const tokens = q.split(/\s+/).filter(Boolean);
        let score = 99;
        if (text === q) score = 0;
        else if (text.startsWith(q)) score = 1;
        else if (text.includes(q)) score = 2;
        else if (tokens.length > 1 && tokens.every(token => text.includes(token))) score = 3;
        return { option, score, text };
      })
      .filter(item => item.score < 99)
      .sort((a, b) => a.score - b.score || a.text.length - b.text.length || a.text.localeCompare(b.text));
    return candidates.length ? candidates[0].option : null;
  }

  function resetSelectFilter(inputEl, selectEl) {
    if (inputEl) inputEl.value = '';
    if (!selectEl) return;
    Array.from(selectEl.options || []).forEach(option => {
      option.hidden = false;
      option.style.display = '';
    });
  }

  function addProductSkillFromFilter(inputId, skillSelectId, productSelectId) {
    const inputEl = document.getElementById(inputId);
    const skillSelect = document.getElementById(skillSelectId);
    if (!inputEl || !skillSelect) return false;
    const query = inputEl.value.trim();
    if (!query) return false;

    const option = bestLooseMatchOption(skillSelect, query);
    if (!option) {
      showToast(`No product skill found matching "${query}".`, 'info', 4000);
      return false;
    }

    const selected = Array.from(skillSelect.selectedOptions || []);
    if (!option.selected && selected.length >= 4) {
      showToast('Product Skill limit is 4. Remove one to add another.', 'info', 4500);
      return false;
    }

    const wasSelected = option.selected;
    option.selected = true;
    resetSelectFilter(inputEl, skillSelect);
    enforceSelectLimit(skillSelect, 4);
    dispatchFieldEvents(skillSelect);
    syncMappedProductSkillsToProducts(productSelectId, skillSelectId);
    showToast(`${wasSelected ? 'Already selected' : 'Added'} product skill: ${option.text}`, wasSelected ? 'info' : 'success', 3500);
    return true;
  }

  function loadProductSkillOptionsFromMatrix() {
    const scrOptions = getScrProductOptions();
    const bySkill = {};
    let lastInternalId = 0;
    let guard = 0;
    const join = 'custrecord_ssm_skill_employee';
    const skillEntryJoin = 'custrecord_ssm_skill_entry';
    let skillActiveFilterSupported = true;

    function addSkill(skillId, skillText) {
      skillId = String(skillId || '').trim();
      skillText = String(skillText || '').trim();
      if (!skillId || !skillText || bySkill[skillId]) return;
      if (isRetiredProductSkillName(skillText)) return;
      const scrMatch = resolveScrProductForSkill(skillId, skillText, scrOptions);
      bySkill[skillId] = {
        value: skillId,
        text: skillText,
        scrValue: scrMatch ? scrMatch.value : '',
        scrText: scrMatch ? scrMatch.text : '',
      };
    }

    function buildSkillOptionFilters(extraFilters) {
      const filters = [
        ...(extraFilters || []),
        new nlobjSearchFilter('custrecord_ssm_skill_entry', null, 'noneof', '@NONE@'),
        new nlobjSearchFilter('custrecord_emproster_rosterstatus', join, 'is', 1),
        new nlobjSearchFilter('custrecord_emproster_eminactive',   join, 'is', 'F'),
        new nlobjSearchFilter('custrecord_emproster_sales_qb',     join, 'is', 25),
        new nlobjSearchFilter('custrecord_emproster_ocostcenter',  join, 'is', ROSTER_COST_CENTER_ID),
        new nlobjSearchFilter('custrecord_emproster_salesregion',  join, 'is', ROSTER_SALES_REGION_ID),
      ];
      if (skillActiveFilterSupported) {
        filters.push(new nlobjSearchFilter('isinactive', skillEntryJoin, 'is', 'F'));
      }
      return filters;
    }

    try {
      const skillCol = new nlobjSearchColumn('custrecord_ssm_skill_entry', null, 'group');
      const rows = nlapiSearchRecord('customrecord_ssm_entry', null, buildSkillOptionFilters(), [skillCol]) || [];
      rows.forEach(row => {
        addSkill(
          row.getValue('custrecord_ssm_skill_entry', null, 'group') || row.getValue('custrecord_ssm_skill_entry'),
          row.getText('custrecord_ssm_skill_entry', null, 'group') || row.getText('custrecord_ssm_skill_entry')
        );
      });
      if (Object.keys(bySkill).length) {
        return Object.values(bySkill).sort((a, b) => a.text.localeCompare(b.text));
      }
    } catch (e) {
      console.warn('[SCOUT] Grouped product skill option search failed; falling back to paged matrix scan.', e);
    }

    while (guard < 30) {
      guard += 1;
      const filters = buildSkillOptionFilters([
        new nlobjSearchFilter('internalidnumber', null, 'greaterthan', lastInternalId),
      ]);
      const idCol = new nlobjSearchColumn('internalid');
      try { idCol.setSort(false); } catch (e) { /* best effort sort */ }
      const cols = [
        idCol,
        new nlobjSearchColumn('custrecord_ssm_skill_entry'),
      ];
      let rows = [];
      try {
        rows = nlapiSearchRecord('customrecord_ssm_entry', null, filters, cols) || [];
      } catch (e) {
        if (skillActiveFilterSupported) {
          skillActiveFilterSupported = false;
          console.warn('[SCOUT] Product skill active filter failed; retrying matrix scan with retired-skill guard only.', e);
          continue;
        }
        console.warn('[SCOUT] Product skill option matrix scan failed.', e);
        break;
      }
      if (!rows.length) break;

      rows.forEach(row => {
        const rowId = parseInt(row.getValue('internalid'), 10) || 0;
        if (rowId > lastInternalId) lastInternalId = rowId;
        addSkill(row.getValue('custrecord_ssm_skill_entry'), row.getText('custrecord_ssm_skill_entry'));
      });

      if (rows.length < 1000 || !lastInternalId) break;
    }

    return Object.values(bySkill).sort((a, b) => a.text.localeCompare(b.text));
  }

  function refreshProductSkillOptionsFromMatrix() {
    if (PRODUCT_SKILL_OPTIONS_CACHE && PRODUCT_SKILL_OPTIONS_CACHE.length) {
      applyProductSkillOptions(PRODUCT_SKILL_OPTIONS_CACHE);
      return;
    }
    try {
      const options = loadProductSkillOptionsFromMatrix();
      PRODUCT_SKILL_OPTIONS_CACHE = options.length ? options : fallbackProductSkillOptions();
      applyProductSkillOptions(PRODUCT_SKILL_OPTIONS_CACHE);
      console.log('[SCOUT] Loaded product skill options:', PRODUCT_SKILL_OPTIONS_CACHE.length);
    } catch (e) {
      PRODUCT_SKILL_OPTIONS_CACHE = fallbackProductSkillOptions();
      applyProductSkillOptions(PRODUCT_SKILL_OPTIONS_CACHE);
      console.warn('[SCOUT] Product skill matrix option load failed; using fallback product skill map.', e);
    }
  }

