  /* ────────────────────────────────────────────────────────────────
     TOAST NOTIFICATIONS
  ──────────────────────────────────────────────────────────────── */

  let _toastTimer = null;
  let _pageToastTimer = null;

  function showToast(msg, type, duration) {
    const t = document.getElementById('sc-toast');
    if (!t) return;
    t.textContent = msg;
    t.className = `show ${type || 'info'}`;
    clearTimeout(_toastTimer);
    _toastTimer = setTimeout(() => { t.className = ''; }, duration || 4000);
  }

  function showPageToast(msg, type, duration) {
    let t = document.getElementById('sc-page-toast');
    if (!t) {
      t = document.createElement('div');
      t.id = 'sc-page-toast';
      document.body.appendChild(t);
    }
    t.textContent = msg;
    t.className = `show ${type || 'info'}`;
    clearTimeout(_pageToastTimer);
    _pageToastTimer = setTimeout(() => { t.className = ''; }, duration || 4000);
  }

  /* ────────────────────────────────────────────────────────────────
     NETSUITE FIELD HELPERS
  ──────────────────────────────────────────────────────────────── */

  function todayString() {
    const d = new Date();
    const mm = String(d.getMonth() + 1).padStart(2, '0');
    const dd = String(d.getDate()).padStart(2, '0');
    const yy = String(d.getFullYear()).slice(-2);
    return `${mm}/${dd}/${yy}`;
  }

  function todayFullString() {
    const d = new Date();
    const mm = String(d.getMonth() + 1).padStart(2, '0');
    const dd = String(d.getDate()).padStart(2, '0');
    const yyyy = d.getFullYear();
    return `${mm}/${dd}/${yyyy}`;
  }

  function getRequestDetails() { return nlapiGetFieldValue('custrecord_screq_details') || ''; }
  function getHashtags()       { return nlapiGetFieldValue('custrecord_screq_hashtags') || ''; }
  function hasHashtag(current, tag) {
    const escaped = String(tag || '').replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    return new RegExp(`(^|[\\s,;])${escaped}(?=$|[\\s,;])`, 'i').test(String(current || ''));
  }
  function addHashtagOnce(tag) {
    const current = getHashtags();
    if (hasHashtag(current, tag)) return;
    nlapiSetFieldValue('custrecord_screq_hashtags', current ? `${tag},${current}` : tag, true);
  }
  function setScoutHashtag() {
    addHashtagOnce('#scout');
  }

  /** Read SC Request date-needed field and return YYYY-MM-DD. */
  function getReqDateYMD() {
    const raw = nlapiGetFieldValue('custrecord_screq_date_needed') || '';
    if (!raw) return '';
    const parts = raw.split('/');
    if (parts.length === 3) {
      const [mm, dd, yyyy] = parts;
      return `${yyyy}-${mm.padStart(2, '0')}-${dd.padStart(2, '0')}`;
    }
    return raw;
  }

  function triggerNetSuiteFieldEvents(fieldId) {
    try {
      findFieldControls(fieldId).forEach(el => dispatchFieldEvents(el));
    } catch (e) { /* best effort */ }
  }

  function setFieldValueWithSyncSourcing(fieldId, value) {
    let wrote = false;
    try {
      nlapiSetFieldValue(fieldId, value, true, true);
      wrote = true;
    } catch (e) {
      try {
        nlapiSetFieldValue(fieldId, value, true);
        wrote = true;
      } catch (inner) { /* try current-record fallback below */ }
    }

    try {
      const rec = unsafeWindow.nlapiGetCurrentRecord && unsafeWindow.nlapiGetCurrentRecord();
      if (rec && typeof rec.setValue === 'function') {
        rec.setValue({
          fieldId,
          value,
          ignoreFieldChange: false,
          forceSyncSourcing: true,
        });
        wrote = true;
      } else if (rec && typeof rec.setFieldValue === 'function') {
        rec.setFieldValue(fieldId, value);
        wrote = true;
      }
    } catch (e) { /* current-record fallback may not be available */ }

    triggerNetSuiteFieldEvents(fieldId);
    return wrote;
  }

  function getRosterEmployeeId(rosterId) {
    const key = String(rosterId || '').trim();
    if (!key) return '';
    if (Object.prototype.hasOwnProperty.call(ASSIGNEE_EMPLOYEE_CACHE, key)) {
      return ASSIGNEE_EMPLOYEE_CACHE[key];
    }
    let employeeId = '';
    try {
      employeeId = String(nlapiLookupField('customrecord_emproster', key, 'custrecord_emproster_emp') || '').trim();
    } catch (e) {
      console.warn('[Staffing Helper] Could not resolve assignee employee for roster:', key, e.message || e);
    }
    ASSIGNEE_EMPLOYEE_CACHE[key] = employeeId;
    return employeeId;
  }

  function setStatus(id)   { setFieldValueWithSyncSourcing('custrecord_screq_status', id); }
  function setAssignee(id) {
    setFieldValueWithSyncSourcing(SCR_FIELD_ASSIGNEE, id);
    const employeeId = getRosterEmployeeId(id);
    if (employeeId) setFieldValueWithSyncSourcing(SCR_FIELD_ASSIGNEE_EMPLOYEE, employeeId);
    setTimeout(() => triggerNetSuiteFieldEvents(SCR_FIELD_ASSIGNEE), 250);
  }
  function setLeadAssigned(assignAsLead) {
    nlapiSetFieldValue('custrecord_screq_assigned_lead', assignAsLead ? 'T' : 'F', true);
  }
  function setLeadTrue()   { setLeadAssigned(true); }
  function prependRequestDetails(text) {
    const prefix = String(text || '');
    const existing = getRequestDetails();
    const remaining = Math.max(0, SCR_REQUEST_DETAILS_MAX_CHARS - prefix.length);
    let nextValue = prefix + String(existing || '').slice(0, remaining);
    if (nextValue.length > SCR_REQUEST_DETAILS_MAX_CHARS) {
      nextValue = nextValue.slice(0, SCR_REQUEST_DETAILS_MAX_CHARS);
    }
    nlapiSetFieldValue('custrecord_screq_details', nextValue, true);
  }
  function getInitials(name) {
    return String(name || '')
      .trim()
      .split(/\s+/)
      .filter(Boolean)
      .map(part => part.charAt(0).toUpperCase())
      .join('');
  }
  function getCommentInitials(name) {
    return getCommentInitialsOverride() || getInitials(name);
  }
  function buildDirectManagerNotesTemplate(empName) {
    const initials = getCommentInitials(empName);
    const staffedBy = initials ? `${empName}/${initials}` : empName;
    return [
      'Industry: ',
      'SKU: ',
      'Integrations:',
      'Partners:',
      'Competitors: ',
      '__',
      'Why we win: ',
      'Red Flags: ',
      '__',
      `${todayFullString()} - Staffed Deal [${staffedBy}]`,
    ].join('\n');
  }
  function buildEngagementNotesTemplate(empName) {
    const initials = getCommentInitials(empName);
    return [
      todayFullString(),
      'Last Steps:',
      'Next Steps:',
      'Red Flags: ',
      'Value/Impact:',
      `[${initials}]`,
    ].join('\n');
  }
  function setDirectManagerNotes(empName) {
    appendScManagerNotes(buildDirectManagerNotesTemplate(empName), /Staffed Deal\s*\[/i);
  }
  function buildAdditionalRequestDetailsBlock(details) {
    const cleaned = String(details || '').trim();
    return cleaned ? `Additional staffing details:\n${cleaned}\n` : '';
  }

  /** Wrap a staffing note with the standard ADDED/end markers (item 3). */
  function wrapStaffingNote(requestDetailsScript, empName, requestDetailsNote) {
    const d = new Date();
    const mm = String(d.getMonth() + 1).padStart(2, '0');
    const dd = String(d.getDate()).padStart(2, '0');
    const yy = String(d.getFullYear()).slice(2);
    const header = `-- ADDED by ${empName} on ${mm}/${dd}/${yy} --\n`;
    const footer = `----- end of SC assignment ----\n\n`;
    const baseNote = String(requestDetailsScript || '');
    const additionalDetails = buildAdditionalRequestDetailsBlock(requestDetailsNote);
    const separator = additionalDetails && baseNote && !/\n$/.test(baseNote) ? '\n' : '';
    return header + baseNote + separator + additionalDetails + footer;
  }

  function getCurrentScrId() {
    try {
      return new URLSearchParams(window.location.search).get('id') || nlapiGetFieldValue('id') || nlapiGetFieldValue('internalid') || '';
    } catch (e) {
      return '';
    }
  }

  function isScrEditMode() {
    const params = new URLSearchParams(window.location.search);
    if (/^t$/i.test(params.get('e') || '')) return true;
    return Boolean(document.getElementById('submitter') || document.querySelector('input[type="submit"][value="Save"], button[name="submitter"]'));
  }

  function goToEditMode() {
    const url = new URL(window.location.href);
    url.searchParams.set('e', 'T');
    window.location.assign(url.toString());
  }

  function saveNetSuiteForm() {
    const selectors = [
      '#submitter',
      '#btn_multibutton_submitter',
      'input[name="submitter"]',
      'input[type="submit"][value="Save"]',
      'input[type="button"][value="Save"]',
      'button[name="submitter"]',
      'button[value="Save"]',
    ];
    for (const doc of getAccessibleDocuments()) {
      for (const selector of selectors) {
        const btn = doc.querySelector(selector);
        if (btn) {
          btn.click();
          return true;
        }
      }
    }
    console.warn('[Staffing Helper] Save button not found after pending staffing action.');
    return false;
  }

  function storePendingStaffAction(action) {
    sessionStorage.setItem(STAFFING_PENDING_KEY, JSON.stringify({
      ...action,
      scrId: getCurrentScrId(),
      savedAt: Date.now(),
    }));
    showToast('Opening edit mode to apply and save SCOUT changes…', 'info', 5000);
    goToEditMode();
  }

  function normalizeProductIds(productIds) {
    return [...new Set(normalizeProductEntries(productIds)
      .map(entry => String(entry.scrValue || entry.value || '').trim())
      .filter(Boolean))];
  }

  function normalizeProductEntries(products) {
    return (products || [])
      .map(item => {
        if (item && typeof item === 'object') {
          return {
            value: String(item.value || item.id || item.scrValue || '').trim(),
            text: String(item.text || item.label || '').trim(),
            scrValue: String(item.scrValue || '').trim(),
          };
        }
        return { value: String(item || '').trim(), text: '', scrValue: '' };
      })
      .filter(entry => entry.value || entry.scrValue);
  }

  function getSelectedProductEntries(selectId) {
    const el = document.getElementById(selectId);
    if (!el) return [];
    return normalizeProductEntries(Array.from(el.selectedOptions).map(o => ({
      value: o.value,
      text: o.text || o.label || '',
      scrValue: o.dataset.scrValue || '',
    })));
  }

  function getSelectedSkillProductEntries(selectId) {
    const el = document.getElementById(selectId);
    if (!el) return [];
    return normalizeProductEntries(Array.from(el.selectedOptions).map(o => ({
      value: o.dataset.scrValue || '',
      text: o.dataset.scrText || o.text || o.label || '',
      scrValue: o.dataset.scrValue || '',
    })));
  }

  function getProductsForStaffing(productSelectId, skillSelectId) {
    return normalizeProductEntries([
      ...getSelectedProductEntries(productSelectId),
      ...getSelectedSkillProductEntries(skillSelectId),
    ]);
  }

  function enforceSelectLimit(selectEl, max) {
    if (!selectEl) return;
    const selected = Array.from(selectEl.selectedOptions || []);
    while (selected.length > max) {
      const option = selected.shift();
      if (option) option.selected = false;
    }
  }

  function productOptionId(option) {
    if (!option) return '';
    return String(option.dataset?.scrValue || option.value || '').trim();
  }

  function findMappedSkillOptionForProduct(skillSelect, productOption) {
    if (!skillSelect || !productOption) return null;
    const productId = productOptionId(productOption);
    const productText = productOption.text || productOption.label || '';
    const skillId = productId ? PRODUCT_SKILL_MAP[productId] : '';
    const options = Array.from(skillSelect.options || []);

    const byExactText = options.find(option =>
      normalizeProductName(option.text || option.label || '') === normalizeProductName(productText) ||
      normalizeProductName(option.dataset?.scrText || '') === normalizeProductName(productText)
    );
    if (byExactText) return byExactText;

    const byScrValue = options.find(option =>
      String(option.dataset?.scrValue || '') === String(productId) &&
      productNamesCompatible(productText, option.text || option.label || option.dataset?.scrText || '')
    );
    if (byScrValue) return byScrValue;

    if (skillId) {
      const bySkillId = options.find(option =>
        (String(option.value || '') === String(skillId) ||
          String(option.dataset?.skillId || '') === String(skillId)) &&
        productNamesCompatible(productText, option.text || option.label || option.dataset?.scrText || '')
      );
      if (bySkillId) return bySkillId;
    }
    const fallback = findHelperProductOption(skillSelect, productId, productText);
    return fallback && productNamesCompatible(productText, fallback.text || fallback.label || fallback.dataset?.scrText || '') ? fallback : null;
  }

  function findMappedProductOptionForSkill(productSelect, skillOption) {
    if (!productSelect || !skillOption) return null;
    const scrValue = String(skillOption.dataset?.scrValue || '').trim();
    if (!scrValue) return null;
    const skillText = skillOption.dataset?.scrText || skillOption.text || skillOption.label || '';
    const productOption = findHelperProductOption(productSelect, scrValue, skillText);
    return productOption && productNamesCompatible(skillText, productOption.text || productOption.label || '') ? productOption : null;
  }

  function syncProductsToMappedProductSkills(productSelectId, skillSelectId) {
    if (_productSelectionSyncing) return;
    const productSelect = document.getElementById(productSelectId);
    const skillSelect = document.getElementById(skillSelectId);
    if (!productSelect || !skillSelect) return;

    _productSelectionSyncing = true;
    try {
      let changed = false;
      const pairs = Array.from(productSelect.options || [])
        .map(productOption => ({ productOption, skillOption: findMappedSkillOptionForProduct(skillSelect, productOption) }))
        .filter(pair => pair.skillOption);
      const wantedSkills = new Set(pairs
        .filter(pair => pair.productOption.selected)
        .map(pair => pair.skillOption));

      pairs.forEach(({ skillOption }) => {
        if (!wantedSkills.has(skillOption) && skillOption.selected) {
          skillOption.selected = false;
          changed = true;
        }
      });

      let selectedSkills = Array.from(skillSelect.selectedOptions || []);
      wantedSkills.forEach(skillOption => {
        if (!skillOption || skillOption.selected || selectedSkills.length >= 4) return;
        skillOption.selected = true;
        selectedSkills = Array.from(skillSelect.selectedOptions || []);
        changed = true;
      });
      if (changed) dispatchFieldEvents(skillSelect);
    } finally {
      _productSelectionSyncing = false;
    }
  }

  function syncMappedProductSkillsToProducts(productSelectId, skillSelectId) {
    if (_productSelectionSyncing) return;
    const productSelect = document.getElementById(productSelectId);
    const skillSelect = document.getElementById(skillSelectId);
    if (!productSelect || !skillSelect) return;

    _productSelectionSyncing = true;
    try {
      let changed = false;
      const pairs = Array.from(skillSelect.options || [])
        .map(skillOption => ({ skillOption, productOption: findMappedProductOptionForSkill(productSelect, skillOption) }))
        .filter(pair => pair.productOption);
      const wantedProducts = new Set(pairs
        .filter(pair => pair.skillOption.selected)
        .map(pair => pair.productOption));

      pairs.forEach(({ productOption }) => {
        if (!wantedProducts.has(productOption) && productOption.selected) {
          productOption.selected = false;
          changed = true;
        }
      });

      let selectedProducts = Array.from(productSelect.selectedOptions || []);
      wantedProducts.forEach(productOption => {
        if (!productOption || productOption.selected || selectedProducts.length >= 4) return;
        productOption.selected = true;
        selectedProducts = Array.from(productSelect.selectedOptions || []);
        changed = true;
      });
      if (changed) dispatchFieldEvents(productSelect);
    } finally {
      _productSelectionSyncing = false;
    }
  }

  function getSelectedProductIds(selectId) {
    return normalizeProductIds(getSelectedProductEntries(selectId));
  }

  function resolveProductEntriesForScr(products) {
    const entries = normalizeProductEntries(products);
    const scrOptions = getScrProductOptions();
    const resolved = [];
    const seen = new Set();
    entries.forEach(entry => {
      const match = findScrProductOptionForEntry(entry, scrOptions);
      const value = match ? match.value : (entry.scrValue || entry.value);
      if (!value || seen.has(value)) return;
      seen.add(value);
      resolved.push({
        value,
        text: match ? match.text : entry.text,
      });
    });
    return resolved;
  }

  function dispatchFieldEvents(el) {
    if (!el) return;
    try {
      const EventCtor = el.ownerDocument?.defaultView?.Event || Event;
      ['input', 'change', 'blur'].forEach(eventName => {
        el.dispatchEvent(new EventCtor(eventName, { bubbles: true }));
      });
    } catch (e) { /* best effort */ }
  }

  function setInputValueIfPresent(el, value) {
    if (!el || !('value' in el)) return false;
    try {
      el.value = value;
      dispatchFieldEvents(el);
      return true;
    } catch (e) {
      return false;
    }
  }

  function syncNetSuiteMultiSelectDom(fieldId, ids, texts) {
    const wanted = new Set(ids.map(String));
    const wantedText = new Set(texts.map(normalizeProductName));
    const delimiterValue = ids.join(String.fromCharCode(5));
    let wrote = false;

    findFieldControls(fieldId).forEach(el => {
      try {
        if (el.tagName === 'SELECT' && el.multiple) {
          Array.from(el.options).forEach(option => {
            option.selected = wanted.has(String(option.value)) || wantedText.has(normalizeProductName(option.text || option.label || ''));
          });
          dispatchFieldEvents(el);
          wrote = true;
        } else if (el.tagName === 'INPUT' || el.tagName === 'TEXTAREA') {
          const id = el.id || '';
          const name = el.name || '';
          if (id === fieldId || name === fieldId || id.endsWith('_display') || name.endsWith('_display')) {
            wrote = setInputValueIfPresent(el, id.endsWith('_display') || name.endsWith('_display') ? texts.join(', ') : delimiterValue) || wrote;
          }
        } else if (el.id && el.id.endsWith('_val')) {
          el.textContent = texts.join(', ');
          wrote = true;
        }
      } catch (e) { /* keep trying remaining controls */ }
    });

    getAccessibleDocuments().forEach(doc => {
      try {
        const selected = doc.getElementById(`${fieldId}_selected`);
        const available = doc.getElementById(`${fieldId}_avail`) || doc.getElementById(`${fieldId}_unselected`);
        const hidden = doc.getElementById(fieldId) || doc.querySelector(`[name="${fieldId}"]`);
        const display = doc.getElementById(`${fieldId}_display`) || doc.querySelector(`[name="${fieldId}_display"]`);

        if (selected && selected.tagName === 'SELECT') {
          const byValue = new Map();
          [selected, available].filter(Boolean).forEach(select => {
            Array.from(select.options || []).forEach(option => byValue.set(String(option.value), option));
          });
          Array.from(selected.options || []).forEach(option => {
            if (!wanted.has(String(option.value))) {
              option.selected = false;
              if (available) available.appendChild(option);
            }
          });
          ids.forEach((id, index) => {
            const option = byValue.get(String(id)) || new Option(texts[index] || String(id), String(id));
            option.selected = true;
            selected.appendChild(option);
          });
          dispatchFieldEvents(selected);
          if (available) dispatchFieldEvents(available);
          wrote = true;
        }

        wrote = setInputValueIfPresent(hidden, delimiterValue) || wrote;
        if (display) wrote = setInputValueIfPresent(display, texts.join(', ')) || wrote;
      } catch (e) { /* keep scanning docs */ }
    });

    return wrote;
  }

  function selectedPayloadForNsWidget(values) {
    return values.map(value => (/^\d+$/.test(String(value)) ? Number(value) : String(value)));
  }

  function syncNsMultiDropdownProducts(ids, texts) {
    const wanted = new Set(ids.map(String));
    const wantedText = new Set(texts.map(normalizeProductName));
    const widgets = getNsMultiDropdownProductWidgets();
    let wrote = false;

    widgets.forEach(widget => {
      try {
        const options = parseNsMultiDropdownOptions(widget);
        const selected = options
          .filter(option => wanted.has(String(option.value)) || wantedText.has(normalizeProductName(option.text)))
          .map(option => String(option.value));
        if (!selected.length) return;

        const selectedJson = JSON.stringify(selectedPayloadForNsWidget(selected));
        const selectedText = options
          .filter(option => selected.includes(String(option.value)))
          .map(option => option.text)
          .join(', ');
        const csv = selected.join(',');
        const delimiterValue = selected.join(String.fromCharCode(5));
        const name = widget.getAttribute('data-name') || '';

        widget.setAttribute('data-selected', selectedJson);
        widget.dataset.selected = selectedJson;
        widget.setAttribute('value', csv);
        dispatchFieldEvents(widget);

        const doc = widget.ownerDocument || document;
        const controls = [
          doc.getElementById(name),
          doc.getElementById(`${name}_display`),
          doc.querySelector(`[name="${name}"]`),
          doc.querySelector(`[name="${name}_display"]`),
          doc.querySelector(`input[data-name="${name}"]`),
        ].filter(Boolean);
        controls.forEach(control => {
          const id = control.id || '';
          const controlName = control.name || '';
          const isDisplay = id.endsWith('_display') || controlName.endsWith('_display');
          const isHidden = String(control.type || '').toLowerCase() === 'hidden';
          setInputValueIfPresent(control, isDisplay ? selectedText : (isHidden ? csv : delimiterValue));
        });

        try {
          const $ = unsafeWindow.jQuery || unsafeWindow.$;
          if ($) {
            $(widget)
              .attr('data-selected', selectedJson)
              .data('selected', selectedPayloadForNsWidget(selected))
              .trigger('input')
              .trigger('change')
              .trigger('blur');
          }
        } catch (e) { /* jQuery is optional */ }

        console.log('[SCOUT] ns-multi-dropdown products set:', name, selectedJson, selectedText);
        wrote = true;
      } catch (e) {
        console.warn('[SCOUT] ns-multi-dropdown product sync failed:', e);
      }
    });

    return wrote;
  }

  function getProductsFromField(fieldId) {
    try {
      const values = nlapiGetFieldValues(fieldId);
      if (Array.isArray(values)) return values.map(String).filter(Boolean);
      if (values == null || values === '') return [];
      return String(values).split(',').map(s => s.trim()).filter(Boolean);
    } catch (e) {
      return null;
    }
  }

  function setProductsWithSimpleApi(ids) {
    const csv = ids.map(String).filter(Boolean).join(',');
    if (!csv) return false;
    const strArray = csv.split(',').map(s => s.trim()).filter(Boolean);
    for (const fieldId of SCR_FIELD_PRODUCT_CANDIDATES) {
      try {
        nlapiSetFieldValues(fieldId, strArray);
        console.log('[SCOUT] Simple product multiselect set:', fieldId, strArray, 'readback:', getProductsFromField(fieldId));
        return true;
      } catch (e) {
        console.warn('[SCOUT] Simple product multiselect set failed:', fieldId, e);
      }
    }
    return false;
  }

  function submitProductIdsOnRecord(ids) {
    const scrId = getCurrentScrId();
    if (!scrId || !ids.length) return false;
    const values = ids.map(String);
    for (const fieldId of SCR_RECORD_PRODUCT_FIELD_CANDIDATES) {
      const attempts = [
        () => nlapiSubmitField(SCR_RECORD_TYPE, scrId, fieldId, values, true),
        () => nlapiSubmitField(SCR_RECORD_TYPE, scrId, [fieldId], [values], true),
        () => nlapiSubmitField(SCR_RECORD_TYPE, scrId, fieldId, values.join(String.fromCharCode(5)), true),
      ];
      for (const attempt of attempts) {
        try {
          attempt();
          console.log('[SCOUT] Direct product submit succeeded:', fieldId, values);
          return true;
        } catch (e) { /* try the next NetSuite encoding */ }
      }
    }
    return false;
  }

  function setProductIdsOnForm(products, opts) {
    opts = opts || {};
    const resolvedProducts = resolveProductEntriesForScr(products);
    const ids = resolvedProducts.map(product => product.value);
    const displayTexts = resolvedProducts.map(product => product.text || String(product.value));
    const texts = resolvedProducts.map(product => product.text).filter(Boolean);
    if (!ids.length) return false;
    let wrote = false;

    wrote = syncNsMultiDropdownProducts(ids, displayTexts) || wrote;
    wrote = setProductsWithSimpleApi(ids) || wrote;

    try {
      nlapiSetFieldValues(SCR_FIELD_PRODUCTS, ids, true, true);
      wrote = true;
    } catch (e) {
      try {
        nlapiSetFieldValues(SCR_FIELD_PRODUCTS, ids, false, true);
        wrote = true;
      } catch (inner) { /* try current-record and DOM fallbacks below */ }
    }

    try {
      const rec = unsafeWindow.nlapiGetCurrentRecord && unsafeWindow.nlapiGetCurrentRecord();
      if (rec && typeof rec.setFieldValues === 'function') {
        rec.setFieldValues(SCR_FIELD_PRODUCTS, ids);
        wrote = true;
      } else if (rec && typeof rec.setValue === 'function') {
        rec.setValue({
          fieldId: SCR_FIELD_PRODUCTS,
          value: ids,
          ignoreFieldChange: false,
          forceSyncSourcing: true,
        });
        wrote = true;
      }
    } catch (e) { /* current-record fallback may not be available */ }

    if (texts.length) {
      try {
        nlapiSetFieldTexts(SCR_FIELD_PRODUCTS, texts, true, true);
        wrote = true;
      } catch (e) {
        try {
          nlapiSetFieldTexts(SCR_FIELD_PRODUCTS, texts, false, true);
          wrote = true;
        } catch (inner) { /* keep DOM fallback below */ }
      }
    }

    SCR_FIELD_PRODUCT_CANDIDATES.forEach(fieldId => {
      wrote = syncNetSuiteMultiSelectDom(fieldId, ids, displayTexts) || wrote;
    });

    if (opts.submitRecord) {
      const submitted = submitProductIdsOnRecord(ids);
      wrote = submitted || wrote;
      if (submitted) console.log('[SCOUT] Submitted SCR products directly:', ids, displayTexts);
      else console.warn('[SCOUT] Direct SCR product submit failed; relying on form-field sync only:', ids, displayTexts);
    }

    if (!wrote) console.warn('[Staffing Helper] Unable to write SCR product field:', SCR_FIELD_PRODUCTS, ids);
    return wrote;
  }

  function syncProductIdsToForm(products, retry, opts) {
    const entries = normalizeProductEntries(products);
    if (!entries.length) return;
    setProductIdsOnForm(entries, opts);
    if (retry) {
      [150, 500].forEach(delay => {
        setTimeout(() => setProductIdsOnForm(entries, opts), delay);
      });
    }
  }

  function buildDefaultStaffingRequestNote(scName) {
    return `${scName} has been staffed, please schedule upcoming strategy meeting with the SC.\n`;
  }

  function applyDirectStaffing(scId, scName, empName, hasLeadOnOpp, notes, productIds, assignAsLead, requestDetailsNote) {
    assignAsLead = assignAsLead !== false;
    const requestDetailsBaseScript = buildDefaultStaffingRequestNote(scName);
    const requestDetailsScript = wrapStaffingNote(requestDetailsBaseScript, empName, requestDetailsNote);
    setStatus(2);
    setAssignee(scId);
    setLeadAssigned(assignAsLead);
    setScoutHashtag();
    prependRequestDetails(requestDetailsScript);
    setDirectManagerNotes(empName);
    setStaffingPopupNotes(notes);
    appendEngagementNotesTemplate(empName);
    syncProductIdsToForm(productIds, true, { submitRecord: true });
  }

  function applyAmoStaffing(scId, scName, empName, hasLeadOnOpp, notes, deliverableOverride, productIds, assignAsLead, requestDetailsNote) {
    assignAsLead = assignAsLead !== false;
    const hasDeliverableOverride = arguments.length >= 6;
    const deliverable = hasDeliverableOverride
      ? normalizeAmoDeliverableName(deliverableOverride)
      : getSelectedAmoDeliverable();
    const tmplFn = deliverable && isValidAmoDeliverableName(deliverable) ? AMO_DELIVERABLE_TEMPLATES[deliverable] : null;
    const requestDetailsBaseScript = tmplFn ? tmplFn(scName, empName) : buildDefaultStaffingRequestNote(scName);
    setStatus(2);
    setAssignee(scId);
    setLeadAssigned(assignAsLead);
    setScoutHashtag();
    prependRequestDetails(wrapStaffingNote(requestDetailsBaseScript, empName, requestDetailsNote));
    setStaffingPopupNotes(notes);
    appendEngagementNotesTemplate(empName);
    if (deliverable && isValidAmoDeliverableName(deliverable)) syncDeliverableToForm(deliverable);
    syncProductIdsToForm(productIds, true, { submitRecord: true });
    return deliverable;
  }

  function applyOnHold(meId, notes) {
    setStatus(3);
    setAssignee(meId);
    setScoutHashtag();
    setStaffingPopupNotes(notes);
  }

  function applyCancelRequest(empName, notes) {
    const note = `SC Request cancelled by SC Manager (${empName}). \nPlease create a new request if needed.\n---\n\n`;
    prependRequestDetails(note);
    setStatus(4);
    setScoutHashtag();
    setStaffingPopupNotes(notes);
    try { nlapiSetFieldValue('custrecord_screq_engmnt_status', 5, true); } catch (_) {}
    nlapiSetFieldValue('custrecord_screq_assigned_lead', 'F', true);
  }

  function resumePendingStaffAction() {
    let pending = null;
    try {
      pending = JSON.parse(sessionStorage.getItem(STAFFING_PENDING_KEY) || 'null');
    } catch (e) {
      sessionStorage.removeItem(STAFFING_PENDING_KEY);
    }
    if (!pending) return;
    if (pending.scrId && pending.scrId !== getCurrentScrId()) return;
    if (Date.now() - Number(pending.savedAt || 0) > 10 * 60 * 1000) {
      sessionStorage.removeItem(STAFFING_PENDING_KEY);
      return;
    }
    if (pending.type && !['direct', 'amo', 'onhold', 'cancel'].includes(pending.type)) {
      sessionStorage.removeItem(STAFFING_PENDING_KEY);
      showToast('This pending SCOUT action is no longer available.', 'info', 6000);
      return;
    }
    if (!isScrEditMode()) return;

    try {
      if (pending.type === 'amo') {
        applyAmoStaffing(pending.scId, pending.scName, pending.empName, pending.hasLeadOnOpp, pending.notes, pending.deliverable, pending.productIds, pending.assignAsLead !== false, pending.requestDetailsNote);
      } else if (pending.type === 'onhold') {
        applyOnHold(pending.meId, pending.notes);
      } else if (pending.type === 'cancel') {
        applyCancelRequest(pending.empName, pending.notes);
      } else {
        applyDirectStaffing(pending.scId, pending.scName, pending.empName, pending.hasLeadOnOpp, pending.notes, pending.productIds, pending.assignAsLead !== false, pending.requestDetailsNote);
      }
      sessionStorage.removeItem(STAFFING_PENDING_KEY);
      const actionLabel = pending.type === 'onhold'
        ? 'on hold changes'
        : pending.type === 'cancel'
          ? 'cancellation changes'
          : `staffing changes for ${pending.scName}`;
      showToast(`✔ Applied ${actionLabel}; saving record…`, 'success', 5000);
      setTimeout(function () {
        triggerNetSuiteFieldEvents(SCR_FIELD_ASSIGNEE);
        saveNetSuiteForm();
      }, PENDING_STAFFING_SAVE_DELAY_MS);
    } catch (e) {
      console.error('[Staffing Helper] Pending staffing action failed:', e);
      showToast('Could not apply pending SCOUT action. Check console for details.', 'error', 8000);
    }
  }

  /**
   * Direct staffing — items 1 (lead conditional), 3 (markers), 4 (new message),
   * 7 (no confirm), 8 (notes popup).
   */
  function staffSC(scId, scName, empName, hasLeadOnOpp) {
    showNotesDialog('Staff ' + scName, function (dialog) {
      const notes = dialog.staffingNotes;
      const assignAsLead = dialog.assignAsLead;
      const requestDetailsNote = dialog.requestDetailsNote;
      const assignmentLabel = assignAsLead ? 'Lead SC' : 'Secondary SC';
      if (!isScrEditMode()) {
        storePendingStaffAction({ type: 'direct', scId, scName, empName, hasLeadOnOpp, notes, requestDetailsNote, assignAsLead, productIds: getProductsForStaffing('sc-products', 'sc-product-skills') });
        return;
      }
      applyDirectStaffing(scId, scName, empName, hasLeadOnOpp, notes, getProductsForStaffing('sc-products', 'sc-product-skills'), assignAsLead, requestDetailsNote);
      showToast(`✔ Staffed: ${scName} as ${assignmentLabel} — save the record to confirm.`, 'success', 6000);
    }, { showLeadToggle: true, showRequestDetailsBox: true });
  }

  function getSelectedAmoDeliverableFromPicker() {
    const picker = document.getElementById('sc-amo-deliverable');
    const selected = normalizeAmoDeliverableName(picker && picker.value);
    return isValidAmoDeliverableName(selected) ? selected : '';
  }

  function getCurrentAmoDeliverableFromForm() {
    const rawValue = String(readFormFieldValue(SCR_FIELD_DELIVERABLE) || '').trim();
    if (!rawValue) return '';

    const formValue = readFormField(SCR_FIELD_DELIVERABLE);
    const normalized = normalizeAmoDeliverableName(formValue);
    if (isValidAmoDeliverableName(normalized)) return normalized;

    const rawNormalized = normalizeAmoDeliverableName(rawValue);
    return isValidAmoDeliverableName(rawNormalized) ? rawNormalized : '';
  }

  function getSelectedAmoDeliverable(options) {
    const opts = options || {};
    const pickerValue = getSelectedAmoDeliverableFromPicker();
    if (pickerValue) return pickerValue;
    if (opts.requirePickerSelection) return '';
    return getCurrentAmoDeliverableFromForm();
  }

  function isCurrentScrAmo() {
    const reqType = `${readFormField(SCR_FIELD_TYPE)} ${readFormField('custrecord_screq_request_type')}`;
    return /amo/i.test(reqType);
  }

  /**
   * AMO variant — items 1 (lead conditional), 3 (markers), 4 (remove strategy-call line),
   * 5 (deliverable field sync), 7 (no confirm), 8 (notes popup).
   */
  function staffSCWithDeliverable(scId, scName, empName, hasLeadOnOpp) {
    showNotesDialog('Staff ' + scName + ' (AMO)', function (dialog) {
      const notes = dialog.staffingNotes;
      const assignAsLead = dialog.assignAsLead;
      const requestDetailsNote = dialog.requestDetailsNote;
      const deliverable = getSelectedAmoDeliverable({ requirePickerSelection: true });
      const assignmentLabel = assignAsLead ? 'Lead SC' : 'Secondary SC';
      const continueStaffing = function () {
        if (!isScrEditMode()) {
          storePendingStaffAction({ type: 'amo', scId, scName, empName, hasLeadOnOpp, notes, requestDetailsNote, deliverable, assignAsLead, productIds: getProductsForStaffing('sc-amo-products', 'sc-amo-product-skills') });
          return;
        }
        applyAmoStaffing(scId, scName, empName, hasLeadOnOpp, notes, deliverable, getProductsForStaffing('sc-amo-products', 'sc-amo-product-skills'), assignAsLead, requestDetailsNote);
        const label = deliverable ? ` (${deliverable})` : '';
        showToast(`✔ Staffed: ${scName}${label} as ${assignmentLabel} — save the record to confirm.`, 'success', 6000);
      };
      if (!deliverable) {
        showAmoBlankDeliverableWarning(continueStaffing);
        return;
      }
      continueStaffing();
    }, { showLeadToggle: true, showRequestDetailsBox: true });
  }

  function staffFromActiveTab(scId, scName, empName, hasLeadOnOpp) {
    const amoPane = document.getElementById('sc-amo-pane');
    if (isCurrentScrAmo() || (amoPane && amoPane.classList.contains('active'))) {
      staffSCWithDeliverable(scId, scName, empName, hasLeadOnOpp);
    } else {
      staffSC(scId, scName, empName, hasLeadOnOpp);
    }
  }

  function normalizeRouteName(name) {
    return String(name || '')
      .toLowerCase()
      .replace(/&/g, ' and ')
      .replace(/[^a-z0-9]+/g, ' ')
      .trim()
      .replace(/\s+/g, ' ');
  }

  function routeNameVariants(name) {
    const raw = String(name || '').trim();
    const variants = [raw];
    if (raw.includes(',')) {
      const parts = raw.split(',');
      const last = (parts[0] || '').trim();
      const first = parts.slice(1).join(',').trim();
      if (first && last) variants.push(`${first} ${last}`);
    }
    return [...new Set(variants.map(normalizeRouteName).filter(Boolean))];
  }

  function setOnHold(meId) {
    if (!meId) {
      showToast('SCOUT could not resolve your roster record, so On Hold self-assignment is unavailable for this role.', 'error', 8000);
      return;
    }
    if (!confirm('Place this request On Hold and assign it to yourself?')) return;
    showNotesDialog('Place Request On Hold', function (dialog) {
      const notes = dialog.staffingNotes;
      if (!isScrEditMode()) {
        storePendingStaffAction({ type: 'onhold', meId, notes });
        return;
      }
      applyOnHold(meId, notes);
      showToast('✔ Status set to On Hold — save the record to confirm.', 'info');
    });
  }

  function cancelRequest(empName) {
    if (!confirm('Cancel this SC Request?\n\nThis will:\n• Set both statuses to Cancelled\n• Set Lead SC to false\n• Prepend a cancellation note to Request Details')) return;
    showNotesDialog('Cancel SC Request', function (dialog) {
      const notes = dialog.staffingNotes;
      if (!isScrEditMode()) {
        storePendingStaffAction({ type: 'cancel', empName, notes });
        return;
      }
      applyCancelRequest(empName, notes);
      showToast('✔ Request cancelled — save the record to confirm.', 'error', 6000);
    });
  }

  /* ────────────────────────────────────────────────────────────────
     CALENDAR DASHBOARD
     GM_openInTab opens the shared GitHub Pages dashboard from NetSuite.
     Falls back to GM_setClipboard if GM_openInTab is unavailable.
     URL parameters are built directly — no external helper required.
  ──────────────────────────────────────────────────────────────── */

  /**
   * Build the roster entry object that matches the dashboard's expected format.
   * Accepts either an employee record (from search results / My Team) or the
   * lightweight payload stored in _selectedMap.
   */
  function toRosterEntry(p) {
    return {
      id:         '',
      name:       p.name      || p.employee || '',
      email:      p.email     || '',
      manager:    p.manager   || '',
      team:       p.team      || p.vertical || '',
      legacyOrg:  '',
      location:   p.location  || '',
      timeZone:   p.timeZone  || inferTimeZone(p.location),
      source:     '',
    };
  }

  /**
   * Build the dashboard URL for a single consultant.
   * Format: ?consultant=EMAIL&consultantName=NAME&date=YYYY-MM-DD&zone=TZ&duration=60&source=…
   */
  function buildDashboardUrl(e) {
    const entry  = toRosterEntry(e);
    const params = new URLSearchParams({
      consultant:     entry.email,
      consultantName: entry.name,
      date:           getDateForCal(),
      zone:           Intl.DateTimeFormat().resolvedOptions().timeZone,
      duration:       '60',
      source:         'scr-staffing-helper',
    });
    return `${getDashboardUrl()}?${params.toString()}`;
  }

  /**
   * Build the dashboard URL for multiple consultants — opens ONE combined tab.
   * Format: ?consultants=email1,email2,…&date=YYYY-MM-DD&zone=TZ&duration=60&source=…
   */
  function buildMultiDashboardUrl(entries) {
    const params = new URLSearchParams({
      consultants: entries.map(e => e.email).join(','),
      date:        getDateForCal(),
      zone:        Intl.DateTimeFormat().resolvedOptions().timeZone,
      duration:    '60',
      source:      'scr-staffing-helper',
    });
    return `${getDashboardUrl()}?${params.toString()}`;
  }

  /** Open a URL using GM_openInTab or fall back to clipboard. */
  function gmOpenUrl(url) {
    try {
      const opener = (typeof GM_openInTab !== 'undefined') ? GM_openInTab
                   : (typeof GM !== 'undefined' && GM.openInTab) ? GM.openInTab
                   : null;
      if (opener) {
        opener(url, { active: true, insert: true });
        return;
      }
    } catch (_) { /* fall through */ }
    // Last resort: copy to clipboard
    try { GM_setClipboard(url); } catch (_) { navigator.clipboard.writeText(url).catch(() => {}); }
    showToast('📋 Dashboard link copied — paste in a new tab to open.', 'info', 8000);
  }

  function copyToClipboardQuietly(text) {
    try {
      GM_setClipboard(text);
      return true;
    } catch (_) {
      try {
        navigator.clipboard.writeText(text).catch(() => {});
        return true;
      } catch (e) {
        return false;
      }
    }
  }

  function openExternalProtocol(url) {
    const link = document.createElement('a');
    link.href = url;
    link.rel = 'noopener noreferrer';
    link.style.display = 'none';
    document.body.appendChild(link);
    link.click();
    setTimeout(() => link.remove(), 1000);
  }

  function requestText(url) {
    return new Promise((resolve, reject) => {
      const requestUrl = `${url}${url.includes('?') ? '&' : '?'}_scout=${Date.now()}`;
      if (typeof GM_xmlhttpRequest !== 'undefined') {
        GM_xmlhttpRequest({
          method: 'GET',
          url: requestUrl,
          headers: { 'Cache-Control': 'no-cache' },
          onload: res => {
            if (res.status >= 200 && res.status < 300) resolve(res.responseText || '');
            else reject(new Error(`Request returned ${res.status}`));
          },
          onerror: () => reject(new Error('Request failed')),
          ontimeout: () => reject(new Error('Request timed out')),
          timeout: 10000,
        });
        return;
      }
      fetch(requestUrl, { cache: 'no-store' })
        .then(res => {
          if (!res.ok) throw new Error(`Request returned ${res.status}`);
          return res.text();
        })
        .then(resolve)
        .catch(reject);
    });
  }

  function extractUserscriptMetaValue(text, key) {
    const re = new RegExp(`^\\s*//\\s*@${key}\\s+(.+?)\\s*$`, 'mi');
    const match = String(text || '').match(re);
    return match ? match[1].trim() : '';
  }

  function tokenizeScoutVersion(version) {
    const normalized = String(version || '')
      .trim()
      .replace(/^[bv](?=\d)/i, '');
    const tokens = (normalized.match(/\d+|[a-z]+/gi) || []).map(token => {
      const isNumber = /^\d+$/.test(token);
      return isNumber ? { type: 'number', value: Number(token) } : { type: 'text', value: token.toLowerCase() };
    });
    while (tokens.length && tokens[tokens.length - 1].type === 'number' && tokens[tokens.length - 1].value === 0) {
      tokens.pop();
    }
    return tokens;
  }

  function compareScoutVersions(a, b) {
    const aa = tokenizeScoutVersion(a);
    const bb = tokenizeScoutVersion(b);
    const len = Math.max(aa.length, bb.length);
    for (let i = 0; i < len; i++) {
      const av = aa[i] || { type: 'number', value: 0 };
      const bv = bb[i] || { type: 'number', value: 0 };
      if (av.type === bv.type) {
        if (av.value > bv.value) return 1;
        if (av.value < bv.value) return -1;
        continue;
      }
      return av.type === 'number' ? 1 : -1;
    }
    return 0;
  }

  function readCachedScoutUpdate() {
    try {
      const cached = JSON.parse(localStorage.getItem(SCOUT_UPDATE_CACHE_KEY) || 'null');
      if (!cached || !cached.version) return null;
      return cached;
    } catch (e) {
      return null;
    }
  }

  function writeCachedScoutUpdate(updateInfo) {
    try {
      localStorage.setItem(SCOUT_UPDATE_CACHE_KEY, JSON.stringify(updateInfo));
    } catch (e) { /* storage can fail in restricted browser contexts */ }
  }

  function getScoutUpdateChannel() {
    if (getEarlyAdopterUpdatesEnabled()) {
      const configuredTestingUrl = String(getLocalConfig().testingUpdateUrl || '').trim();
      const testingUrl = configuredTestingUrl || SCOUT_TESTING_UPDATE_CHECK_URL;
      return {
        key: 'testing',
        label: 'Testing',
        checkUrl: testingUrl,
        installUrl: configuredTestingUrl || SCOUT_TESTING_INSTALL_URL,
      };
    }
    return {
      key: 'stable',
      label: 'Stable',
      checkUrl: SCOUT_UPDATE_CHECK_URL,
      installUrl: SCOUT_INSTALL_URL,
    };
  }

  function renderScoutUpdateBanner(updateInfo) {
    const banner = document.getElementById('sc-update-banner');
    const toggle = document.getElementById('sc-skills-toggle');
    if (!banner) return;
    const remoteVersion = updateInfo && updateInfo.version;
    const hasUpdate = remoteVersion && compareScoutVersions(remoteVersion, SCRIPT_VERSION) > 0;
    banner.hidden = !hasUpdate;
    banner.classList.toggle('show', Boolean(hasUpdate));
    if (toggle) {
      toggle.classList.toggle('sc-update-available', Boolean(hasUpdate));
      toggle.title = hasUpdate
        ? `SCOUT update available: ${SCRIPT_VERSION} -> ${remoteVersion}`
        : 'SCOUT - SC Operations Utility Tool';
    }
    if (!hasUpdate) return;

    const channelLabel = updateInfo.channelLabel || 'Stable';
    const installUrl = updateInfo.downloadUrl || updateInfo.updateUrl || SCOUT_INSTALL_URL;
    banner.dataset.installUrl = installUrl;
    const text = banner.querySelector('.sc-update-banner-text');
    if (text) {
      const label = channelLabel === 'Testing' ? 'SCOUT testing update available' : 'SCOUT update available';
      text.innerHTML = `<strong>${escHtml(label)}:</strong> ${escHtml(SCRIPT_VERSION)} -> ${escHtml(remoteVersion)}`;
    }
  }

  async function checkScoutUpdate(force) {
    const channel = getScoutUpdateChannel();
    let cached = readCachedScoutUpdate();
    if (cached && (cached.channelKey !== channel.key || cached.checkUrl !== channel.checkUrl)) {
      cached = null;
    }
    const now = Date.now();
    if (!force && cached && now - Number(cached.checkedAt || 0) < SCOUT_UPDATE_CHECK_INTERVAL_MS) {
      renderScoutUpdateBanner(cached);
      return cached;
    }

    try {
      const text = await requestText(channel.checkUrl);
      const version = extractUserscriptMetaValue(text, 'version');
      if (!version) throw new Error('Remote userscript version not found');
      const updateInfo = {
        version,
        updateUrl: extractUserscriptMetaValue(text, 'updateURL') || channel.checkUrl,
        downloadUrl: extractUserscriptMetaValue(text, 'downloadURL') || channel.installUrl,
        checkedAt: now,
        channelKey: channel.key,
        channelLabel: channel.label,
        checkUrl: channel.checkUrl,
      };
      writeCachedScoutUpdate(updateInfo);
      renderScoutUpdateBanner(updateInfo);
      return updateInfo;
    } catch (e) {
      console.warn('[SCOUT] Update check failed:', e.message || e);
      if (cached) renderScoutUpdateBanner(cached);
      return null;
    }
  }

  function wireScoutUpdateBanner() {
    const banner = document.getElementById('sc-update-banner');
    const installBtn = document.getElementById('sc-update-install-btn');
    const copyBtn = document.getElementById('sc-update-copy-btn');
    if (installBtn) {
      installBtn.addEventListener('click', () => {
        const url = (banner && banner.dataset.installUrl) || SCOUT_INSTALL_URL;
        showToast('Opening SCOUT update...', 'info', 5000);
        gmOpenUrl(url);
      });
    }
    if (copyBtn) {
      copyBtn.addEventListener('click', () => {
        const url = (banner && banner.dataset.installUrl) || SCOUT_INSTALL_URL;
        const copied = copyToClipboardQuietly(url);
        showToast(copied ? 'SCOUT update link copied.' : 'Could not copy update link.', copied ? 'success' : 'error', 5000);
      });
    }
  }

  function triggerSlackWorkflowWebhook(webhookUrl) {
    const payload = {
      source: 'SCOUT',
      script_version: SCRIPT_VERSION,
      page_url: window.location.href,
      page_title: document.title || '',
      requested_at: new Date().toISOString(),
    };
    return new Promise((resolve, reject) => {
      const body = JSON.stringify(payload);
      if (typeof GM_xmlhttpRequest !== 'undefined') {
        GM_xmlhttpRequest({
          method: 'POST',
          url: webhookUrl,
          headers: { 'Content-Type': 'application/json' },
          data: body,
          onload: res => {
            if (res.status >= 200 && res.status < 300) resolve(res);
            else reject(new Error(`Slack workflow returned ${res.status}`));
          },
          onerror: () => reject(new Error('Slack workflow request failed')),
          ontimeout: () => reject(new Error('Slack workflow request timed out')),
          timeout: 10000,
        });
        return;
      }
      fetch(webhookUrl, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body,
      }).then(resolve).catch(reject);
    });
  }

  async function openScoutFeedbackWorkflow() {
    const webhookUrl = getFeedbackWebhookUrl();
    if (webhookUrl) {
      if (!/^https:\/\/hooks\.slack\.com\/triggers\//i.test(webhookUrl)) {
        showToast('Feedback webhook should start with https://hooks.slack.com/triggers/. Check SCOUT Settings.', 'error', 9000);
        return;
      }
      showToast('Starting Slack feedback workflow...', 'info', 4000);
      try {
        await triggerSlackWorkflowWebhook(webhookUrl);
        showToast('Slack feedback workflow started.', 'success', 6000);
        return;
      } catch (e) {
        console.warn('[SCOUT] Slack feedback workflow failed', e);
        showToast('Could not start Slack workflow. Check the saved webhook URL.', 'error', 9000);
        return;
      }
    }

    copyToClipboardQuietly(SCOUT_FEEDBACK_URL);
    window.alert([
      'SCOUT copied the Slack workflow link to your clipboard.',
      '',
      'Click OK to open Slack.',
      'If the workflow does not appear automatically, paste the copied link into Slack or the Slack web app and click it there to start the workflow.',
    ].join('\n'));
    try {
      openExternalProtocol(SCOUT_SLACK_OPEN_URL);
    } catch (_) {
      gmOpenUrl(SCOUT_FEEDBACK_URL);
    }
    showToast('Slack opened. Paste the copied workflow link into Slack or the Slack web app if needed.', 'info', 9000);
  }

  function activeStaffingModeLabel() {
    const amoPane = document.getElementById('sc-amo-pane');
    return isCurrentScrAmo() || (amoPane && amoPane.classList.contains('active')) ? 'AMO' : 'Direct';
  }

  function selectedOptionTexts(selectId) {
    const el = document.getElementById(selectId);
    if (!el) return [];
    return Array.from(el.selectedOptions || [])
      .map(o => String(o.text || o.label || o.value || '').trim())
      .filter(Boolean);
  }

  function uniqueTextList(items) {
    const seen = new Set();
    return (items || []).map(item => String(item || '').trim()).filter(item => {
      const key = item.toLowerCase();
      if (!key || seen.has(key)) return false;
      seen.add(key);
      return true;
    });
  }

  function getGptIndustryText(mode) {
    const selectId = mode === 'AMO' ? 'sc-amo-industry' : 'sc-industry';
    const selected = selectedOptionTexts(selectId).filter(text => !/^—?\s*any industry/i.test(text));
    if (selected.length) return selected[0];

    const options = INDUSTRY_OPTIONS_CACHE || [];
    const defaultId = options.length ? getScrIndustryDefault(options) : '';
    const defaultOption = defaultId ? options.find(o => String(o.id) === String(defaultId)) : null;
    if (defaultOption && defaultOption.name) return defaultOption.name;

    const family = getFirstReadableField(SCR_FIELD_INDUSTRY_FAMILY_CANDIDATES);
    const subgroup = getFirstReadableField(SCR_FIELD_INDUSTRY_SUBGROUP_CANDIDATES);
    return [family.text || family.value, subgroup.text || subgroup.value].filter(Boolean).join(' - ');
  }

  function getGptSkillText(mode) {
    const isAmo = mode === 'AMO';
    const skills = [
      ...selectedOptionTexts(isAmo ? 'sc-amo-product-skills' : 'sc-product-skills'),
      ...selectedOptionTexts(isAmo ? 'sc-amo-products' : 'sc-products'),
    ];
    if (document.getElementById(isAmo ? 'sc-amo-cert-cpa' : 'sc-cert-cpa')?.checked) skills.push('CPA');
    return uniqueTextList(skills).join('\n');
  }

  function getGptDateText() {
    const dates = [];
    try {
      const scNeeded = readFieldDateYMD(SCR_FIELD_DATE_SC_NEEDED)
        || findDateValueByLabel(/date\s+sc\s+needed/i)
        || readFieldDateYMD(SCR_FIELD_DATE_NEEDED)
        || findDateValueByLabel(/^date\s+needed$/i);
      if (scNeeded) dates.push(`Date SC Needed: ${scNeeded}`);
    } catch (e) { /* best effort */ }
    try {
      const meetingDate = getDateForCal();
      if (meetingDate && !dates.some(line => line.includes(meetingDate))) {
        dates.push(`Anticipated customer meeting date: ${meetingDate}`);
      }
    } catch (e) { /* best effort */ }
    return dates.join('\n');
  }

  function readSearchValue(row, fieldId, join) {
    if (!row) return '';
    try {
      const text = join ? row.getText(fieldId, join) : row.getText(fieldId);
      if (text) return text;
    } catch (e) { /* try value */ }
    try {
      const value = join ? row.getValue(fieldId, join) : row.getValue(fieldId);
      return value || '';
    } catch (e) {
      return '';
    }
  }

  function normalizeCustomerLocationParts(city, state, countryRaw) {
    const countryText = String(countryRaw || '').trim();
    const isCanada = /^ca$/i.test(countryText) || /^canada$/i.test(countryText);
    const isUnitedStates = /^us$/i.test(countryText) || /^usa$/i.test(countryText) || /^united states$/i.test(countryText);
    return {
      city: String(city || '').trim(),
      state: String(state || '').trim(),
      country: isCanada ? 'Canada' : (isUnitedStates ? '' : countryText),
    };
  }

  function readLocationFromSearchRow(row, join) {
    return normalizeCustomerLocationParts(
      readSearchValue(row, 'city', join),
      readSearchValue(row, 'state', join),
      readSearchValue(row, 'country', join));
  }

  function hasLocationParts(location) {
    return Boolean(location && (location.city || location.state || location.country));
  }

  function lookupCompanyLocation(companyId, defaultBillingOnly) {
    const attempts = defaultBillingOnly
      ? [
        { join: 'address', defaultField: 'isdefaultbilling' },
        { join: 'address', defaultField: 'defaultbilling' },
        { join: 'addressbook', defaultField: 'isdefaultbilling' },
        { join: 'addressbook', defaultField: 'defaultbilling' },
        { join: null, defaultField: 'isdefaultbilling' },
        { join: null, defaultField: 'defaultbilling' },
      ]
      : [{ join: null, defaultField: '' }];

    for (const attempt of attempts) {
      try {
        const filters = [new nlobjSearchFilter('internalid', null, 'is', companyId)];
        if (attempt.defaultField) {
          filters.push(new nlobjSearchFilter(attempt.defaultField, attempt.join, 'is', 'T'));
        }
        const rows = nlapiSearchRecord('entity', null, filters, [
          new nlobjSearchColumn('city', attempt.join),
          new nlobjSearchColumn('state', attempt.join),
          new nlobjSearchColumn('country', attempt.join),
        ]) || [];
        if (!rows.length) continue;
        const location = readLocationFromSearchRow(rows[0], attempt.join);
        if (hasLocationParts(location)) return location;
      } catch (e) { /* try the next default-billing field/join shape */ }
    }
    return { city: '', state: '', country: '' };
  }

  function getCompanyDefaultBillingLocation(companyId) {
    return lookupCompanyLocation(companyId, true) || { city: '', state: '', country: '' };
  }

  function getCompanyLocationFallback(companyId) {
    return lookupCompanyLocation(companyId, false) || { city: '', state: '', country: '' };
  }

  function getGptCustomerLocationText() {
    try {
      const companyId = (nlapiGetFieldValue(SCR_FIELD_COMPANY) || '').trim();
      if (!companyId) return '';
      const location = getCompanyDefaultBillingLocation(companyId);
      const finalLocation = hasLocationParts(location) ? location : getCompanyLocationFallback(companyId);
      return [finalLocation.city, finalLocation.state, finalLocation.country].filter(Boolean).join(', ');
    } catch (e) {
      return '';
    }
  }

  function getGptRequestDetailsText() {
    try {
      return (readFormTextField('custrecord_screq_details') || getRequestDetails() || '').trim();
    } catch (e) {
      return '';
    }
  }

  function getGptScrUrl() {
    try {
      const url = new URL(window.location.href);
      const scrId = url.searchParams.get('id') || getCurrentScrId();
      const rectype = url.searchParams.get('rectype') || '2840';
      if (scrId) {
        const clean = new URL(`${url.origin}${url.pathname}`);
        clean.searchParams.set('rectype', rectype);
        clean.searchParams.set('id', scrId);
        return clean.toString();
      }
      url.searchParams.delete('e');
      return url.toString();
    } catch (e) {
      return String(window.location.href || '');
    }
  }

