  function buildGptAssistPromptFromValues(values) {
    const lines = [];
    appendGptAssistOperatingRules(lines);
    lines.push('');
    lines.push('SC REQUEST INPUTS');
    lines.push('Please recommend Solution Consultants for this NetSuite SC Request using the source-of-truth rules above.');
    lines.push('');
    lines.push('Staffing mode: ' + (values.mode || 'Direct'));
    if (values.scrUrl) {
      lines.push('NetSuite SCR URL: ' + values.scrUrl);
      lines.push('Use this NetSuite SCR URL in the Slack manager outreach message so the manager can open the request directly.');
    }
    if (values.includeIndustry && values.industry) {
      lines.push('Industry / Sub-Industry: ' + values.industry);
    } else {
      lines.push('Industry / Sub-Industry: intentionally not used for this request.');
    }
    if (values.skills) {
      lines.push('');
      lines.push('Additional skills / product skills to consider:');
      lines.push(values.skills);
    }
    lines.push('');
    lines.push('Regional staffing requested: ' + (values.regional ? 'Yes' : 'No'));
    if (values.regional) {
      lines.push('If possible, prioritize SCs in the same timezone or near the customer location.');
    }
    if (values.location) lines.push('Customer billing/location context: ' + values.location);
    if (values.dates) {
      lines.push('');
      lines.push('Dates or windows when the SC is needed:');
      lines.push(values.dates);
    }
    lines.push('');
    lines.push('Please check Outlook calendars for the requested date(s)/windows if calendar data is available. Return both recommended SCs and SCs who otherwise match but should be disqualified because of scheduling conflicts; state the conflict reason when available.');
    lines.push('Return the answer using the locked 11-part response format above.');
    if (values.details) {
      lines.push('');
      lines.push('SC Request Details:');
      lines.push(values.details);
    }
    return lines.join('\n');
  }

  function isFirefoxBrowser() {
    const ua = String(navigator.userAgent || '');
    return /firefox|fxios/i.test(ua);
  }

  function buildGptAssistUrl(prompt) {
    if (isFirefoxBrowser()) return SCOUT_GPT_URL;
    try {
      const url = new URL(SCOUT_GPT_URL);
      if (prompt) url.searchParams.set('q', prompt);
      return url.toString();
    } catch (e) {
      return prompt ? `${SCOUT_GPT_URL}?q=${encodeURIComponent(prompt)}` : SCOUT_GPT_URL;
    }
  }

  function showGptAssistDialog() {
    const mode = activeStaffingModeLabel();
    const defaultValues = {
      mode,
      includeIndustry: true,
      industry: getGptIndustryText(mode),
      skills: getGptSkillText(mode),
      regional: false,
      location: getGptCustomerLocationText(),
      dates: getGptDateText(),
      details: getGptRequestDetailsText(),
      scrUrl: getGptScrUrl(),
    };
    const initialValues = GPT_ASSIST_DRAFT ? { ...defaultValues, ...GPT_ASSIST_DRAFT, mode, scrUrl: defaultValues.scrUrl } : defaultValues;

    const overlay = document.createElement('div');
    overlay.className = 'sc-notes-overlay';
    overlay.innerHTML = `
      <div class="sc-notes-dialog sc-gpt-dialog">
        <h3>Ask AI Agent</h3>
        <div class="sc-gpt-dialog-grid">
          <div class="sc-field">
            <label class="sc-label" for="sc-gpt-industry">Industry / Sub-Industry</label>
            <input type="text" id="sc-gpt-industry" value="${escAttr(initialValues.industry)}">
          </div>
          <div class="sc-field">
            <label class="sc-label" for="sc-gpt-location">Customer location</label>
            <input type="text" id="sc-gpt-location" value="${escAttr(initialValues.location)}" placeholder="City, State">
          </div>
        </div>
        <label class="sc-gpt-option-row"><input type="checkbox" id="sc-gpt-include-industry" ${initialValues.includeIndustry ? 'checked' : ''}> Use industry in recommendation</label>
        <label class="sc-gpt-option-row"><input type="checkbox" id="sc-gpt-regional" ${initialValues.regional ? 'checked' : ''}> Regional staffing: prefer same timezone / nearby area</label>
        <div class="sc-gpt-dialog-grid">
          <div class="sc-field">
            <label class="sc-label" for="sc-gpt-skills">Additional skills / product skills</label>
            <textarea id="sc-gpt-skills" placeholder="One per line">${escHtml(initialValues.skills)}</textarea>
          </div>
          <div class="sc-field">
            <label class="sc-label" for="sc-gpt-dates">Date SC Needed / additional dates</label>
            <textarea id="sc-gpt-dates" placeholder="Date SC Needed is prefilled. Add other date windows, one per line.">${escHtml(initialValues.dates)}</textarea>
          </div>
        </div>
        <div class="sc-field">
          <label class="sc-label" for="sc-gpt-details">SC Request Details</label>
          <textarea id="sc-gpt-details">${escHtml(initialValues.details)}</textarea>
        </div>
        <div class="sc-field">
          <label class="sc-label" for="sc-gpt-preview">Prompt preview</label>
          <textarea id="sc-gpt-preview" class="sc-gpt-prompt-preview"></textarea>
        </div>
        <div class="sc-notes-btn-row">
          <button class="sc-notes-cancel-btn" id="sc-gpt-cancel">Cancel</button>
          <button class="sc-notes-cancel-btn" id="sc-gpt-copy">Copy Prompt</button>
          <button class="sc-notes-ok-btn" id="sc-gpt-open">Open GPT</button>
        </div>
      </div>`;
    document.body.appendChild(overlay);

    const controls = {
      includeIndustry: overlay.querySelector('#sc-gpt-include-industry'),
      regional: overlay.querySelector('#sc-gpt-regional'),
      industry: overlay.querySelector('#sc-gpt-industry'),
      location: overlay.querySelector('#sc-gpt-location'),
      skills: overlay.querySelector('#sc-gpt-skills'),
      dates: overlay.querySelector('#sc-gpt-dates'),
      details: overlay.querySelector('#sc-gpt-details'),
      preview: overlay.querySelector('#sc-gpt-preview'),
    };

    function currentValues() {
      return {
        mode,
        includeIndustry: controls.includeIndustry.checked,
        regional: controls.regional.checked,
        industry: controls.industry.value.trim(),
        location: controls.location.value.trim(),
        skills: controls.skills.value.trim(),
        dates: controls.dates.value.trim(),
        details: controls.details.value.trim(),
        scrUrl: getGptScrUrl(),
      };
    }
    function saveDraft() {
      GPT_ASSIST_DRAFT = {
        ...currentValues(),
        preview: controls.preview.value,
      };
    }
    function refreshPreview() {
      controls.preview.value = buildGptAssistPromptFromValues(currentValues());
      saveDraft();
    }
    function cleanup() {
      saveDraft();
      overlay.remove();
    }
    function copyPrompt(showMessage = true) {
      const copied = copyToClipboardQuietly(controls.preview.value);
      if (showMessage) {
        showToast(copied ? 'AI prompt copied to clipboard.' : 'Could not copy prompt automatically.', copied ? 'success' : 'error', 4500);
        showPageToast(copied ? 'AI prompt copied to clipboard.' : 'Could not copy prompt automatically.', copied ? 'success' : 'error', 4500);
      }
      return copied;
    }

    ['input', 'change'].forEach(eventName => {
      Object.values(controls).forEach(control => {
        if (control && control !== controls.preview) control.addEventListener(eventName, refreshPreview);
      });
      controls.preview.addEventListener(eventName, saveDraft);
    });
    overlay.querySelector('#sc-gpt-cancel').addEventListener('click', cleanup);
    overlay.querySelector('#sc-gpt-copy').addEventListener('click', copyPrompt);
    overlay.querySelector('#sc-gpt-open').addEventListener('click', function () {
      const prompt = controls.preview.value;
      const copied = copyPrompt(false);
      const firefoxMode = isFirefoxBrowser();
      const successMsg = firefoxMode
        ? 'AI prompt copied. Paste it into ChatGPT.'
        : 'Opening ChatGPT with the prompt in the URL.';
      const fallbackMsg = firefoxMode
        ? 'Opening ChatGPT. Copy the prompt manually if needed.'
        : 'Opening ChatGPT with the prompt URL. Copy the prompt manually if needed.';
      const messageMs = firefoxMode ? 8000 : 6500;
      showToast(copied ? successMsg : fallbackMsg, copied ? 'success' : 'info', messageMs);
      showPageToast(copied ? successMsg : fallbackMsg, copied ? 'success' : 'info', messageMs);
      cleanup();
      setTimeout(() => gmOpenUrl(buildGptAssistUrl(prompt)), 500);
    });
    if (initialValues.preview) {
      controls.preview.value = initialValues.preview;
      saveDraft();
    } else {
      refreshPreview();
    }
    controls.preview.focus();
    controls.preview.setSelectionRange(0, 0);
  }

  /** Open the calendar dashboard for a single consultant (one tab). */
  function openCalForOne(e) {
    gmOpenUrl(buildDashboardUrl(e));
  }

  /**
   * Open the calendar dashboard for all consultants in a result set (one tab).
   */
  function openCalForAll(employees) {
    if (!employees || employees.length === 0) return;
    if (employees.length === 1) {
      gmOpenUrl(buildDashboardUrl(employees[0]));
    } else {
      gmOpenUrl(buildMultiDashboardUrl(employees.map(toRosterEntry)));
    }
  }

  /* ────────────────────────────────────────────────────────────────
     NETSUITE SEARCH HELPERS
  ──────────────────────────────────────────────────────────────── */

  function baseFilters(empRec, joinField) {
    const teamId = empRec && typeof empRec.getValue === 'function'
      ? empRec.getValue('custrecord_emproster_salesteam')
      : '';
    const filters = [
      new nlobjSearchFilter('custrecord_emproster_rosterstatus', joinField, 'is', 1),
      new nlobjSearchFilter('custrecord_emproster_eminactive',   joinField, 'is', 'F'),
      new nlobjSearchFilter('custrecord_emproster_ocostcenter',  joinField, 'is', ROSTER_COST_CENTER_ID),
      new nlobjSearchFilter('custrecord_emproster_salesregion',  joinField, 'is', ROSTER_SALES_REGION_ID),
      new nlobjSearchFilter('custrecord_emproster_sales_qb',     joinField, 'is', 25),
    ];
    if (teamId) filters.push(new nlobjSearchFilter('custrecord_emproster_salesteam', joinField, 'is', teamId));
    return filters;
  }

  /**
   * Base filters for AMO search — no team/region restriction.
   * Results are post-filtered in JS to salesteam = 'AMO'.
   */
  function amoBaseFilters(joinField) {
    return [
      new nlobjSearchFilter('custrecord_emproster_rosterstatus', joinField, 'is', 1),
      new nlobjSearchFilter('custrecord_emproster_eminactive',   joinField, 'is', 'F'),
      new nlobjSearchFilter('custrecord_emproster_ocostcenter',  joinField, 'is', ROSTER_COST_CENTER_ID),
      new nlobjSearchFilter('custrecord_emproster_salesregion',  joinField, 'is', ROSTER_SALES_REGION_ID),
      new nlobjSearchFilter('custrecord_emproster_sales_qb',     joinField, 'is', 25),
    ];
  }

  function uiFilters(opts, joinField, empIds) {
    const f = [];
    if (opts.myTeam && empIds && empIds.me)
      f.push(new nlobjSearchFilter('custrecord_emproster_mgrroster', joinField, 'is', empIds.me));
    if (SCOUT_CAN_READ_VERTICAL_AMO && opts.vertical && opts.vertical.length > 0)
      f.push(new nlobjSearchFilter('custrecord_emproster_vertical_amo', joinField, 'anyof', opts.vertical));
    if (opts.tier && opts.tier.length > 0)
      f.push(new nlobjSearchFilter('custrecord_emproster_sales_tier', joinField, 'anyof', opts.tier));
    if (SCOUT_CAN_READ_SALES_SUBREGION && opts.region && opts.region.length > 0)
      f.push(new nlobjSearchFilter('custrecord_emproster_salessubregion', joinField, 'anyof', opts.region));
    return f;
  }

  function getSkillData(skillIds, empRec, empIds, filterOpts) {
    const join = 'custrecord_ssm_skill_employee';
    const rosterBase = filterOpts && filterOpts.limitToMyTeam ? amoBaseFilters(join) : baseFilters(empRec, join);
    const filters = [
      new nlobjSearchFilter('custrecord_ssm_skill_entry', null, 'anyof', skillIds),
      ...rosterBase,
      ...uiFilters(filterOpts, join, empIds),
    ];
    const cols = [
      new nlobjSearchColumn('custrecord_ssm_skill_employee'),
      new nlobjSearchColumn('internalid',                           join),
      new nlobjSearchColumn('custrecord_emproster_avail',           join),
      ...availabilityNotesColumns(join),
      ...managerAvailResColumns(join),
      new nlobjSearchColumn('custrecord_emproster_mgrroster',       join),
      new nlobjSearchColumn('custrecord_emproster_olocation',       join),
      ...salesSubregionColumns(join),
      ...verticalAmoColumns(join),
      new nlobjSearchColumn('custrecord_emproster_sales_tier',      join),
      new nlobjSearchColumn('custrecord_emproster_salesteam',       join),
      new nlobjSearchColumn('custrecord_emproster_emp',             join),
      new nlobjSearchColumn('custrecord_ssm_skill_entry'),
      new nlobjSearchColumn('custrecord_ssm_skill_rating'),
    ];
    const results = nlapiSearchRecord('customrecord_ssm_entry', null, filters, cols);
    if (!results) return [];
    return results.map(r => ({
      employeeId:   r.getValue('internalid', join),
      employee:     r.getText('custrecord_ssm_skill_employee'),
      manager:      r.getText('custrecord_emproster_mgrroster', join),
      availability: r.getText('custrecord_emproster_avail', join),
      availNotes:   readAvailabilityNotes(r, join),
      availRes:     readManagerAvailRes(r, join),
      location:     r.getText('custrecord_emproster_olocation', join),
      region:       readSalesSubregion(r, join),
      vertical:     readVerticalAmo(r, join),
      tier:         r.getText('custrecord_emproster_sales_tier', join),
      salesteam:    r.getText('custrecord_emproster_salesteam', join),
      employeeRecId: r.getValue('custrecord_emproster_emp', join) || '',
      skill:        r.getText('custrecord_ssm_skill_entry'),
      ratingRaw:    parseRatingValue(r.getText('custrecord_ssm_skill_rating') || r.getValue('custrecord_ssm_skill_rating')),
    })).filter(r => parseInt(r.ratingRaw, 10) >= 1);
  }

  function splitIndustryIdList(industryId) {
    return String(industryId || '').split(',').map(s => s.trim()).filter(Boolean);
  }

  function resolveIndustrySearchIds(industryId) {
    const resolved = [];
    splitIndustryIdList(industryId).forEach(id => {
      if (id.startsWith('gtm:')) {
        const key = id.slice(4);
        (INDUSTRY_OPTIONS_CACHE || []).forEach(option => {
          if (option.gtmKey === key) {
            splitIndustryIdList(option.id).forEach(childId => {
              if (childId && !childId.startsWith('gtm:') && !resolved.includes(childId)) resolved.push(childId);
            });
          }
        });
      } else if (!resolved.includes(id)) {
        resolved.push(id);
      }
    });
    return resolved.filter(id => id && !id.startsWith('gtm:'));
  }

  function getIndustryData(industryId, empRec, empIds, filterOpts) {
    const join = 'custrecord_sr_ind_rating_employee';
    const industryIds = resolveIndustrySearchIds(industryId);
    if (!industryIds.length) return [];
    const rosterBase = filterOpts && filterOpts.limitToMyTeam ? amoBaseFilters(join) : baseFilters(empRec, join);
    const filters = [
      new nlobjSearchFilter('custrecord_sr_ind_rating_subindustry', null, 'anyof', industryIds),
      ...rosterBase,
      ...uiFilters(filterOpts, join, empIds),
    ];
    const cols = [
      new nlobjSearchColumn('custrecord_sr_ind_rating_employee'),
      new nlobjSearchColumn('internalid', join),
      new nlobjSearchColumn('custrecord_sr_ind_rating'),
      new nlobjSearchColumn('custrecord_emproster_emp', join),
      new nlobjSearchColumn('custrecord_emproster_salesteam', join),
      ...verticalAmoColumns(join),
    ];
    const results = nlapiSearchRecord('customrecord_sr_industry_rating_entry', null, filters, cols);
    if (!results) return [];
    return results.map(r => ({
      employeeId:     r.getValue('internalid', join),
      employee:       r.getText('custrecord_sr_ind_rating_employee'),
      employeeRecId:  r.getValue('custrecord_emproster_emp', join) || '',
      salesteam:      r.getText('custrecord_emproster_salesteam', join) || '',
      vertical:       readVerticalAmo(r, join),
      industryRating: parseRatingValue(r.getText('custrecord_sr_ind_rating') || r.getValue('custrecord_sr_ind_rating')),
    })).filter(r => parseInt(r.industryRating, 10) >= 1);
  }

  function parseRatingValue(value) {
    const raw = String(value || '').trim();
    const match = raw.match(/[1-4]/);
    return match ? parseInt(match[0], 10) : 0;
  }

  function ratingCredit(value) {
    return RATING_WEIGHTS[Math.max(0, Math.min(4, parseInt(value, 10) || 0))] || 0;
  }

  function ratingLabel(value) {
    const rating = parseInt(value, 10) || 0;
    if (rating >= 3) return 'SME';
    if (rating === 2) return 'Experienced';
    if (rating === 1) return 'Ramping';
    return 'No Experience';
  }

  function getEmployeeEmails(rosterIds) {
    if (!rosterIds || rosterIds.length === 0) return {};
    try {
      const filters = [new nlobjSearchFilter('internalid', null, 'anyof', rosterIds)];
      const cols = [
        new nlobjSearchColumn('internalid'),
        new nlobjSearchColumn('email', 'custrecord_emproster_emp'),
      ];
      const results = nlapiSearchRecord('customrecord_emproster', null, filters, cols);
      if (!results) return {};
      const map = {};
      results.forEach(r => {
        map[r.getValue('internalid')] = r.getValue('email', 'custrecord_emproster_emp') || '';
      });
      return map;
    } catch (e) {
      console.warn('[Staffing Helper] Could not fetch employee emails:', e);
      return {};
    }
  }

  function nsDateString(d) {
    const mm = String(d.getMonth() + 1).padStart(2, '0');
    const dd = String(d.getDate()).padStart(2, '0');
    return `${mm}/${dd}/${d.getFullYear()}`;
  }

  function addDays(date, days) {
    const d = new Date(date.getTime());
    d.setDate(d.getDate() + days);
    return d;
  }

  function getRecentScrLoad(members) {
    members = members || [];
    const ids = [...new Set(members.map(m => m.employeeId).filter(Boolean))];
    const rosterByEmployee = {};
    const rosterByName = {};

    function addRosterNameVariant(name, rosterId) {
      const key = normalizeLoose(name);
      if (key && rosterId) rosterByName[key] = rosterId;
    }

    members.forEach(m => {
      if (m.employeeRecId && m.employeeId) rosterByEmployee[m.employeeRecId] = m.employeeId;
      const rawName = m.employee || m.name || '';
      addRosterNameVariant(rawName, m.employeeId);
      if (rawName.includes(',')) {
        const parts = rawName.split(',').map(s => s.trim()).filter(Boolean);
        if (parts.length >= 2) addRosterNameVariant(`${parts[1]} ${parts[0]}`, m.employeeId);
      } else {
        const parts = rawName.trim().split(/\s+/).filter(Boolean);
        if (parts.length >= 2) addRosterNameVariant(`${parts.slice(-1)[0]}, ${parts.slice(0, -1).join(' ')}`, m.employeeId);
      }
    });
    const counts = {};
    const now = Date.now();
    ids.forEach(id => {
      const cached = RECENT_LOAD_CACHE.get(id);
      counts[id] = cached && (now - cached.ts < RECENT_LOAD_CACHE_TTL_MS) ? cached.count : 0;
    });
    const missing = ids.filter(id => {
      const cached = RECENT_LOAD_CACHE.get(id);
      return !cached || (now - cached.ts >= RECENT_LOAD_CACHE_TTL_MS);
    });
    if (!missing.length) return counts;

    const missingSet = new Set(missing);
    const employeeIds = Object.keys(rosterByEmployee).filter(empId => missingSet.has(rosterByEmployee[empId]));
    const seenScrs = new Set();
    const loadDebugSamples = [];
    missing.forEach(id => { counts[id] = 0; });

    function readSearchValue(r, fieldId, joinId) {
      try { return joinId ? r.getValue(fieldId, joinId) : r.getValue(fieldId); }
      catch (e) { return ''; }
    }

    function readSearchText(r, fieldId, joinId) {
      try { return joinId ? r.getText(fieldId, joinId) : r.getText(fieldId); }
      catch (e) { return ''; }
    }

    function columnDescriptor(col) {
      const parts = [];
      ['getName', 'getLabel', 'getJoin', 'getSummary'].forEach(fn => {
        try {
          if (col && typeof col[fn] === 'function') parts.push(col[fn]() || '');
        } catch (e) { /* ignore */ }
      });
      return parts.join(' ').toLowerCase();
    }

    function parseLoadCountValue(value) {
      const normalized = String(value == null ? '' : value).replace(/,/g, '').trim();
      if (!/^\d+(?:\.\d+)?$/.test(normalized)) return null;
      return Math.max(0, Math.round(Number(normalized)));
    }

    function loadCountFromSavedSearchColumns(r) {
      let cols = [];
      try { cols = typeof r.getAllColumns === 'function' ? (r.getAllColumns() || []) : []; }
      catch (e) { cols = []; }
      const candidates = [];
      cols.forEach(col => {
        const hint = columnDescriptor(col);
        const rawValue = readColumnValue(r, col, false);
        const rawText = readColumnValue(r, col, true);
        const value = parseLoadCountValue(rawValue);
        const textValue = parseLoadCountValue(rawText);
        const count = value != null ? value : textValue;
        if (count == null) return;
        if (/assignee|consultant|employee|manager|email|name|region|vertical|team/i.test(hint)) return;

        let score = 0;
        if (/\b(scr|request|load)\b/i.test(hint)) score += 25;
        if (/(last|lst)\s*7|7\s*(?:days|dys)|assigned.*7/i.test(hint)) score += 80;
        if (/count|sum|formula|numeric/i.test(hint)) score += 30;
        if (/\bcount\b|\bsum\b/i.test(hint)) score += 20;
        if (score > 0) candidates.push({ score, count, hint });
      });
      if (!candidates.length) return null;
      candidates.sort((a, b) => b.score - a.score);
      return candidates[0].count;
    }

    function rosterIdFromNameText(text) {
      const nameKey = normalizeLoose(text);
      if (!nameKey) return '';
      if (rosterByName[nameKey]) return rosterByName[nameKey];
      const matchedKey = Object.keys(rosterByName).find(key =>
        key && (nameKey === key || nameKey.includes(key) || key.includes(nameKey)));
      return matchedKey ? rosterByName[matchedKey] : '';
    }

    function readColumnValue(r, col, asText) {
      try {
        return asText ? r.getText(col) : r.getValue(col);
      } catch (e) { /* fall through */ }
      try {
        const name = col && typeof col.getName === 'function' ? col.getName() : '';
        const join = col && typeof col.getJoin === 'function' ? col.getJoin() : null;
        const summary = col && typeof col.getSummary === 'function' ? col.getSummary() : null;
        return asText ? r.getText(name, join, summary) : r.getValue(name, join, summary);
      } catch (e) { return ''; }
    }

    function rosterIdFromSavedSearchColumns(r) {
      let cols = [];
      try { cols = typeof r.getAllColumns === 'function' ? (r.getAllColumns() || []) : []; }
      catch (e) { cols = []; }
      for (const col of cols) {
        const hint = columnDescriptor(col);
        const value = String(readColumnValue(r, col, false) || '').trim();
        const text = String(readColumnValue(r, col, true) || '').trim();
        const byName = rosterIdFromNameText(text) || rosterIdFromNameText(value);
        if (byName) return byName;
        if (/assignee|employee|consultant|staff/i.test(hint)) {
          if (value && missingSet.has(value)) return value;
          if (value && rosterByEmployee[value]) return rosterByEmployee[value];
        }
      }
      return '';
    }

    function sampleLoadRow(r, rowCount, searchId, recordType) {
      if (loadDebugSamples.length >= 4) return;
      let cols = [];
      try { cols = typeof r.getAllColumns === 'function' ? (r.getAllColumns() || []) : []; }
      catch (e) { cols = []; }
      loadDebugSamples.push({
        searchId,
        recordType,
        rowCount,
        columns: cols.slice(0, 12).map(col => ({
          hint: columnDescriptor(col),
          value: readColumnValue(r, col, false),
          text: readColumnValue(r, col, true),
        })),
      });
    }

    function rosterIdFromLoadRow(r) {
      const directRosterId = readSearchValue(r, SCR_FIELD_ASSIGNEE);
      if (directRosterId && missingSet.has(directRosterId)) return directRosterId;

      const employeeId = readSearchValue(r, SCR_FIELD_ASSIGNEE_EMPLOYEE) ||
        readSearchValue(r, 'custrecord_emproster_emp', SCR_FIELD_ASSIGNEE);
      if (employeeId && rosterByEmployee[employeeId]) return rosterByEmployee[employeeId];

      const assigneeName = normalizeLoose(readSearchText(r, SCR_FIELD_ASSIGNEE) ||
        readSearchText(r, SCR_FIELD_ASSIGNEE_EMPLOYEE));
      const byName = rosterIdFromNameText(assigneeName);
      if (byName) return byName;

      return rosterIdFromSavedSearchColumns(r);
    }

    function addRows(rows, opts) {
      const options = opts || {};
      let matched = 0;
      (rows || []).forEach(r => {
        const assignee = rosterIdFromLoadRow(r);
        if (!assignee || !missingSet.has(assignee)) return;
        const savedSearchMetric = options.useSavedSearchMetric ? loadCountFromSavedSearchColumns(r) : null;
        if (savedSearchMetric != null) {
          counts[assignee] = Math.max(Number(counts[assignee] || 0), savedSearchMetric);
          matched += 1;
          return;
        }
        const scrId = r.getValue('internalid') || `${assignee}:${counts[assignee]}`;
        const seenKey = `${assignee}:${scrId}`;
        if (seenScrs.has(seenKey)) return;
        seenScrs.add(seenKey);
        counts[assignee] = (counts[assignee] || 0) + 1;
        matched += 1;
      });
      return matched;
    }

    function runLoadSearch(searchId, filters, cols, opts) {
      const searchTypes = searchId ? [SCR_RECORD_TYPE, null] : [SCR_RECORD_TYPE];
      for (const recordType of searchTypes) {
        try {
          const rows = nlapiSearchRecord(recordType, searchId || null, filters, cols) || [];
          if (searchId && recordType && rows.length === 0) continue;
          if (searchId && rows.length) sampleLoadRow(rows[0], rows.length, searchId, recordType);
          const matched = addRows(rows, opts);
          return { ok: true, rows: rows.length, matched };
        } catch (e) {
          console.warn('[Staffing Helper] Recent SCR load lookup failed:', {
            searchId,
            recordType,
            message: e.message || e,
          });
        }
      }
      return { ok: false, rows: 0, matched: 0 };
    }

    function hasAnyLoadCount() {
      return missing.some(id => Number(counts[id] || 0) > 0);
    }

    const savedSearchResult = runLoadSearch(RECENT_LOAD_SEARCH_ID, null, null, { useSavedSearchMetric: true });
    if (!savedSearchResult.ok) {
      console.warn('[Staffing Helper] Recent SCR load saved search was unavailable. Counts defaulted to zero.', {
        searchId: RECENT_LOAD_SEARCH_ID,
      });
    }
    if (!hasAnyLoadCount() && loadDebugSamples.length) {
      console.warn('[Staffing Helper] SCR load search returned rows but none matched the visible roster cards.', {
        searchId: RECENT_LOAD_SEARCH_ID,
        visibleRosterIds: missing,
        visibleEmployeeIds: employeeIds,
        visibleNameKeys: Object.keys(rosterByName).slice(0, 20),
        samples: loadDebugSamples,
      });
    }
    missing.forEach(id => RECENT_LOAD_CACHE.set(id, { count: counts[id] || 0, ts: Date.now() }));
    return counts;
  }

  function enrichRecentScrLoad(members) {
    if (!members || !members.length) return;
    const loadMap = getRecentScrLoad(members);
    members.forEach(m => { m.recentLoad = loadMap[m.employeeId] || 0; });
  }

  /**
   * Enrich member objects (from getRequestedSCRoster / loadQuickAssignCard) with
   * availability and email fetched directly from customrecord_emproster.
   * This ensures accurate avail/notes regardless of how the member was located.
   * Mutates each member in-place.
   */
  function enrichMembersWithRosterData(members) {
    if (!members || !members.length) return;
    try {
      const ids = members.map(function (m) { return m.employeeId; }).filter(Boolean);
      if (!ids.length) return;
      const filters = [new nlobjSearchFilter('internalid', null, 'anyof', ids)];
      const cols = [
        new nlobjSearchColumn('internalid'),
        new nlobjSearchColumn('custrecord_emproster_avail'),
        ...availabilityNotesColumns(null),
        ...managerAvailResColumns(null),
        new nlobjSearchColumn('custrecord_emproster_emp'),
        new nlobjSearchColumn('custrecord_emproster_salesteam'),
        new nlobjSearchColumn('email', 'custrecord_emproster_emp'),
      ];
      const results = nlapiSearchRecord('customrecord_emproster', null, filters, cols);
      if (!results) return;
      const map = {};
      results.forEach(function (r) {
        const id = r.getValue('internalid');
        if (!id) return;
        map[id] = {
          availability: (r.getText('custrecord_emproster_avail')             || '').toLowerCase(),
          availNotes:    readAvailabilityNotes(r, null),
          availRes:      readManagerAvailRes(r, null),
          employeeRecId: r.getValue('custrecord_emproster_emp')               || '',
          salesteam:     r.getText('custrecord_emproster_salesteam')          || '',
          email:         r.getValue('email', 'custrecord_emproster_emp')      || '',
        };
      });
      members.forEach(function (m) {
        const d = map[m.employeeId];
        if (!d) return;
        m.availability = d.availability;
        m.availNotes   = d.availNotes;
        m.availRes     = d.availRes;
        m.employeeRecId = d.employeeRecId;
        m.salesteam    = d.salesteam;
        m.email        = d.email;
      });
    } catch (e) {
      console.warn('[Staffing Helper] enrichMembersWithRosterData error:', e);
    }
  }

  function normalizeLoose(text) {
    return String(text || '')
      .toLowerCase()
      .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
      .replace(/[^a-z0-9]+/g, ' ')
      .trim();
  }

  function getAdditionalSkillOptions(prefix) {
    return {
      cpa: Boolean(document.getElementById(`${prefix}-cert-cpa`)?.checked),
    };
  }

  function hasAdditionalSkillFilters(opts) {
    return Boolean(opts && opts.cpa);
  }

  function mergeKnownAdditionalSkillMatches(matches, opts) {
    if (!opts || !opts.cpa) return matches;
    (ADDITIONAL_SKILL_KNOWN_MATCHES.cpa || []).forEach(targetName => {
      try {
        const last = targetName.includes(',') ? targetName.split(',')[0].trim() : targetName.split(/\s+/).slice(-1)[0];
        const result = searchRosterByName(last);
        const variants = routeNameVariants(targetName);
        (result.members || []).forEach(member => {
          const normalized = normalizeRouteName(member.employee);
          if (variants.some(v => normalized === v || normalized.includes(v) || v.includes(normalized))) {
            matches.add(member.employeeId);
          }
        });
      } catch (e) {
        console.warn('[Staffing Helper] Known CPA fallback lookup failed:', targetName, e.message || e);
      }
    });
    return matches;
  }

  function getRecordValueText(rec, fieldId) {
    const parts = [];
    try {
      const value = rec.getFieldValue(fieldId);
      if (Array.isArray(value)) parts.push(value.join(' '));
      else if (value != null) parts.push(String(value));
    } catch (e) { /* keep collecting */ }
    try {
      const values = rec.getFieldValues(fieldId);
      if (Array.isArray(values)) parts.push(values.join(' '));
    } catch (e) { /* keep collecting */ }
    try {
      const text = rec.getFieldText(fieldId);
      if (text != null) parts.push(String(text));
    } catch (e) { /* keep collecting */ }
    return parts.filter(Boolean).join(' ');
  }

  function getGlobalResultMeta(result) {
    const out = { id: '', type: '', text: '' };
    try { out.id = result.getId ? result.getId() : ''; } catch (e) { /* ignore */ }
    try { out.type = result.getRecordType ? result.getRecordType() : ''; } catch (e) { /* ignore */ }
    ['name', 'title', 'info1', 'info2', 'recordtype'].forEach(col => {
      try {
        const value = result.getValue && result.getValue(col);
        if (value) out.text += ` ${value}`;
      } catch (e) { /* ignore */ }
      try {
        const text = result.getText && result.getText(col);
        if (text) out.text += ` ${text}`;
      } catch (e) { /* ignore */ }
    });
    return out;
  }

  function recordReferencesCandidateEmployee(rec, fields, employeeToRoster, employeeNameToRoster) {
    const matchedRosterIds = new Set();
    fields.forEach(fieldId => {
      const raw = getRecordValueText(rec, fieldId);
      if (!raw) return;
      raw.split(/[,\s]+/).forEach(token => {
        if (employeeToRoster[token]) employeeToRoster[token].forEach(id => matchedRosterIds.add(id));
      });
      const normalizedText = normalizeLoose(raw);
      Object.keys(employeeNameToRoster).forEach(nameKey => {
        if (nameKey && normalizedText === nameKey) {
          employeeNameToRoster[nameKey].forEach(id => matchedRosterIds.add(id));
        }
      });
    });
    return matchedRosterIds;
  }

  function certificationHaystackMatches(haystack, opts) {
    const normalized = normalizeLoose(haystack);
    return !opts.cpa || /\bcpa\b/.test(normalized);
  }

  function getRecordLineValueText(rec, sublistId, fieldId, line) {
    const parts = [];
    try {
      const value = rec.getLineItemValue(sublistId, fieldId, line);
      if (value != null) parts.push(String(value));
    } catch (e) { /* keep collecting */ }
    try {
      const text = rec.getLineItemText(sublistId, fieldId, line);
      if (text != null) parts.push(String(text));
    } catch (e) { /* keep collecting */ }
    return parts.filter(Boolean).join(' ');
  }

  function employeeRecordCertificationMatches(members, opts) {
    const matches = new Set();
    if (!hasAdditionalSkillFilters(opts) || !members || !members.length) return matches;
    if (!unsafeWindow.nlapiLoadRecord) return matches;

    const certLike = /(cert|credential|qualification|qual|skill|recmach)/i;
    const scanMembers = members.filter(m => m.employeeRecId && m.employeeId);

    scanMembers.forEach(member => {
      try {
        const rec = nlapiLoadRecord('employee', member.employeeRecId);
        if (!rec) return;

        try {
          const bodyFields = typeof rec.getAllFields === 'function' ? (rec.getAllFields() || []) : [];
          const bodyHaystack = bodyFields
            .map(fieldId => getRecordValueText(rec, fieldId))
            .join(' ');
          if (bodyHaystack && certificationHaystackMatches(bodyHaystack, opts)) {
            matches.add(member.employeeId);
            return;
          }
        } catch (e) { /* body scan is best-effort */ }

        const sublists = typeof rec.getAllLineItems === 'function' ? (rec.getAllLineItems() || []) : [];
        const relevantSublists = sublists.filter(sublistId => certLike.test(sublistId));
        const listsToScan = relevantSublists.length ? relevantSublists : sublists;

        for (const sublistId of listsToScan) {
          let count = 0;
          try { count = Number(rec.getLineItemCount(sublistId)) || 0; } catch (e) { count = 0; }
          if (!count) continue;

          let fields = [];
          try { fields = rec.getAllLineItemFields(sublistId) || []; } catch (e) { fields = []; }
          if (!fields.length) continue;

          for (let line = 1; line <= Math.min(count, 200); line++) {
            const lineHaystack = [
              sublistId,
              ...fields.map(fieldId => getRecordLineValueText(rec, sublistId, fieldId, line)),
            ].join(' ');
            if (certificationHaystackMatches(lineHaystack, opts)) {
              matches.add(member.employeeId);
              return;
            }
          }
        }
      } catch (e) {
        console.warn('[Staffing Helper] Employee certification sublist scan failed:', member.employee, e.message || e);
      }
    });
    return matches;
  }

  function loadedCertificationRecordMatches(members, opts, employeeToRoster, schemas) {
    const matches = new Set();
    if (!hasAdditionalSkillFilters(opts) || !members || !members.length) return matches;
    if (!unsafeWindow.nlapiLoadRecord) return matches;

    const employeeIds = [...new Set(members.map(m => m.employeeRecId).filter(Boolean))];
    if (!employeeIds.length) return matches;
    const searched = new Set();

    (schemas || []).forEach(schema => {
      const key = `${schema.recordType}:${schema.employee}`;
      if (searched.has(key)) return;
      searched.add(key);

      try {
        const rows = nlapiSearchRecord(schema.recordType, null, [
          new nlobjSearchFilter(schema.employee, null, 'anyof', employeeIds),
        ], [
          new nlobjSearchColumn('internalid'),
          new nlobjSearchColumn(schema.employee),
        ]) || [];

        rows.slice(0, 300).forEach(row => {
          const employeeId = row.getValue(schema.employee);
          const rosterIds = employeeToRoster[employeeId] || [];
          if (!rosterIds.length) return;

          try {
            const recId = row.getId ? row.getId() : row.getValue('internalid');
            if (!recId) return;
            const rec = nlapiLoadRecord(schema.recordType, recId);
            if (!rec || typeof rec.getAllFields !== 'function') return;
            const fields = rec.getAllFields() || [];
            const haystack = fields.map(fieldId => getRecordValueText(rec, fieldId)).join(' ');
            if (!certificationHaystackMatches(haystack, opts)) return;
            rosterIds.forEach(id => matches.add(id));
          } catch (loadErr) {
            console.warn('[Staffing Helper] Certification record load failed:', schema.recordType, loadErr.message || loadErr);
          }
        });
      } catch (e) {
        console.warn('[Staffing Helper] Loaded certification lookup schema failed:', key, e.message || e);
      }
    });
    return matches;
  }

  function getCertificationMatches(members, opts) {
    if (!hasAdditionalSkillFilters(opts) || !members || !members.length) {
      return new Set((members || []).map(m => m.employeeId));
    }
    const employeeIds = [...new Set(members.map(m => m.employeeRecId).filter(Boolean))];
    if (!employeeIds.length) return mergeKnownAdditionalSkillMatches(new Set(), opts);

    const schemas = [
      {
        recordType: 'customrecord_employee_certification',
        employee: 'custrecord_certification_employee',
        title: 'custrecord_certification_title',
        notes: 'custrecord_certification_notes',
      },
      {
        recordType: 'customrecord_certifications',
        employee: 'custrecord_cert_employee',
        title: 'custrecord_cert_title',
        notes: 'custrecord_cert_notes',
      },
      {
        recordType: 'customrecord_emp_certification',
        employee: 'custrecord_emp_cert_employee',
        title: 'custrecord_emp_cert_title',
        notes: 'custrecord_emp_cert_notes',
      },
      {
        recordType: 'customrecord_certification',
        employee: 'custrecord_certification_employee',
        title: 'custrecord_certification_title',
        notes: 'custrecord_certification_notes',
      },
      {
        recordType: 'customrecord_certification',
        employee: 'custrecord_employee',
        title: 'custrecord_certification_title',
        notes: 'custrecord_notes',
      },
      {
        recordType: 'customrecord_certification',
        employee: 'custrecord_employee',
        title: 'name',
        notes: null,
      },
      {
        recordType: 'customrecord_emp_certifications',
        employee: 'custrecord_emp_cert_employee',
        title: 'custrecord_emp_cert_title',
        notes: 'custrecord_emp_cert_notes',
      },
      {
        recordType: 'customrecord_employee_certification',
        employee: 'custrecord_employee',
        title: 'name',
        notes: null,
      },
      {
        recordType: 'customrecord_certifications',
        employee: 'custrecord_employee',
        title: 'name',
        notes: null,
      },
    ];

    const employeeToRoster = {};
    members.forEach(m => {
      if (!m.employeeRecId) return;
      if (!employeeToRoster[m.employeeRecId]) employeeToRoster[m.employeeRecId] = [];
      employeeToRoster[m.employeeRecId].push(m.employeeId);
    });

    const matches = new Set();
    for (const schema of schemas) {
      try {
        const filters = [
          new nlobjSearchFilter(schema.employee, null, 'anyof', employeeIds),
        ];
        const cols = [
          new nlobjSearchColumn(schema.employee),
          new nlobjSearchColumn(schema.title),
        ];
        if (schema.notes) cols.push(new nlobjSearchColumn(schema.notes));
        const rows = nlapiSearchRecord(schema.recordType, null, filters, cols) || [];
        rows.forEach(r => {
          const employeeId = r.getValue(schema.employee);
          const title = r.getText(schema.title) || r.getValue(schema.title) || '';
          const notes = schema.notes ? (r.getValue(schema.notes) || '') : '';
          const haystack = normalizeLoose(`${title} ${notes}`);
          const cpaOk = !opts.cpa || /\bcpa\b/.test(haystack);
          if (!cpaOk) return;
          (employeeToRoster[employeeId] || []).forEach(rosterId => matches.add(rosterId));
        });
      } catch (e) {
        console.warn('[Staffing Helper] Certification lookup schema failed:', schema.recordType, e.message || e);
      }
    }
    if (matches.size === 0) {
      loadedCertificationRecordMatches(members, opts, employeeToRoster, schemas).forEach(id => matches.add(id));
    }
    if (matches.size === 0) {
      employeeRecordCertificationMatches(members, opts).forEach(id => matches.add(id));
    }
    return mergeKnownAdditionalSkillMatches(matches, opts);
  }

  function applyAdditionalSkillFilters(members, opts) {
    if (!hasAdditionalSkillFilters(opts)) return members;
    const matches = getCertificationMatches(members, opts);
    return members.filter(m => matches.has(m.employeeId));
  }

