  /* ── Meeting date for View Cal ──────────────────────────────────── */
  /**
   * Returns the best date for the calendar URL (YYYY-MM-DD).
   * Prefers the Anticipated Customer Meeting date field; falls back to date_needed.
   */
  function toCalendarYMD(raw) {
    const value = String(raw || '').trim();
    if (!value) return '';

    let m = value.match(/^(\d{1,2})\/(\d{1,2})\/(\d{2,4})$/);
    if (m) {
      const yyyy = m[3].length === 2 ? `20${m[3]}` : m[3];
      return `${yyyy}-${m[1].padStart(2,'0')}-${m[2].padStart(2,'0')}`;
    }

    m = value.match(/^(\d{4})-(\d{1,2})-(\d{1,2})/);
    if (m) return `${m[1]}-${m[2].padStart(2,'0')}-${m[3].padStart(2,'0')}`;

    const parsed = new Date(value);
    if (!Number.isNaN(parsed.valueOf())) {
      const mm = String(parsed.getMonth() + 1).padStart(2, '0');
      const dd = String(parsed.getDate()).padStart(2, '0');
      return `${parsed.getFullYear()}-${mm}-${dd}`;
    }
    return '';
  }

  function readFieldDateYMD(fieldId) {
    if (!fieldId) return '';
    try {
      const raw = nlapiGetFieldValue(fieldId) || '';
      const ymd = toCalendarYMD(raw);
      if (ymd) return ymd;
    } catch (e) { /* field may not exist */ }
    try {
      const raw = readFormFieldValue(fieldId) || readFormField(fieldId) || '';
      const ymd = toCalendarYMD(raw);
      if (ymd) return ymd;
    } catch (e) { /* field may not exist */ }
    return '';
  }

  function findDateValueByLabel(labelPattern) {
    function valueFromControl(el) {
      if (!el) return '';
      if ('value' in el && el.value) return el.value;
      return el.textContent || '';
    }

    function controlsNear(el) {
      const controls = [];
      if (el.htmlFor) {
        const direct = el.ownerDocument.getElementById(el.htmlFor);
        if (direct) controls.push(direct);
      }
      if (el.id && /_fs_lbl$/i.test(el.id)) {
        const base = el.id.replace(/_fs_lbl$/i, '');
        [base, `${base}_fs`, `${base}_val`, `${base}_display`].forEach(id => {
          const candidate = el.ownerDocument.getElementById(id);
          if (candidate) controls.push(candidate);
        });
      }
      const row = el.closest && el.closest('tr, .uir-field-wrapper, .uir-field, .field_widget');
      if (row) controls.push(...row.querySelectorAll('input, select, textarea, span[id$="_val"]'));
      if (el.parentElement?.nextElementSibling) {
        controls.push(...el.parentElement.nextElementSibling.querySelectorAll('input, select, textarea, span[id$="_val"]'));
      }
      return controls;
    }

    function searchDoc(doc) {
      const labels = Array.from(doc.querySelectorAll('label, span, div, td, th'))
        .filter(el => {
          const text = (el.textContent || '').replace(/\s+/g, ' ').trim();
          return text.length > 0 && text.length < 120 && labelPattern.test(text);
        });
      for (const label of labels) {
        for (const control of controlsNear(label)) {
          const ymd = toCalendarYMD(valueFromControl(control));
          if (ymd) return ymd;
        }
      }
      return '';
    }

    function searchWin(win) {
      try {
        const found = searchDoc(win.document);
        if (found) return found;
        for (let i = 0; i < win.frames.length; i++) {
          const nested = searchWin(win.frames[i]);
          if (nested) return nested;
        }
      } catch (e) { /* cross-origin or inaccessible frame */ }
      return '';
    }

    try {
      return searchWin(unsafeWindow.top || unsafeWindow) || searchWin(unsafeWindow);
    } catch (e) {
      return '';
    }
  }

  function getDateForCal() {
    for (const fieldId of SCR_FIELD_MEETING_DATE_CANDIDATES) {
      const ymd = readFieldDateYMD(fieldId);
      if (ymd) return ymd;
    }
    const labelledMeetingDate = findDateValueByLabel(/anticipated\s+customer\s+meeting\s+date/i);
    if (labelledMeetingDate) return labelledMeetingDate;

    const needed = readFieldDateYMD('custrecord_screq_date_needed');
    if (needed) return needed;

    console.warn('[Staffing Helper] Calendar date not found; dashboard may default to today.');
    return '';
  }

  /* ── Lead-on-opp check ──────────────────────────────────────────── */
  /**
   * Check if another SCR on the same opportunity already has ASSIGN AS LEAD = T.
   * Returns the name of the lead SC if found, or null if not.
   * Uses SCR_FIELD_OPP — field name needs confirmation.
   */
  function checkLeadOnOpp() {
    try {
      const oppId = (nlapiGetFieldValue(SCR_FIELD_OPP) || '').trim();
      if (!oppId) return null;
      const currentId = nlapiGetFieldValue('internalid') || '';
      const rows = nlapiSearchRecord(SCR_RECORD_TYPE, null, [
        new nlobjSearchFilter(SCR_FIELD_OPP,             null, 'is', oppId),
        new nlobjSearchFilter(SCR_FIELD_ASSIGNED_LEAD,   null, 'is', 'T'),
        new nlobjSearchFilter('custrecord_screq_status',  null, 'noneof', [4, 5]), // exclude cancelled
      ], [
        new nlobjSearchColumn('internalid'),
        new nlobjSearchColumn('custrecord_screq_assignee'),
      ]);
      if (!rows || !rows.length) return null;
      // Ignore if the only match is this record itself
      for (var i = 0; i < rows.length; i++) {
        const id = rows[i].getValue('internalid');
        if (id && id !== currentId) {
          return rows[i].getText('custrecord_screq_assignee') || 'another SC';
        }
      }
      return null;
    } catch (e) {
      console.warn('[Staffing Helper] checkLeadOnOpp:', e.message || e);
      return null;
    }
  }

  /**
   * Fetch all roster records where the current user is the manager.
   * Returns the same shape as consolidateData results (sans skill/rank fields).
   */
  function getRosterSearchColumns() {
    return [
      new nlobjSearchColumn('name'),
      new nlobjSearchColumn('internalid'),
      new nlobjSearchColumn('custrecord_emproster_avail'),
      ...availabilityNotesColumns(null),
      ...managerAvailResColumns(null),
      new nlobjSearchColumn('custrecord_emproster_olocation'),
      ...salesSubregionColumns(null),
      ...verticalAmoColumns(null),
      new nlobjSearchColumn('custrecord_emproster_sales_tier'),
      new nlobjSearchColumn('custrecord_emproster_emp'),
    ];
  }

  function activeRosterFilters() {
    return [
      new nlobjSearchFilter('custrecord_emproster_rosterstatus', null, 'is', 1),
      new nlobjSearchFilter('custrecord_emproster_eminactive',  null, 'is', 'F'),
      new nlobjSearchFilter('custrecord_emproster_ocostcenter', null, 'is', ROSTER_COST_CENTER_ID),
      new nlobjSearchFilter('custrecord_emproster_salesregion', null, 'is', ROSTER_SALES_REGION_ID),
    ];
  }

  function mapRosterResult(r, sourceLabel) {
    return {
      employeeId:    r.getValue('internalid'),
      employee:      r.getValue('name'),
      manager:       sourceLabel || '',
      availability:  (r.getText('custrecord_emproster_avail') || '').toLowerCase(),
      availNotes:    readAvailabilityNotes(r, null),
      availRes:      readManagerAvailRes(r, null),
      location:      extractShortLocation(r.getText('custrecord_emproster_olocation')),
      region:        readSalesSubregion(r, null),
      vertical:      readVerticalAmo(r, null),
      tier:          (r.getText('custrecord_emproster_sales_tier') || '').replace('Solution Consultant - ', ''),
      employeeRecId: r.getValue('custrecord_emproster_emp') || '',
      email:         '',   // filled in by getEmployeeEmails()
      weightedScore: 0,
      stackRank:     0,
      skills:        {},
      industryRating: 0,
      industryScore:  0,
    };
  }

  function rosterNameVariants(token) {
    const raw = String(token || '').trim();
    const variants = [];
    if (!raw) return variants;
    variants.push(raw);
    if (!raw.includes(',')) {
      const parts = raw.split(/\s+/).filter(Boolean);
      if (parts.length >= 2) variants.push(`${parts[parts.length - 1]}, ${parts.slice(0, -1).join(' ')}`);
    }
    return [...new Set(variants)];
  }

  function getAdditionalMyTeamRoster() {
    const tokens = getExtraTeamMemberTokens();
    if (!tokens.length) return [];
    const byId = {};
    const cols = getRosterSearchColumns();

    function addRows(rows, sourceLabel) {
      (rows || []).slice(0, 10).forEach(r => {
        const mapped = mapRosterResult(r, sourceLabel);
        if (mapped.employeeId) byId[mapped.employeeId] = mapped;
      });
    }

    function run(filters, sourceLabel) {
      try {
        addRows(nlapiSearchRecord('customrecord_emproster', null, filters, cols) || [], sourceLabel);
      } catch (e) {
        console.warn('[Staffing Helper] Additional My Team lookup failed:', sourceLabel, e.message || e);
      }
    }

    tokens.forEach(token => {
      const label = `Added: ${token}`;
      if (/^\d+$/.test(token)) {
        run([...activeRosterFilters(), new nlobjSearchFilter('internalid', null, 'is', token)], label);
        run([...activeRosterFilters(), new nlobjSearchFilter('custrecord_emproster_emp', null, 'is', token)], label);
      }
      rosterNameVariants(token).forEach(name => {
        run([...activeRosterFilters(), new nlobjSearchFilter('name', null, 'contains', name)], label);
      });
    });

    return Object.values(byId);
  }

  function getConfiguredManagerRosterRecords() {
    const tokens = getExtraTeamManagerTokens();
    if (!tokens.length) return [];
    const byId = {};
    const cols = [
      new nlobjSearchColumn('internalid'),
      new nlobjSearchColumn('name'),
      new nlobjSearchColumn('custrecord_emproster_emp'),
    ];

    function addManagers(rows, sourceLabel) {
      (rows || []).slice(0, 10).forEach(r => {
        const id = r.getValue('internalid');
        if (!id || byId[id]) return;
        byId[id] = {
          id,
          name: r.getValue('name') || sourceLabel || `Manager ${id}`,
        };
      });
    }

    function run(filters, sourceLabel) {
      try {
        addManagers(nlapiSearchRecord('customrecord_emproster', null, filters, cols) || [], sourceLabel);
      } catch (e) {
        console.warn('[Staffing Helper] Additional Manager lookup failed:', sourceLabel, e.message || e);
      }
    }

    tokens.forEach(token => {
      const label = `Manager: ${token}`;
      if (/^\d+$/.test(token)) {
        run([...activeRosterFilters(), new nlobjSearchFilter('internalid', null, 'is', token)], label);
        run([...activeRosterFilters(), new nlobjSearchFilter('custrecord_emproster_emp', null, 'is', token)], label);
      }
      rosterNameVariants(token).forEach(name => {
        run([...activeRosterFilters(), new nlobjSearchFilter('name', null, 'contains', name)], label);
      });
    });

    return Object.values(byId);
  }

  function getAdditionalManagerTeamsRoster() {
    const managers = getConfiguredManagerRosterRecords();
    if (!managers.length) return [];
    const byId = {};
    const cols = getRosterSearchColumns();

    managers.forEach(manager => {
      try {
        const rows = nlapiSearchRecord('customrecord_emproster', null, [
          new nlobjSearchFilter('custrecord_emproster_mgrroster', null, 'is', manager.id),
          ...activeRosterFilters(),
        ], cols) || [];
        rows.forEach(r => {
          const mapped = mapRosterResult(r, `Mgr: ${manager.name}`);
          if (mapped.employeeId && !byId[mapped.employeeId]) byId[mapped.employeeId] = mapped;
        });
      } catch (e) {
        console.warn('[Staffing Helper] Additional Manager team lookup failed:', manager.name, e.message || e);
      }
    });

    return Object.values(byId);
  }

  function getMyTeamRoster(empIds) {
    if (!empIds || !empIds.me) return [];
    try {
      const filters = [
        new nlobjSearchFilter('custrecord_emproster_mgrroster',  null, 'is', empIds.me),
        ...activeRosterFilters(),
      ];
      const cols = getRosterSearchColumns();
      const results = nlapiSearchRecord('customrecord_emproster', null, filters, cols);
      if (!results) return [];
      return results.map(r => mapRosterResult(r, ''));
    } catch (e) {
      console.error('[Staffing Helper] getMyTeamRoster error:', e);
      return [];
    }
  }

  /* ────────────────────────────────────────────────────────────────
     DATA CONSOLIDATION
  ──────────────────────────────────────────────────────────────── */

  function availRank(text) {
    switch ((text || '').toLowerCase()) {
      case 'green':  return 3;
      case 'yellow': return 2;
      case 'red':    return 1;
      default:       return 0;
    }
  }

  function isExcludedVertical(vertical) {
    const normalized = String(vertical || '').trim().toLowerCase();
    return EXCLUDED_VERTICALS.some(v => {
      const target = String(v).trim().toLowerCase();
      return normalized === target || (target === 'productivity' && normalized.includes(target));
    });
  }

  function consolidateData(skillRows, industryRows, sortKey, expectedSkillCount, matchOperator) {
    skillRows = skillRows || [];
    industryRows = industryRows || [];
    if (skillRows.length === 0 && industryRows.length === 0) return [];
    const byEmployee = {};
    for (const row of skillRows) {
      const key = row.employee;
      if (!byEmployee[key]) {
        byEmployee[key] = {
          employeeId:    row.employeeId,
          employee:      row.employee,
          manager:       row.manager,
          availability:  (row.availability || '').toLowerCase(),
          availNotes:    row.availNotes,
          availRes:      row.availRes,
          location:      extractShortLocation(row.location),
          region:        row.region,
          vertical:      row.vertical,
          tier:          (row.tier || '').replace('Solution Consultant - ', ''),
          salesteam:     row.salesteam || '',
          employeeRecId: row.employeeRecId || '',
          weightedScore: 0,
          skills:        {},
          matchedSkillKeys: {},
          matchedSkillCount: 0,
          requiredSkillCount: expectedSkillCount || 0,
          industryRating: 0,
          industryScore: 0,
          email:         '',
        };
      }
      const w = ratingCredit(row.ratingRaw);
      byEmployee[key].weightedScore += w;
      byEmployee[key].skills[row.skill] = row.ratingRaw;
      byEmployee[key].matchedSkillKeys[row.skill] = true;
    }

    if (industryRows && industryRows.length > 0) {
      const indById = {};
      for (const r of industryRows) {
        indById[r.employeeId] = Math.max(indById[r.employeeId] || 0, Number(r.industryRating) || 0);
      }
      for (const r of industryRows) {
        const key = r.employee || r.employeeId;
        if (!byEmployee[key]) {
          byEmployee[key] = {
            employeeId:    r.employeeId,
            employee:      r.employee,
            manager:       '',
            availability:  '',
            availNotes:    '',
            availRes:      '',
            location:      '',
            region:        r.region || '',
            vertical:      r.vertical || '',
            tier:          '',
            salesteam:     r.salesteam || '',
            employeeRecId: r.employeeRecId || '',
            weightedScore: 0,
            skills:        {},
            matchedSkillKeys: {},
            matchedSkillCount: 0,
            requiredSkillCount: expectedSkillCount || 0,
            industryRating: 0,
            industryScore: 0,
            email:         '',
          };
        }
      }
      for (const emp of Object.values(byEmployee)) {
        emp.industryRating = indById[emp.employeeId] || 0;
        emp.industryScore = ratingCredit(emp.industryRating);
      }
    }

    const employees = Object.values(byEmployee);
    const hasIndustry = industryRows && industryRows.length > 0;
    const maxScore = Math.max((expectedSkillCount || 0) + (hasIndustry ? 1 : 0), 1);
    for (const e of employees) {
      e.matchedSkillCount = Object.keys(e.matchedSkillKeys || {}).length;
      delete e.matchedSkillKeys;
      const score = (e.weightedScore || 0) + (hasIndustry ? ratingCredit(e.industryRating) : 0);
      e.stackRank = parseFloat(((score / maxScore) * 100).toFixed(1));
    }

    const sortableEmployees = matchOperator === 'all'
      ? employees.filter(e => e.matchedSkillCount >= (expectedSkillCount || 0))
      : employees;

    sortableEmployees.sort((a, b) => {
      const criteria = buildSortCriteria(sortKey, hasIndustry);
      for (const [field, dir] of criteria) {
        let va = field === 'availRank' ? availRank(a.availability) : a[field];
        let vb = field === 'availRank' ? availRank(b.availability) : b[field];
        if (va === vb) continue;
        return dir === 'desc' ? vb - va : va - vb;
      }
      return 0;
    });
    return sortableEmployees;
  }

  function buildSortCriteria(sortKey, hasIndustry) {
    if (!hasIndustry) {
      if (sortKey === 'sia') return [['stackRank','desc'], ['availRank','desc']];
      return [['matchedSkillCount','desc'], ['stackRank','desc'], ['availRank','desc']];
    }
    switch (sortKey) {
      case 'isa': return [['industryScore','desc'],['matchedSkillCount','desc'], ['stackRank','desc'], ['availRank','desc']];
      case 'ais': return [['availRank','desc'],    ['industryScore','desc'], ['stackRank','desc']];
      case 'sia': return [['stackRank','desc'],    ['industryScore','desc'], ['availRank','desc']];
      default:    return [['industryScore','desc'],['availRank','desc'],     ['stackRank','desc']];
    }
  }

  function extractShortLocation(loc) {
    if (!loc) return '';
    const m = loc.match(/^[\w]+-[\w]+/i);
    return m ? m[0] : loc;
  }

  /* ────────────────────────────────────────────────────────────────
     RENDER RESULTS
  ──────────────────────────────────────────────────────────────── */

  function renderResults(employees, hasIndustry, empName, containerId, mode, page) {
    containerId = containerId || 'sc-results-area';
    mode        = mode        || 'direct';
    page        = Math.max(1, page || 1);
    const area  = document.getElementById(containerId);
    if (!employees || employees.length === 0) {
      area.innerHTML = '<div class="sc-status">No results found. Try adjusting your filters.</div>';
      return;
    }
    if (employees.some(e => e.recentLoad == null)) enrichRecentScrLoad(employees);

    SEARCH_RESULT_CACHE[containerId] = { employees, hasIndustry, empName, mode };
    const industrySelect = document.getElementById(mode === 'amo' ? 'sc-amo-industry' : 'sc-industry');
    const selectedIndustryLabel = industrySelect && industrySelect.selectedOptions && industrySelect.selectedOptions[0]
      ? industrySelect.selectedOptions[0].text
      : 'Industry';
    const shortIndustryLabel = selectedIndustryLabel.length > 34
      ? selectedIndustryLabel.slice(0, 31) + '...'
      : selectedIndustryLabel;
    const totalPages = Math.max(1, Math.ceil(employees.length / SEARCH_PAGE_SIZE));
    page = Math.min(page, totalPages);
    const startIndex = (page - 1) * SEARCH_PAGE_SIZE;
    const pageEmployees = employees.slice(startIndex, startIndex + SEARCH_PAGE_SIZE);

    const cards = pageEmployees.map(e => {
      const empId       = escAttr(e.employeeId);
      const empHrefId   = encodeURIComponent(String(e.employeeId || ''));
      const employee    = escHtml(e.employee);
      const employeeAtr = escAttr(e.employee);
      const email       = escAttr(e.email);
      const manager     = escHtml(e.manager);
      const managerAtr  = escAttr(e.manager);
      const vertical    = escHtml(e.vertical);
      const verticalAtr = escAttr(e.vertical);
      const tier        = escHtml(e.tier);
      const region      = escHtml(e.region);
      const location    = escHtml(e.location);
      const locationAtr = escAttr(e.location);
      const avail       = availabilityClass(e.availability);
      const availLabel  = availabilityLabel(e.availability);
      const stackRank   = Math.max(0, Math.min(100, Number(e.stackRank) || 0));
      const indRating   = Math.max(0, Math.min(4, Number(e.industryRating) || 0));
      const indLabel    = ratingLabel(indRating);
      const skillParts  = Object.entries(e.skills || {})
        .map(([s, r]) => {
          const skill = String(s || '');
          const shortSkill = skill.length > 20 ? skill.slice(0, 18) + '…' : skill;
          const skillLabel = ratingLabel(r);
          return `<span class="sc-skill-tag" title="${escAttr(skill)} - ${escAttr(skillLabel)}">${escHtml(shortSkill)} ${escHtml(skillLabel)}</span>`;
        });
      if (hasIndustry) {
        skillParts.unshift(`<span class="sc-skill-tag sc-industry-rating-tag" title="${escAttr(selectedIndustryLabel)} - ${escAttr(indLabel)}">${escHtml(shortIndustryLabel)} ${escHtml(indLabel)}</span>`);
      }
      const skillTags = skillParts.join('');

      const calTitle = e.email
        ? `Open calendar dashboard for ${e.employee} (${e.email})`
        : `Open calendar dashboard for ${e.employee}`;

      return `
        <div class="sc-result-card">
          <div class="sc-card-head">
            <label class="sc-card-select-label" title="Select for multi-calendar view">
              <input type="checkbox" class="sc-consultant-checkbox"
                data-empid="${empId}"
                data-email="${email}"
                data-empname="${employeeAtr}"
                data-manager="${managerAtr}"
                data-team="${verticalAtr}"
                data-location="${locationAtr}">
            </label>
            <div class="sc-card-name-block">
              <a class="sc-card-name"
                 href="/app/common/custom/custrecordentry.nl?rectype=1572&id=${empHrefId}"
                 target="_blank"
                 title="${employeeAtr}">${employee}</a>
              ${e.manager ? `<div class="sc-card-mgr">${manager}</div>` : ''}
              <div class="sc-card-badges">
                ${e.vertical ? `<span class="sc-attr-badge">${vertical}</span>` : ''}
                ${e.tier     ? `<span class="sc-attr-badge">${tier}</span>`     : ''}
                ${e.region   ? `<span class="sc-attr-badge">${region}</span>`   : ''}
                ${e.location ? `<span class="sc-attr-badge">${location}</span>` : ''}
                <span class="sc-load-badge">SCR Lst 7 dys ${Number(e.recentLoad || 0)}</span>
              </div>
            </div>
            <div class="sc-card-right">
              <span class="sc-avail-pill ${avail}" title="${avail}">
                <span class="sc-avail-dot ${avail}"></span>${availLabel}
              </span>
              <div class="sc-card-btn-row">
                <button class="sc-viewcal-btn"
                  data-email="${email}"
                  data-empname="${employeeAtr}"
                  data-manager="${managerAtr}"
                  data-vertical="${verticalAtr}"
                  data-location="${locationAtr}"
                  title="${escAttr(calTitle)}">📅 View Cal</button>
                <button class="${mode === 'amo' ? 'sc-amo-staff-btn' : 'sc-staff-btn'}"
                  data-empid="${empId}"
                  data-empname="${employeeAtr}"
                  title="Staff ${employeeAtr}">✔ Staff</button>
              </div>
            </div>
          </div>
          <div class="sc-card-body">
            ${e.availNotes ? `<div class="sc-card-avail-notes">${escHtml(e.availNotes)}${e.availRes ? `<div class="sc-card-avail-res">${escHtml(e.availRes)}</div>` : ''}</div>` : ''}
            ${skillTags    ? `<div class="sc-card-skills">${skillTags}</div>` : ''}
            <div class="sc-card-footer">
              <div class="sc-rank-inline">
                <span class="sc-rank-label">Rank</span>
                <div class="sc-rank-bar-bg">
                  <div class="sc-rank-bar-fill" style="width:${stackRank}%"></div>
                </div>
                <span class="sc-rank-pct">${stackRank}%</span>
              </div>
            </div>
          </div>
        </div>`;
    }).join('');

    const plural = employees.length === 1 ? '' : 's';
    const paginationHtml = totalPages > 1
      ? `<div class="sc-pagination">
          <button class="sc-page-btn" id="${containerId}-prev-page" ${page <= 1 ? 'disabled' : ''}>Prev</button>
          <span class="sc-page-label">Page ${page} of ${totalPages}</span>
          <button class="sc-page-btn" id="${containerId}-next-page" ${page >= totalPages ? 'disabled' : ''}>Next</button>
        </div>`
      : '';
    area.innerHTML = `
      <div class="sc-results-header">
        <span class="sc-results-count">${employees.length} result${plural} · showing ${startIndex + 1}-${startIndex + pageEmployees.length}</span>
        <button class="sc-viewall-cal-btn" id="${containerId}-viewall-cal-btn" title="Open calendar dashboard for all ${employees.length} consultant${plural}">
          📅 View All Calendars
        </button>
      </div>
      <div id="sc-cards-list">${cards}</div>
      ${paginationHtml}`;

    // Wire checkboxes (multi-select)
    wireCheckboxes(area);

    // Wire View All Calendars button (bulk — must originate from a click)
    document.getElementById(`${containerId}-viewall-cal-btn`).addEventListener('click', () => {
      openCalForAll(employees);
    });

    const prevBtn = document.getElementById(`${containerId}-prev-page`);
    const nextBtn = document.getElementById(`${containerId}-next-page`);
    if (prevBtn) prevBtn.addEventListener('click', () => renderResults(employees, hasIndustry, empName, containerId, mode, page - 1));
    if (nextBtn) nextBtn.addEventListener('click', () => renderResults(employees, hasIndustry, empName, containerId, mode, page + 1));

    // Wire per-card View Cal buttons (single consultant)
    area.querySelectorAll('.sc-viewcal-btn').forEach(btn => {
      btn.addEventListener('click', () => {
        openCalForOne({
          email:    btn.dataset.email    || '',
          employee: btn.dataset.empname  || '',
          manager:  btn.dataset.manager  || '',
          vertical: btn.dataset.vertical || '',
          location: btn.dataset.location || '',
        });
      });
    });

    // Wire Staff buttons (direct uses sc-staff-btn, amo uses sc-amo-staff-btn)
    const staffSelector = mode === 'amo' ? '.sc-amo-staff-btn' : '.sc-staff-btn';
    area.querySelectorAll(staffSelector).forEach(btn => {
      btn.addEventListener('click', () => {
        const scId   = btn.dataset.empid;
        const scName = btn.dataset.empname;
        if (mode === 'amo') {
          syncProductsToForm('sc-amo-products');
          staffSCWithDeliverable(scId, scName, empName, _hasLeadOnOpp);
        } else {
          syncProductsToForm('sc-products');
          staffSC(scId, scName, empName, _hasLeadOnOpp);
        }
      });
    });
  }

  /* ────────────────────────────────────────────────────────────────
     MY TEAM SECTION
  ──────────────────────────────────────────────────────────────── */

