  function loadMyTeam(empIds, empName) {
    const area = document.getElementById('sc-myteam-area');
    if (!area) return;
    area.innerHTML = '<div class="sc-status loading">Loading team…</div>';

    setTimeout(() => {
      try {
        const teamById = {};
        getMyTeamRoster(empIds).forEach(member => {
          if (member.employeeId) teamById[member.employeeId] = member;
        });
        getAdditionalMyTeamRoster().forEach(member => {
          if (member.employeeId) teamById[member.employeeId] = member;
        });
        getAdditionalManagerTeamsRoster().forEach(member => {
          if (member.employeeId && !teamById[member.employeeId]) teamById[member.employeeId] = member;
        });
        const team      = Object.values(teamById);
        const rosterIds = team.map(e => e.employeeId);
        MY_TEAM_ROSTER_IDS = new Set(rosterIds.map(id => String(id || '')).filter(Boolean));
        const emailMap  = getEmployeeEmails(rosterIds);
        team.forEach(e => { e.email = emailMap[e.employeeId] || ''; });

        // Sort: green → yellow → red/unknown, then alphabetically
        team.sort((a, b) => {
          const diff = availRank(b.availability) - availRank(a.availability);
          return diff !== 0 ? diff : a.employee.localeCompare(b.employee);
        });

        renderMyTeamCards(team, area, empName);
      } catch (err) {
        console.error('[Staffing Helper] loadMyTeam error:', err);
        area.innerHTML = `<div class="sc-error">Could not load team: ${escHtml(err.message || err)}</div>`;
      }
    }, 60);
  }

  /* ────────────────────────────────────────────────────────────────
     SEARCH ORCHESTRATION
  ──────────────────────────────────────────────────────────────── */

  function getMultiSelectValues(id) {
    const el = document.getElementById(id);
    if (!el) return [];
    return Array.from(el.selectedOptions).map(o => o.value).filter(Boolean);
  }

  function getMultiSelectTexts(id) {
    const el = document.getElementById(id);
    if (!el) return [];
    return Array.from(el.selectedOptions)
      .map(o => String(o.text || o.label || o.value || '').trim())
      .filter(Boolean);
  }

  function getCheckboxValue(id) {
    return Boolean(document.getElementById(id)?.checked);
  }

  function normalizeVerticalFilter(value) {
    return normalizeLoose(value);
  }

  function applySalesVerticalFilter(members, filterOpts) {
    const selected = (filterOpts && filterOpts.verticalText || [])
      .map(normalizeVerticalFilter)
      .filter(Boolean);
    if (!selected.length) return members || [];
    return (members || []).filter(member => {
      const vertical = normalizeVerticalFilter(member && member.vertical);
      if (!vertical) return false;
      return selected.some(target => vertical === target || vertical.includes(target) || target.includes(vertical));
    });
  }

  function getMyTeamRosterIdSet(empIds) {
    if (MY_TEAM_ROSTER_IDS && MY_TEAM_ROSTER_IDS.size) return MY_TEAM_ROSTER_IDS;
    const ids = new Set();
    document.querySelectorAll('#sc-myteam-area .sc-consultant-checkbox[data-empid]').forEach(cb => {
      const id = String(cb.dataset.empid || '').trim();
      if (id) ids.add(id);
    });
    if (!ids.size && empIds && empIds.me) {
      try {
        [
          ...getMyTeamRoster(empIds),
          ...getAdditionalMyTeamRoster(),
          ...getAdditionalManagerTeamsRoster(),
        ].forEach(member => {
          const id = String(member && member.employeeId || '').trim();
          if (id) ids.add(id);
        });
        if (ids.size) MY_TEAM_ROSTER_IDS = ids;
      } catch (e) {
        console.warn('[SCOUT] Could not build My Team search limit set:', e.message || e);
      }
    }
    return ids;
  }

  function applyMyTeamLimit(members, filterOpts, empIds) {
    if (!filterOpts || !filterOpts.limitToMyTeam) return members || [];
    const ids = getMyTeamRosterIdSet(empIds);
    if (!ids.size) return [];
    return (members || []).filter(member => ids.has(String(member && member.employeeId || '')));
  }

  function runSearch(empRec, empIds, empName) {
    const btn  = document.getElementById('sc-search-btn');
    const area = document.getElementById('sc-results-area');

    const selectedProducts = Array.from(
      document.getElementById('sc-product-skills').selectedOptions
    ).map(o => parseInt(o.value, 10)).slice(0, 4);

    const industryId = document.getElementById('sc-industry').value || null;
    const additionalSkillOpts = getAdditionalSkillOptions('sc');
    if (selectedProducts.length === 0 && !industryId && !hasAdditionalSkillFilters(additionalSkillOpts)) {
      area.innerHTML = '<div class="sc-error">Select at least one product skill, industry, or additional SC skill before searching.</div>';
      return;
    }

    const skillIds = getSelectedProductSkillIds('sc-product-skills');
    if (selectedProducts.length > 0 && skillIds.length === 0) {
      area.innerHTML = '<div class="sc-error">Selected product skill(s) have no skill matrix entries.</div>';
      return;
    }

    const filterOpts = {
      myTeam:   false,
      limitToMyTeam: getCheckboxValue('sc-filter-myteam'),
      vertical: getMultiSelectValues('sc-filter-vertical'),
      verticalText: getMultiSelectTexts('sc-filter-vertical'),
      tier:     [],
      region:   getMultiSelectValues('sc-filter-region'),
    };
    const sortKey = document.getElementById('sc-filter-sort').value || 'isa';
    const matchOperator = document.getElementById('sc-filter-operator').value || 'any';

    btn.disabled = true;
    area.innerHTML = '<div class="sc-status loading">Searching — this may take a few seconds…</div>';

    setTimeout(() => {
      try {
        const allSkillRows    = skillIds.length ? getSkillData(skillIds, empRec, empIds, filterOpts) : [];
        const skillRows       = allSkillRows.filter(r => !isExcludedVertical(r.vertical));
        const allIndustryRows = industryId ? getIndustryData(industryId, empRec, empIds, filterOpts) : [];
        const industryRows    = allIndustryRows.filter(r => !isExcludedVertical(r.vertical));
        let consolidated      = consolidateData(skillRows, industryRows, sortKey, skillIds.length, matchOperator);
        if (!consolidated.length && hasAdditionalSkillFilters(additionalSkillOpts) && !skillIds.length && !industryId) {
          consolidated = getRosterCandidates(empRec, empIds, filterOpts, 'direct');
        }
        consolidated          = applyAdditionalSkillFilters(consolidated, additionalSkillOpts);
        enrichMembersWithRosterData(consolidated);
        consolidated = consolidated.filter(e => !isExcludedVertical(e.vertical));
        consolidated = applyMyTeamLimit(consolidated, filterOpts, empIds);

        // Fetch emails for View Cal buttons
        const rosterIds = [...new Set(consolidated.map(e => e.employeeId))];
        const emailMap  = getEmployeeEmails(rosterIds);
        consolidated.forEach(e => { e.email = emailMap[e.employeeId] || ''; });

        renderResults(consolidated, Boolean(industryId && industryRows.length), empName);
      } catch (err) {
        console.error('[Staffing Helper] Search error:', err);
        area.innerHTML = `<div class="sc-error">Search error: ${escHtml(err.message || err)}</div>`;
      } finally {
        btn.disabled = false;
      }
    }, 60);
  }

  /**
   * Search for AMO SCs using the same skill/industry data, but:
   * - No team/region filter in the base query (amoBaseFilters)
   * - Post-filter: salesteam text = 'AMO', exclude SDT and TCOE verticals
   */
  function runAmoSearch(empRec, empIds, empName) {
    const btn  = document.getElementById('sc-amo-search-btn');
    const area = document.getElementById('sc-amo-results-area');

    const selectedProducts = Array.from(
      document.getElementById('sc-amo-product-skills').selectedOptions
    ).map(o => parseInt(o.value, 10)).slice(0, 4);

    const industryId = document.getElementById('sc-amo-industry').value || null;
    const additionalSkillOpts = getAdditionalSkillOptions('sc-amo');
    if (selectedProducts.length === 0 && !industryId && !hasAdditionalSkillFilters(additionalSkillOpts)) {
      area.innerHTML = '<div class="sc-error">Select at least one product skill, industry, or additional SC skill before searching.</div>';
      return;
    }

    const skillIds = getSelectedProductSkillIds('sc-amo-product-skills');
    if (selectedProducts.length > 0 && skillIds.length === 0) {
      area.innerHTML = '<div class="sc-error">Selected product skill(s) have no skill matrix entries.</div>';
      return;
    }

    const filterOpts = {
      myTeam:   false,
      limitToMyTeam: getCheckboxValue('sc-amo-filter-myteam'),
      vertical: [],   // AMO sales vertical is filtered by display text after search.
      verticalText: getMultiSelectTexts('sc-amo-filter-vertical'),
      tier:     [],
      region:   getMultiSelectValues('sc-amo-filter-region'),
    };
    const sortKey = document.getElementById('sc-amo-filter-sort').value || 'isa';
    const matchOperator = document.getElementById('sc-amo-filter-operator').value || 'any';

    btn.disabled = true;
    area.innerHTML = '<div class="sc-status loading">Searching AMO SCs — this may take a few seconds…</div>';

    setTimeout(() => {
      try {
        // Build AMO skill filter using amoBaseFilters (no team/region constraint)
        const join = 'custrecord_ssm_skill_employee';
        let skillRows = [];
        if (skillIds.length) {
          const amoSkillFilters = [
            new nlobjSearchFilter('custrecord_ssm_skill_entry', null, 'anyof', skillIds),
            ...amoBaseFilters(join),
            ...uiFilters(filterOpts, join, empIds),
          ];
          const skillCols = [
            new nlobjSearchColumn('custrecord_ssm_skill_employee'),
            new nlobjSearchColumn('internalid',                           join),
            new nlobjSearchColumn('custrecord_emproster_avail',           join),
            ...availabilityNotesColumns(join),
            ...managerAvailResColumns(join),
            new nlobjSearchColumn('custrecord_emproster_mgrroster',       join),
            new nlobjSearchColumn('custrecord_emproster_olocation',       join),
            ...salesSubregionColumns(join),
            ...verticalAmoColumns(join),
            new nlobjSearchColumn('custrecord_emproster_sales_tier',      join),
            new nlobjSearchColumn('custrecord_emproster_salesteam',       join),
            new nlobjSearchColumn('custrecord_emproster_emp',             join),
            new nlobjSearchColumn('custrecord_ssm_skill_entry'),
            new nlobjSearchColumn('custrecord_ssm_skill_rating'),
          ];
          const rawSkill = nlapiSearchRecord('customrecord_ssm_entry', null, amoSkillFilters, skillCols) || [];
          skillRows = rawSkill
            .map(r => ({
              employeeId:   r.getValue('internalid', join),
              employee:     r.getText('custrecord_ssm_skill_employee'),
              manager:      r.getText('custrecord_emproster_mgrroster', join),
              availability: r.getText('custrecord_emproster_avail', join),
              availNotes:   readAvailabilityNotes(r, join),
              availRes:     readManagerAvailRes(r, join),
              location:     r.getText('custrecord_emproster_olocation', join),
              region:       readSalesSubregion(r, join),
              vertical:     readVerticalAmo(r, join),
              tier:         r.getText('custrecord_emproster_sales_tier', join),
              salesteam:    r.getText('custrecord_emproster_salesteam', join),
              employeeRecId: r.getValue('custrecord_emproster_emp', join) || '',
              skill:        r.getText('custrecord_ssm_skill_entry'),
              ratingRaw:    parseRatingValue(r.getText('custrecord_ssm_skill_rating') || r.getValue('custrecord_ssm_skill_rating')),
            }))
            .filter(r => r.salesteam === 'AMO' && !isExcludedVertical(r.vertical) && parseInt(r.ratingRaw, 10) >= 1);
          skillRows = applySalesVerticalFilter(skillRows, filterOpts);
        }

        // Industry data for AMO
        let industryRows = [];
        if (industryId) {
          const indJoin = 'custrecord_sr_ind_rating_employee';
          const industryIds = resolveIndustrySearchIds(industryId);
          if (industryIds.length) {
            const amoIndFilters = [
              new nlobjSearchFilter('custrecord_sr_ind_rating_subindustry', null, 'anyof', industryIds),
              ...amoBaseFilters(indJoin),
              ...uiFilters(filterOpts, indJoin, empIds),
            ];
            const indCols = [
              new nlobjSearchColumn('custrecord_sr_ind_rating_employee'),
              new nlobjSearchColumn('internalid',          indJoin),
              new nlobjSearchColumn('custrecord_sr_ind_rating'),
              new nlobjSearchColumn('custrecord_emproster_salesteam', indJoin),
              ...verticalAmoColumns(indJoin),
              new nlobjSearchColumn('custrecord_emproster_emp', indJoin),
            ];
            const rawInd = nlapiSearchRecord('customrecord_sr_industry_rating_entry', null, amoIndFilters, indCols) || [];
            industryRows = rawInd
              .map(r => ({
                employeeId:     r.getValue('internalid', indJoin),
                employee:       r.getText('custrecord_sr_ind_rating_employee'),
                employeeRecId:  r.getValue('custrecord_emproster_emp', indJoin) || '',
                salesteam:      r.getText('custrecord_emproster_salesteam', indJoin),
                vertical:       readVerticalAmo(r, indJoin),
                industryRating: parseRatingValue(r.getText('custrecord_sr_ind_rating') || r.getValue('custrecord_sr_ind_rating')),
              }))
              .filter(r => r.salesteam === 'AMO' && !isExcludedVertical(r.vertical) && parseInt(r.industryRating, 10) >= 1);
            industryRows = applySalesVerticalFilter(industryRows, filterOpts);
          }
        }

        let consolidated = consolidateData(skillRows, industryRows, sortKey, skillIds.length, matchOperator);
        if (!consolidated.length && hasAdditionalSkillFilters(additionalSkillOpts) && !skillIds.length && !industryId) {
          consolidated = getRosterCandidates(empRec, empIds, filterOpts, 'amo');
        }
        consolidated = applyAdditionalSkillFilters(consolidated, additionalSkillOpts);
        enrichMembersWithRosterData(consolidated);
        consolidated = consolidated.filter(e => !isExcludedVertical(e.vertical));
        consolidated = applySalesVerticalFilter(consolidated, filterOpts);
        consolidated = applyMyTeamLimit(consolidated, filterOpts, empIds);

        const rosterIds = [...new Set(consolidated.map(e => e.employeeId))];
        const emailMap  = getEmployeeEmails(rosterIds);
        consolidated.forEach(e => { e.email = emailMap[e.employeeId] || ''; });

        renderResults(consolidated, Boolean(industryId && industryRows.length), empName,
                      'sc-amo-results-area', 'amo');
      } catch (err) {
        console.error('[Staffing Helper] AMO Search error:', err);
        area.innerHTML = `<div class="sc-error">Search error: ${escHtml(err.message || err)}</div>`;
      } finally {
        btn.disabled = false;
      }
    }, 60);
  }

  /* ────────────────────────────────────────────────────────────────
     MODULE DETECTION
     Scans Request Details text against known module keywords and
     maps them to product IDs in the product <select> elements.
  ──────────────────────────────────────────────────────────────── */

  // Map of regex → { productId, label }
  // Product IDs match the <option value="..."> in buildProductOptions()
  const PRODUCT_KEYWORD_MAP = [
    { pattern: /\bWMS\b/i,                          productId: '50', label: 'WMS' },
    { pattern: /\bwarehouse\s*management\b/i,        productId: '50', label: 'WMS' },
    { pattern: /\bFSM\b/i,                           productId: '19', label: 'Field Service' },
    { pattern: /\bfield\s*service\b/i,               productId: '19', label: 'Field Service' },
    { pattern: /\bOpenAir\b/i,                       productId: '29', label: 'OpenAir' },
    { pattern: /\bPSA\b/i,                           productId: '29', label: 'OpenAir / PSA' },
    { pattern: /\bWIP\b/i,                           productId: '49', label: 'WIP' },
    { pattern: /\bwork\s*in\s*progress\b/i,          productId: '49', label: 'WIP' },
    { pattern: /\bEPM\b/i,                           productId: '12', label: 'EPM' },
    { pattern: /\bplanning\s*&?\s*budgeting\b/i,     productId: '16', label: 'EPM NSPB' },
    { pattern: /\bCRM\b/i,                           productId: 'crm', label: 'CRM', skillOnly: true },
    { pattern: /\bSRP\b/i,                           productId: '45', label: 'SuiteProjects' },
    { pattern: /\bservices\s*resource\s*planning\b/i,productId: '45', label: 'SuiteProjects' },
    { pattern: /\bcommerce\b/i,                      productId: '41', label: 'SuiteCommerce' },
    { pattern: /\bSuiteCommerce\b/i,                 productId: '41', label: 'SuiteCommerce' },
    { pattern: /\bManufacturing\b/i,                 productId: '51', label: 'Work Orders & Assemblies' },
    { pattern: /\bMRP\b/i,                           productId: '51', label: 'Work Orders & Assemblies' },
    { pattern: /\bAdvanced\s*Manufacturing\b/i,      productId: '51', label: 'Work Orders & Assemblies' },
    { pattern: /\bInventory\b/i,                     productId: '23', label: 'Inventory' },
    { pattern: /\bRevenue\s*Recognition\b/i,         productId: '35', label: 'Rev Rec' },
    { pattern: /\bRev\s*Rec\b/i,                     productId: '35', label: 'Rev Rec' },
    { pattern: /\bBanking\b/i,                       productId: '2',  label: 'Banking' },
    { pattern: /\bNS\s*Finance\b/i,                  productId: '20', label: 'Finance' },
    { pattern: /\bFinancial\s*Management\b/i,         productId: '20', label: 'Finance' },
    { pattern: /\bHCM\b/i,                           productId: '44', label: 'SuitePeople' },
    { pattern: /\bHuman\s*Capital\b/i,               productId: '44', label: 'SuitePeople' },
    { pattern: /\bPayroll\b/i,                       productId: '44', label: 'SuitePeople' },
    { pattern: /\bSuiteAnalytics\b/i,                productId: '38', label: 'Analytics' },
    { pattern: /\bSuiteBI\b/i,                       productId: '38', label: 'Analytics' },
    { pattern: /\bOrder\s*Management\b/i,            productId: '4',  label: 'Order Mgmt' },
    { pattern: /\bOMS\b/i,                           productId: '4',  label: 'OMS' },
    { pattern: /\bSubscription\b/i,                  productId: '39', label: 'Subscription Billing' },
    { pattern: /\bSuiteBilling\b/i,                  productId: '39', label: 'SuiteBilling' },
    { pattern: /\bBill\s*Capture\b/i,                productId: '6',  label: 'Bill Capture' },
    { pattern: /\bProcurement\b/i,                   productId: '32', label: 'Procurement' },
    { pattern: /\bPurchase\s*Order\b/i,              productId: '32', label: 'Procurement' },
    { pattern: /\bFixed\s*Assets\b/i,                productId: '21', label: 'Fixed Assets' },
    { pattern: /\bProject\s*Management\b/i,          productId: '45', label: 'Project Mgmt' },
    { pattern: /\bSuiteProjects\b/i,                 productId: '45', label: 'SuiteProjects' },
  ];

  let _opportunityDetectionTextCache = null;

  function textHasScPlusLicenseSignal(text) {
    const value = String(text || '');
    if (!value) return false;
    return /\bSC\s*(?:\+|plus)\s*(?:licenses?|licences?|lic\.?|seats?|users?)?\b/i.test(value) ||
      /\bSuiteConsulting\s*(?:\+|plus)\s*(?:licenses?|licences?|seats?|users?)?\b/i.test(value);
  }

  function getOpportunityDetectionText() {
    if (_opportunityDetectionTextCache != null) return _opportunityDetectionTextCache;
    const chunks = [];
    let oppId = '';
    try {
      oppId = (readFormFieldValue(SCR_FIELD_OPP) || '').trim();
    } catch (e) { /* ignore */ }
    if (!oppId || !/^\d+$/.test(oppId)) {
      _opportunityDetectionTextCache = '';
      return _opportunityDetectionTextCache;
    }

    try {
      const opp = nlapiLoadRecord('opportunity', oppId);
      if (opp) {
        ['title', 'memo', 'tranid'].forEach(fieldId => {
          try { chunks.push(opp.getFieldValue(fieldId) || ''); } catch (e) { /* field may not exist */ }
          try { chunks.push(opp.getFieldText(fieldId) || ''); } catch (e) { /* field may not expose text */ }
        });

        try {
          const lineCount = Math.min(Number(opp.getLineItemCount('item') || 0), 100);
          for (let i = 1; i <= lineCount; i++) {
            try { chunks.push(opp.getLineItemText('item', 'item', i) || ''); } catch (e) { /* ignore */ }
            try { chunks.push(opp.getLineItemValue('item', 'description', i) || ''); } catch (e) { /* ignore */ }
          }
        } catch (e) { /* opportunity may not expose item lines */ }
      }
    } catch (e) {
      console.warn('[SCOUT] Opportunity text scan failed:', e.message || e);
    }

    _opportunityDetectionTextCache = chunks.join('\n');
    return _opportunityDetectionTextCache;
  }

  function visiblePageHasScPlusLicenseSignal() {
    try {
      return getAccessibleDocuments().some(doc => textHasScPlusLicenseSignal(doc.body && doc.body.innerText));
    } catch (e) {
      return false;
    }
  }

  function hasScPlusLicenseSignal() {
    return textHasScPlusLicenseSignal(getRequestDetails()) ||
      textHasScPlusLicenseSignal(readFormTextField('custrecord_screq_details')) ||
      textHasScPlusLicenseSignal(getOpportunityDetectionText()) ||
      visiblePageHasScPlusLicenseSignal();
  }

  function applyAmoDeliverableSuggestionFromRequest() {
    const picker = document.getElementById('sc-amo-deliverable');
    if (!picker || picker.value) return false;
    if (!hasScPlusLicenseSignal()) return false;
    const platform = matchPickerOption(picker, 'Platform');
    if (!platform) return false;
    picker.value = platform.value;
    picker.dataset.scSuggested = 'sc-plus-platform';
    return true;
  }

  /**
   * Parse the SCR Request Details text and return unique matched products.
   * Returns array of { productId, label } (deduped by productId, max 4).
   */
  function parseRequestDetailsForProducts() {
    let text = '';
    try {
      text = nlapiGetFieldValue('custrecord_screq_details') || '';
    } catch (e) {
      try {
        const el = document.getElementById('custrecord_screq_details');
        if (el) text = el.value || el.textContent || '';
      } catch (e2) { /* ignore */ }
    }
    if (!text) return [];

    const seen = new Set();
    const matches = [];
    for (const entry of PRODUCT_KEYWORD_MAP) {
      if (entry.pattern.test(text) && !seen.has(entry.productId)) {
        seen.add(entry.productId);
        matches.push({ productId: entry.productId, label: entry.label, skillOnly: Boolean(entry.skillOnly) });
        if (matches.length >= 4) break;  // cap at 4 suggestions
      }
    }
    return matches;
  }

  /**
   * Render the module insights chips in the given tab's insights card.
   * @param {string} tabId  'direct' or 'amo'
   */
  function updateRequestInsights(tabId) {
    try {
      const isAmo      = tabId === 'amo';
      const cardId     = isAmo ? 'sc-amo-insights-card' : 'sc-insights-card';
      const chipsId    = isAmo ? 'sc-amo-insights-chips' : 'sc-insights-chips';
      const selectId   = isAmo ? 'sc-amo-products'       : 'sc-products';
      const skillSelectId = isAmo ? 'sc-amo-product-skills' : 'sc-product-skills';

      const card  = document.getElementById(cardId);
      const chips = document.getElementById(chipsId);
      const sel   = document.getElementById(selectId);
      const skillSel = document.getElementById(skillSelectId);
      if (!card || !chips || !sel) return;

      const matches = parseRequestDetailsForProducts();
      if (!matches.length) {
        card.style.display = 'none';
        return;
      }

      card.style.display = 'block';
      chips.innerHTML = '';

      matches.forEach(function (m) {
        const chip = document.createElement('button');
        chip.type = 'button';
        chip.className = 'sc-insight-chip';
        chip.textContent = m.label;
        chip.title = m.skillOnly ? 'Product skill: ' + m.label : 'Product ID: ' + m.productId;

        // Mark as already-selected if product is currently chosen
        const opt = findHelperProductOption(sel, m.productId, m.label);
        const skillOpt = findHelperProductOption(skillSel, m.productId, m.label);
        if ((opt && opt.selected) || (skillOpt && skillOpt.selected)) chip.classList.add('selected');

        chip.addEventListener('click', function () {
          // Count currently selected options
          const currentlySelected = Array.from(sel.options).filter(o => o.selected).length;
          if (opt) {
            if (opt.selected) {
              opt.selected = false;
              chip.classList.remove('selected');
            } else {
              if (currentlySelected >= 4) {
                // Deselect the first selected option to make room
                const firstSel = Array.from(sel.options).find(o => o.selected);
                if (firstSel) firstSel.selected = false;
                // Update other chips' states
                chips.querySelectorAll('.sc-insight-chip').forEach(function (c) {
                  const cOpt = findHelperProductOption(sel, c.title.replace('Product ID: ', ''), c.textContent || '');
                  if (cOpt && !cOpt.selected) c.classList.remove('selected');
                });
              }
              opt.selected = true;
              chip.classList.add('selected');
              if (skillOpt && !skillOpt.selected) {
                const selectedSkills = Array.from(skillSel.options).filter(o => o.selected);
                if (selectedSkills.length >= 4) selectedSkills[0].selected = false;
                skillOpt.selected = true;
                skillSel.dispatchEvent(new Event('change', { bubbles: true }));
              }
            }
            // Trigger change event so the product filter badge updates
            sel.dispatchEvent(new Event('change', { bubbles: true }));
          } else if (skillOpt) {
            if (skillOpt.selected) {
              skillOpt.selected = false;
              chip.classList.remove('selected');
            } else {
              const selectedSkills = Array.from(skillSel.options).filter(o => o.selected);
              if (selectedSkills.length >= 4) selectedSkills[0].selected = false;
              skillOpt.selected = true;
              chip.classList.add('selected');
            }
            skillSel.dispatchEvent(new Event('change', { bubbles: true }));
          }
        });

        chips.appendChild(chip);
      });
    } catch (e) { /* ignore */ }
  }

  /* ────────────────────────────────────────────────────────────────
     STAFFING CONTEXT — reads SCR + company data to populate the
     Request Context card shown above My Team.
  ──────────────────────────────────────────────────────────────── */

  function escHtml(str) {
    return String(str || '')
      .replace(/&/g, '&amp;').replace(/</g, '&lt;')
      .replace(/>/g, '&gt;').replace(/"/g, '&quot;');
  }

  function escAttr(str) {
    return escHtml(str).replace(/'/g, '&#39;');
  }

  function availabilityClass(raw) {
    const v = String(raw || '').trim().toLowerCase();
    return /^(green|yellow|red)$/.test(v) ? v : 'unknown';
  }

  function availabilityLabel(raw) {
    const v = availabilityClass(raw);
    return v.charAt(0).toUpperCase() + v.slice(1);
  }

  /**
   * Scan request details text for patterns indicating a specific SC was requested.
   * Returns the SC name string or null.
   */
  // Prepositions/conjunctions/qualifiers that may appear after a name
  // (e.g. "Quinn Dagley For Continuity") — stop trimming here.
  var SC_NAME_STOP = /^(for|with|the|a|an|and|but|or|of|to|in|on|at|by|from|as|per|re|about|due|via|if|possible|available|ideally|preferably|please|thanks|thank|because|since|who|which|when|where)$/i;

  function trimScName(raw) {
    if (!raw) return '';
    var head = String(raw || '')
      .replace(/[“”]/g, '"')
      .replace(/[‘’]/g, "'")
      .split(/\s+[-–—]\s+|[-–—]{2,}|[.;,\n\r]|(?:\s+\()\s*/)[0]
      .trim();
    var words = head.split(/\s+/);
    var out = [];
    for (var i = 0; i < words.length; i++) {
      if (/^[-–—:]+$/.test(words[i])) break;
      if (SC_NAME_STOP.test(words[i])) break;
      out.push(words[i]);
    }
    // Require at least First + Last (2 words) to be a valid name
    return out.length >= 2 ? out.join(' ') : '';
  }

  function normalizeRequestedName(raw, allowLowercase) {
    const name = trimScName(raw);
    if (!name) return '';
    const words = name.split(/\s+/);
    const hasProperCase = words.every(w => /^[A-ZÁÉÍÓÚÄËÏÖÜ]/.test(w));
    if (!hasProperCase && !allowLowercase) return '';
    if (hasProperCase) return name;
    return words
      .map(w => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase())
      .join(' ');
  }

  function parseRequestedSC(text) {
    if (!text) return null;
    // NAME must be 2+ words. Lowercase names are only accepted after explicit tagging/request phrases.
    const NAME = '([A-Za-záéíóúäëïöüÁÉÍÓÚÄËÏÖÜ\'-]+(?:\\s+[A-Za-záéíóúäëïöüÁÉÍÓÚÄËÏÖÜ\'-]+){1,3})';
    const patterns = [
      // "Requested SC: Ben Shimota" / "Request SC: Ben Shimota"
      { re: new RegExp('requested?\\s+sc\\s*[:\\-]\\s*' + NAME, 'i'), allowLowercase: true },
      // "Requesting SC: Ben Shimota" (with sc label)
      { re: new RegExp('requesting\\s+sc\\s*[:\\-]?\\s*' + NAME, 'i'), allowLowercase: true },
      // "Requesting Ben Shimota" (verb form, no sc/colon — action word makes false pos. unlikely)
      { re: new RegExp('requesting\\s+' + NAME, 'i'), allowLowercase: false },
      // "Previously worked with Melanie Igel and think she would be a good fit"
      { re: new RegExp('previously\\s+worked\\s+with\\s+' + NAME, 'i'), allowLowercase: false },
      // "Working with Ron Traum for NSIP ecommerce integration"
      { re: new RegExp('\\bworking\\s+with\\s+' + NAME, 'i'), allowLowercase: false },
      // "Hoping we can work with Mark Newkirk on this one"
      { re: new RegExp('\\bhoping\\s+(?:we\\s+can\\s+)?work\\s+with\\s+' + NAME, 'i'), allowLowercase: false },
      // "Andrew Kravet is available and coordinated with him on this, Please staff"
      { re: new RegExp(NAME + '\\s+is\\s+available[^.\\n\\r]{0,160}\\bplease\\s+staff\\b', 'i'), allowLowercase: false },
      // "Looking to get Corey Tenanes assigned here if possible"
      { re: new RegExp('\\blooking\\s+to\\s+get\\s+' + NAME + '\\s+assigned\\b', 'i'), allowLowercase: false },
      // "Melanie Igel would be a good fit"
      { re: new RegExp(NAME + '\\s+(?:would\\s+be|is)\\s+a\\s+good\\s+fit', 'i'), allowLowercase: false },
      // "Please use / assign / assign to / get / tag Austin Schaub"
      { re: new RegExp('please\\s+(?:use|assign|request|get|tag)\\s+(?:to\\s+)?' + NAME, 'i'), allowLowercase: true },
      // "Assign to Quinn Dagley"
      { re: new RegExp('\\bassign\\s+to\\s+' + NAME, 'i'), allowLowercase: true },
      // "Tag Elaine Smith"
      { re: new RegExp('\\btag\\s+' + NAME, 'i'), allowLowercase: true },
      // "Preferred SC: Name" / "Prefer SC: Name" — require "sc" to avoid "prefer Standard SOW"
      { re: new RegExp('prefer(?:red|ring)?\\s+sc\\s*[:\\-]?\\s*' + NAME, 'i'), allowLowercase: true },
      // "Would like to work with / Would like Michael Anderson"
      { re: new RegExp('would\\s+like\\s+(?:to\\s+work\\s+with\\s+)?' + NAME, 'i'), allowLowercase: false },
      // NS form prompt: "Is there a specific SC … why? Austin Schaub"
      { re: new RegExp('specific\\s+sc[^?]*\\?\\s*' + NAME, 'i'), allowLowercase: true },
    ];
    for (const pat of patterns) {
      const m = text.match(pat.re);
      if (m && m[1]) {
        const name = normalizeRequestedName(m[1], pat.allowLowercase);
        if (name) return name;
      }
    }
    return null;
  }

  function resolveIndustryFamily(subIndustryId, industryId) {
    if (subIndustryId && INDUSTRY_FAMILY_MAP[Number(subIndustryId)]) {
      return INDUSTRY_FAMILY_MAP[Number(subIndustryId)];
    }
    if (industryId && INDUSTRY_FAMILY_BY_INDUSTRY_ID[Number(industryId)]) {
      return INDUSTRY_FAMILY_BY_INDUSTRY_ID[Number(industryId)];
    }
    return '';
  }

  /* ── Requested SC roster lookup ─────────────────────────────────── */

  function cloneRosterLookupResult(result) {
    return {
      ...result,
      members: (result.members || []).map(m => ({ ...m })),
    };
  }

  function rosterLookupCacheKey(value) {
    return String(value || '').trim().toLowerCase();
  }

  const REQUESTED_SC_NICKNAMES = {
    pat: ['patrick', 'patricia'],
    mike: ['michael'],
    michael: ['mike'],
    tom: ['thomas'],
    thomas: ['tom'],
    bob: ['robert'],
    robert: ['bob'],
    dave: ['david'],
    david: ['dave'],
    dan: ['daniel'],
    daniel: ['dan'],
    alex: ['alexander', 'alexandra'],
  };

  function normalizeRequestedNameTokens(value) {
    return normalizeLoose(String(value || '').replace(/['’]/g, '')).split(/\s+/).filter(Boolean);
  }

  function firstNameMatchesRequested(memberFirst, requestedFirst) {
    if (!memberFirst || !requestedFirst) return false;
    if (memberFirst === requestedFirst) return true;
    const requestedAliases = REQUESTED_SC_NICKNAMES[requestedFirst] || [];
    const memberAliases = REQUESTED_SC_NICKNAMES[memberFirst] || [];
    return requestedAliases.includes(memberFirst) || memberAliases.includes(requestedFirst);
  }

  function requestedRosterSearchTerms(fullName) {
    const parts = String(fullName || '').trim().split(/\s+/).filter(Boolean);
    const last = parts.length > 1 ? parts[parts.length - 1] : (parts[0] || '');
    const terms = [last];
    const compact = last.replace(/[^A-Za-z0-9]/g, '');
    if (compact && compact !== last) terms.push(compact);
    return [...new Set(terms.filter(Boolean))];
  }

  function requestedRosterMemberMatches(member, requestedName) {
    const memberTokens = normalizeRequestedNameTokens(member && member.employee);
    const requestTokens = normalizeRequestedNameTokens(requestedName);
    if (memberTokens.length < 2 || requestTokens.length < 2) return false;

    const reqFirst = requestTokens[0];
    const reqLast  = requestTokens[requestTokens.length - 1];
    if (!reqFirst || !reqLast) return false;

    // Support both "First Last" and NetSuite-style "Last, First" roster names.
    if (firstNameMatchesRequested(memberTokens[0], reqFirst) && memberTokens.indexOf(reqLast) > 0) return true;
    if (memberTokens[0] === reqLast && memberTokens.slice(1).some(token => firstNameMatchesRequested(token, reqFirst))) return true;

    return memberTokens.join(' ') === requestTokens.join(' ');
  }

  function rosterMemberFromRosterSearch(r) {
    return {
      employeeId:   r.getValue('internalid'),
      employee:     r.getValue('name') || '',
      manager:      r.getText('custrecord_emproster_mgrroster') || '',
      availability: (r.getText('custrecord_emproster_avail') || '').toLowerCase(),
      availNotes:   readAvailabilityNotes(r, null),
      availRes:     readManagerAvailRes(r, null),
      location:     extractShortLocation(r.getText('custrecord_emproster_olocation')),
      region:       readSalesSubregion(r, null),
      vertical:     readVerticalAmo(r, null),
      tier:         (r.getText('custrecord_emproster_sales_tier') || '').replace('Solution Consultant - ', ''),
      salesteam:    r.getText('custrecord_emproster_salesteam') || '',
      employeeRecId: r.getValue('custrecord_emproster_emp') || '',
      email:        r.getValue('email', 'custrecord_emproster_emp') || '',
    };
  }

  function scNameToneClass(member) {
    return /amo/i.test(member && member.salesteam ? member.salesteam : '')
      ? 'sc-card-name-amo'
      : 'sc-card-name-direct';
  }

  function searchRosterByName(searchTerm) {
    const filters = [
      new nlobjSearchFilter('name', null, 'contains', searchTerm),
      new nlobjSearchFilter('custrecord_emproster_rosterstatus', null, 'is', 1),
      new nlobjSearchFilter('custrecord_emproster_eminactive', null, 'is', 'F'),
      new nlobjSearchFilter('custrecord_emproster_ocostcenter', null, 'is', ROSTER_COST_CENTER_ID),
      new nlobjSearchFilter('custrecord_emproster_salesregion', null, 'is', ROSTER_SALES_REGION_ID),
      new nlobjSearchFilter('custrecord_emproster_sales_qb', null, 'is', 25),
    ];
    const cols = [
      new nlobjSearchColumn('internalid'),
      new nlobjSearchColumn('name'),
      new nlobjSearchColumn('custrecord_emproster_avail'),
      ...availabilityNotesColumns(null),
      ...managerAvailResColumns(null),
      new nlobjSearchColumn('custrecord_emproster_olocation'),
      ...salesSubregionColumns(null),
      ...verticalAmoColumns(null),
      new nlobjSearchColumn('custrecord_emproster_sales_tier'),
      new nlobjSearchColumn('custrecord_emproster_salesteam'),
      new nlobjSearchColumn('custrecord_emproster_emp'),
      new nlobjSearchColumn('custrecord_emproster_mgrroster'),
      new nlobjSearchColumn('email', 'custrecord_emproster_emp'),
    ];
    const results = nlapiSearchRecord('customrecord_emproster', null, filters, cols) || [];
    return {
      members: results.map(rosterMemberFromRosterSearch),
      searched: results.length,
      lastName: searchTerm,
      enriched: true,
      source: 'roster',
    };
  }

  function getRosterCandidates(empRec, empIds, filterOpts, mode) {
    const broadRosterBase = mode === 'amo' || Boolean(filterOpts && filterOpts.limitToMyTeam);
    const filters = [
      ...(broadRosterBase ? amoBaseFilters(null) : baseFilters(empRec, null)),
      ...uiFilters(filterOpts || {}, null, empIds || {}),
    ];
    const cols = [
      new nlobjSearchColumn('internalid'),
      new nlobjSearchColumn('name'),
      new nlobjSearchColumn('custrecord_emproster_avail'),
      ...availabilityNotesColumns(null),
      ...managerAvailResColumns(null),
      new nlobjSearchColumn('custrecord_emproster_olocation'),
      ...salesSubregionColumns(null),
      ...verticalAmoColumns(null),
      new nlobjSearchColumn('custrecord_emproster_sales_tier'),
      new nlobjSearchColumn('custrecord_emproster_salesteam'),
      new nlobjSearchColumn('custrecord_emproster_emp'),
      new nlobjSearchColumn('custrecord_emproster_mgrroster'),
      new nlobjSearchColumn('email', 'custrecord_emproster_emp'),
    ];
    const rows = nlapiSearchRecord('customrecord_emproster', null, filters, cols) || [];
    return rows
      .map(rosterMemberFromRosterSearch)
      .filter(r => mode !== 'amo' || r.salesteam === 'AMO');
  }

  function searchSkillEntriesByRosterName(searchTerm) {
    const join    = 'custrecord_ssm_skill_employee';
    const filters = [
      ...amoBaseFilters(join),
      new nlobjSearchFilter('name', join, 'contains', searchTerm),
    ];
    const cols = [
      new nlobjSearchColumn('custrecord_ssm_skill_employee'),
      new nlobjSearchColumn('internalid',                           join),
      new nlobjSearchColumn('custrecord_emproster_avail',           join),
      ...availabilityNotesColumns(join),
      ...managerAvailResColumns(join),
      new nlobjSearchColumn('custrecord_emproster_olocation',       join),
      ...salesSubregionColumns(join),
      ...verticalAmoColumns(join),
      new nlobjSearchColumn('custrecord_emproster_sales_tier',      join),
      new nlobjSearchColumn('custrecord_emproster_salesteam',       join),
      new nlobjSearchColumn('custrecord_emproster_emp',             join),
      new nlobjSearchColumn('custrecord_emproster_mgrroster',       join),
    ];

    const results = nlapiSearchRecord('customrecord_ssm_entry', null, filters, cols);
    if (!results) return { members: [], searched: 0, lastName: searchTerm, enriched: false, source: 'skills' };

    const seen    = {};
    const members = [];
    results.forEach(function (r) {
      const id = r.getValue('internalid', join);
      if (!id || seen[id]) return;
      seen[id] = true;
      members.push({
        employeeId:   id,
        employee:     r.getText('custrecord_ssm_skill_employee'),
        manager:      r.getText('custrecord_emproster_mgrroster',       join) || '',
        availability: (r.getText('custrecord_emproster_avail',          join) || '').toLowerCase(),
        availNotes:   readAvailabilityNotes(r, join),
        availRes:     readManagerAvailRes(r, join),
        location:     extractShortLocation(r.getText('custrecord_emproster_olocation', join)),
        region:       readSalesSubregion(r, join),
        vertical:     readVerticalAmo(r, join),
        tier:         (r.getText('custrecord_emproster_sales_tier',     join) || '').replace('Solution Consultant - ', ''),
        salesteam:    r.getText('custrecord_emproster_salesteam',       join) || '',
        employeeRecId: r.getValue('custrecord_emproster_emp',           join) || '',
        email:        '',
      });
    });

    return { members: members, searched: results.length, lastName: searchTerm, enriched: false, source: 'skills' };
  }

  // Returns { members: [...], searched: N, lastName: string, error? }.
  // The fast path searches roster records directly; the skill-entry path remains
  // as a compatibility fallback if a NetSuite account behaves differently.
  function getRequestedSCRoster(fullName, options) {
    try {
      const opts = options || {};
      const strictName = Boolean(opts.strictName);
      const trimmed = (fullName || '').trim();
      if (!trimmed) return { members: [], searched: 0, lastName: '', enriched: true };

      const searchTerms = requestedRosterSearchTerms(trimmed);
      const searchTerm = searchTerms[0] || '';
      if (!searchTerm) return { members: [], searched: 0, lastName: '', enriched: true };

      const cacheKey = rosterLookupCacheKey((strictName ? 'strict:' : 'loose:') + searchTerm + (strictName ? ':' + trimmed : ''));
      const cached = _quickAssignRosterCache.get(cacheKey);
      if (cached) return cloneRosterLookupResult(cached);

      let result = null;
      for (const term of searchTerms) {
        try {
          result = searchRosterByName(term);
        } catch (rosterError) {
          console.warn('[Staffing Helper] fast roster lookup failed; falling back to skill lookup:', rosterError);
          result = searchSkillEntriesByRosterName(term);
        }
        if (!strictName || (result.members || []).some(member => requestedRosterMemberMatches(member, trimmed))) break;
      }

      if (strictName) {
        result = {
          ...result,
          members: (result.members || []).filter(function (member) {
            return requestedRosterMemberMatches(member, trimmed);
          }),
        };
      }

      _quickAssignRosterCache.set(cacheKey, cloneRosterLookupResult(result));
      return cloneRosterLookupResult(result);
    } catch (e) {
      console.warn('[Staffing Helper] getRequestedSCRoster error:', e);
      return { members: [], searched: -1, lastName: '', enriched: false, error: String(e) };
    }
  }

  function isValidRequestedSCName(rawName) {
    const name = (rawName || '').trim();
    if (!name) return false;
    const result = getRequestedSCRoster(name, { strictName: true });
    return Boolean(result.members && result.members.length);
  }

