  /**
   * Search through all accessible window frames for a <select> element
   * whose id or name contains the given keyword. Returns the element or null.
   */
  function findSelectAcrossFrames(keyword) {
    const kw = keyword.toLowerCase();

    function searchDoc(doc, label) {
      try {
        const sels = doc.querySelectorAll('select');
        for (const sel of sels) {
          const id   = (sel.id   || '').toLowerCase();
          const name = (sel.name || '').toLowerCase();
          if (id.includes(kw) || name.includes(kw)) {
            console.log('[SCH] findSelect("' + keyword + '") → found in ' + label +
              ' | id="' + sel.id + '" name="' + sel.name + '"' +
              ' val="' + sel.value + '"' +
              (sel.selectedIndex >= 0 ? ' text="' + sel.options[sel.selectedIndex].text + '"' : ''));
            return sel;
          }
        }
      } catch (e) { /* cross-origin or missing doc */ }
      return null;
    }

    function searchWin(win, label) {
      const found = searchDoc(win.document, label);
      if (found) return found;
      try {
        for (let i = 0; i < win.frames.length; i++) {
          const f = searchWin(win.frames[i], label + '.frame[' + i + ']');
          if (f) return f;
        }
      } catch (e) { /* ignore */ }
      return null;
    }

    // Search top window and all its descendants
    try {
      const f = searchWin(unsafeWindow.top || unsafeWindow, 'top');
      if (f) return f;
    } catch (e) { /* ignore */ }

    // Search own window as fallback
    return searchWin(unsafeWindow, 'self');
  }

  /**
   * Dump all <option> value→text pairs from a select found across frames.
   */
  function dumpSelectOptionsAcrossFrames(keyword) {
    const sel = findSelectAcrossFrames(keyword);
    if (!sel) {
      console.log('[SCH] dumpSelectOptionsAcrossFrames("' + keyword + '"): not found in any frame');
      return;
    }
    const opts = Array.from(sel.options).map(o => '  ' + o.value + ' → "' + o.text + '"');
    console.log('[SCH] Frame options for "' + keyword + '" (id=' + sel.id + '):\n' + opts.join('\n'));
  }

