    document.getElementById('sc-amo-btn-cancel').addEventListener('click', () => cancelRequest(empName));

    // ── AMO Product text filter ──────────────────────────────────
    document.getElementById('sc-amo-product-filter').addEventListener('input', function () {
      filterSelectOptionsByQuery('sc-amo-products', this.value);
    });

    document.getElementById('sc-amo-product-skill-filter').addEventListener('input', function () {
      filterSelectOptionsByQuery('sc-amo-product-skills', this.value);
    });
    document.getElementById('sc-amo-product-skill-filter').addEventListener('keydown', function (ev) {
      if (ev.key !== 'Enter') return;
      ev.preventDefault();
      addProductSkillFromFilter('sc-amo-product-skill-filter', 'sc-amo-product-skills', 'sc-amo-products');
    });

    // ── AMO Enforce 4-product max ────────────────────────────────
